window.SERVICES = [{"id":"vespers","name":"მწუხრი","subtitle":"წესი და განგება მწუხრისა","blocks":[{"t":"rubric","text":"დაირეკება სამეუფო ზარი."},{"t":"rubric","text":"შემოდის ეპისკოპოსი ცენტრალური (დასავლეთის) კარით."},{"t":"rubric","text":"წინამძღვარი დასავლეთის კართან ხვდება სინზე დასვენებული ჯვრით."},{"t":"rubric","text":"I დიაკონი (სასაკმევლით) შუაში მის მარჯვნივ II დიაკონი (სანთლით) მესამე დიაკონი მარცხნივ (სანთლით)."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"სიბრძნით!"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"უპატიოსნესსა ქერუბიმთასა და აღმატებით უზესთაესსა სერაბიმთასა, განუხრწნელად მშობელსა სიტყვისა ღვთისასა, მხოლოსა ღვთისმშობელსა გალობით ვადიდებდეთ. დიდება, აწდა. უფალო შეგვიწყალენ (გ-გზის), სახელითა უფლისათა მაღალყოვლადუსამღვდელოესო მეუფეო გვაკურთხენ. მგალობლები: ღირს არსი."},{"t":"rubric","text":"მღვდელმთავარი ემთხვევა ხატს ამ დროს II და III დიაკონი წავლენ აღსავლის კარისკენ და გაჩერდებიან ამბიონთან. მღვდელმთავარი შებრძანდება საკურთხეველში, სამღვდელოება და დიაკვნები ჩრდილოეთის და სამხრეთის კარით შევლენ საკურთხეველში. I დიაკონი სასაკმევლეს მისცემს წინამძღვარს (უპირატესს) და თვითონ აიღებს სანთელს. წინამძღვარი აკურთხებინებს მღვდელმთავარს სასაკმევლეს და დადგება ტრაპეზის წინ, დიაკვნები დგანან ტრაპეზის უკან. იკმევა საკურთხეველი წესისაებრ. I დიაკონი გადის აღსავლის კარით ამბიონზე."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აღსდეგინ!"},{"t":"say","role":"choir","who":"გუნდი","text":"მაღალყოვლადუსამღვდელოესო მეუფეო გვაკურთხენ."},{"t":"rubric","text":"დიაკონი დაბრუნდება აღსავლის კარით თავის ადგილზე."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"დიდება წმიდასა და თანაარსსა, და ცხოველმყოფელსა, და განუყოფელსა სამებასა, ყოვლადვე, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"rubric","text":"წინამძღვარი და დიაკვნები გამოდიან აღსავლის კარით და იკმევა ტაძარი სრულად."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. მოვედით თაყვანისვცეთ დ-გზის აკურთხევს სული... (103 ფს.)"},{"t":"rubric","text":"კმევის დასრულების შემდეგ წინამძღვარი და მღვდლები აიღებს კურთხევას მღვდელმთავრისაგან."},{"t":"rubric","text":"I დიაკონი იღებს კურთხევას გადის ჩრდილოეთის კარით და მაცხოვრის ხატთან ამბობს დიდ ანუ მშვიდობიან კვერექსს."},{"t":"head","text":"ლოცვა ა"},{"t":"prayer","text":"უფალო სახიერო, სულგრძელო და მრავალ-მოწყალეო, ყურად-იღე ლოც-ვაი ჩვენი, და მოხედენ ხმასა ვედრებისა ჩვენისასა, ჰყავ ჩვენ- თანა სასწაულ კეთილ, წარმიძეღუ ჩვენ გზათა შენთა, რათა ვიდოდეთ ჩვენ ჭეშმარიტებითა შენითა, ახარე გულთა ჩვენთა, შიშითა სახელისა შენისა წმიდისათა, რამეთუ დიდ ხარ შენ, და მოქმედი საკვირველებათა, შენ ხარ ღმერთი მხოლოო, და არავინ არს მსგავს შენდა ღმერთთა შორის, უფალო, ძლიერი წყალობითა, და სახიერი კაცთ-მოყვარებითა, შეწევნად და ნუგეშინის-ცემად და ცხოვრებად ყო-ველთა მოსავთა სახელისა შენისა მიმართ წმიდისა: რამეთუ შვენის შენდა ყოველი დიდება, პატივი და თაყვანისცემა, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე; ამინ."},{"t":"head","text":"ლოცვა ბ"},{"t":"rubric","text":"უფალო, ნუ გულის-წყრომითა შენითა მამხილებ ჩვენ, და ნუცა რისხვითა შენითა მსწავლი მსწავლი ჩვენ, არამედ ჰყავ ჩვენ თანა წყალობაი მსგავსად სახიერებისა შენი-სა, მკურნალო და მხსნელო სულთა ჩვენთაო, მიმიძეღუ ჩვენ ნავსაყუ-დელსა ნებისა შენისასა, განანათლენ თვალნი გულთა ჩვენთანი ცნობად ჭეშმარიტებისა შენისა, და მომანიჭე ჩვენ ნეშტი დღისა ამის მშვიდობით, და უცვალებელად, და ყოველნი ჟამნი ცხოვრებისა ჩვენისანი, მეოხებითა წმიდისა ღვთის-მშობლისათა, და ყო-ველთა წმიდათა შენთათა: რამეთუ შენი არს სიმტკიცე, და შენი არს სუფევა, ძალი და დიდება, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა გ"},{"t":"prayer","text":"უფალო, ღმერთო ჩვენო, მომიხსენენ ჩვენ ცოდვილნი და უხმარნი მონანი შენნი, რაჟამს ვხადოდეთ ჩვენ წმი-დასა სახელსა შენსა, და ნუ მარცხვენ ჩვენ სასოებისაგან ჩვენისა წყალობითა შენითა, არამედ მომმადლე ჩვენ, უფალო, ყოველივე საცხოვრებელი თხოვაი, და ღირს მყვენ სიყვარულსა, და შიშსა შენსა ყოვლითა გულითა ჩვენთა, და ყოფად ყოველსა შინა ნებასა შენსა: რამეთუ სახიერი და კაცთ-მოყვარე ღმერთი ხარ, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა დ"},{"t":"prayer","text":"რომელსა ჩვენ ყოველნი დაუდუმებელად გაქებთ შენ, და მარადის გადიდებთ ყოველთა ზეცისა ძალთა მიერ ქებულო, აღავსე პირი ჩვენ ქებითა შენითა, რათა უგალობდეთ სახელსა შენსა წმიდასა, მოგვეც ჩვენ ნაწილი, და სამკვიდრებელი ყოველთა მოშიშთა ჭეშმარიტებისა შენისათა, დაც-ვითა მცნებათა შენთათა, მეოხებითა წმიდისა ღვთის-მშობელისათა, და ყო-ველთა წმიდათა შენთათა. რამეთუ შვენის შენდა ყოველი დიდება, პატივი და თაყვანისცემა, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ე"},{"t":"rubric","text":"უფალო, უფალო, რომელსა უხრწნე-ლითა ნებითა გიპყრიეს ყოველი დაბა-დებული, და სულ-გრძელ ხარ ჩვენ ცოდვილთა ზედა, შემნანებელად სიბოროტისა ჩვენსა, მოგვიხსენენ წყალობითა და მოწყალებითა შენითა, და დაგვიფარენ ჩვენ სახიერებითა შე-ნითა, მოგვეც ჩვენ განვლად ნეშტი დღისა ამის მადლითა შენითა, და განგვა-შორე ბოროტისა ეშმაკისა საცდური, და უვნებელად დაიცევ ცხოვ-რებაი ჩვენი მეორედ მოსულასა მას შენსა, მადლითა სულისა შენისა წმიდისათა: წყალობითა და კაცთმოყვარეობითა, მხოლოდ შობილისა ძისა შენისათა, რომლისა თანა კურთხეულ ხარ, თანა ყოვლად წმიდით სახიერით და ცხოველს მყოფელით სულით შენით, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ვ"},{"t":"prayer","text":"ღმერთო დიდო და საკვირველო, რომელი გამოუთქმელითა სახიერები-თა შენითა, და სიმდიდრითა წინასწარ მცნობელობისა შენისათა განაგებ ყო-ველთა, რომელმან ქვეყანისა ყოველი კეთილი მოგვეც ჩვენ, და შენ მიერი იგი აღთქმული სუფეველი მოგვანიჭე ჩვენ, და აღთქმითა მით კეთილი გზაი გვიჩვენე ჩვენ, დღესა მას მოს-ვლისა შენისასა, ყოვლისა ბოროტისაგან განგვათავისუფლენ ჩვენ, და მოგვანიჭე ჩვენ შემდგომი ნეშტი ცხო--ვრებისა ჩვენისა უცოდველად ვარდ-გომად წინაშე დიდებისა შენისა, საყე-ბელად მხოლოისა სახიერისა და კაცთ-მოყვარისა შენ ღვთისა ჩვენსა: რამეთუ შენ ხარ ღმერთი ჩვენი და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ზ"},{"t":"prayer","text":"ღმერთო დიდო და მაღალო, რომელსა მხოლოსა გაქვს უკვდა-ვებაი და მკვიდრ ხარ ნათელსა თვალთ შეუდგამსა, რომელმან ყოველნი დაბა-დებულნი სიბრძნით შექმენ; რომელმან განჰყავ შორის ნათლისა და შორის ბნელისა, და დააწესე მზეი მფლობელად დღისა, მთოვარეი და ვარს-კვლავნი მფლობელად ღამისა, და ღირს მყვენ ჩვენ ცოდვილნი ჟამსაცა ამას მოსვლად წინაშე პირსა შენსა აღსარებითა, და შეწირვად შენდა მწუხრის ლოცვისა, შენ კაცთ-მოყვარეო, წარმა-რთე ლოცვაი ჩვენი, ვითარცა საკმეველი შენ წინაშე, და შეიწირენ სუნად სურნელად, და მოგვმადლე მწუხრი ესე, და შემომავალი ღამეი მშვიდობით, შეგვმოსე ჩვენ საჭურველი ნათლისა, გვიხსნენ შიშისაგან ღამისა, და ყოვ-ლიგან ღვაწლისა, რომელი ვალნ ბნე-ლსა შინა, და ძილი ესე რომელ მოგვეც განსასვენებელად უძლურებათა ჩვე-ნთა, ჰყავ ყოვლისგან ოცნებისა საეშმაკოისა განშორებულ. ეე, მეუ-ფეო, კეთილთა მომნიჭებელო, რათა სარეცელთაცა ჩვენთა ზედა ვინანდეთ, და ღამითცა ვიხსენებდეთ ყოვლად წმიდასა სახელსა შენსა, წურთითა მცნებათა შენთათა განვნათლდებოდეთ, და სიხარულითა სულისათა აღვსდგეთ დიდების-მეტყველებად სახიერებისა შენისა, რათა ლოცვასა და ვედრე-ბასა შევსწირვიდეთ მოწყალებისა შე-ნისა მიმართ ლოცვათა ჩვენთა-თვის, ერისა უმეცრებისათვის, მეოხებითა წმი-დისა ღვთის-მშობლისათა: რამეთუ სახიერი და კაცთ-მოყვარე ღმერთი ხარ, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ზეგარდამო მშვიდობისა და ცხოვრე-ბისათვის სულთა ჩვენთასა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მშვიდობისათვის ყოვლისა სოფლისა, კეთილად დგომისათვის წმიდათა ღმრთისა ეკლესიათა, და ყოველთა ერთობისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"წმიდისა ამის ტაძრისათვის (მონასტრისათვის), სარწმუნოებითა, სასოებითა და შიშითა ღმრთისათა შემავალთა ამას შინა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"უწმიდესისა და უნეტარესისა, სრულიად საქართველოს კათოლიკოს-პატრიარქი-სა და მცხეთა-თბილისის მთავარეპისკოპოსისა, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტისა დიდისა მეუფისა მამისა ჩვენისა ი ლ ი ა ს ა თ ვ ი ს, და სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრისა მაღალყოვლადუსა-მღვდელოესისა სენაკისა და ჩხოროწყუს მიტროპოლიტისა შიოსათვის, და მაღალყოვლადუსამღვ-დელოესისა ქუთათელ-გაენათელი მიტროპოლიტი-სა იოანესათვის, პატიოსანთა მღვდელთა, ქრი-სტეს მიერ დიაკონთა და ყოვლისა სამღვდელოისა დასისა და ერისა მათისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ღვთივდაცულისა ერისა ჩვენისა, მთავრობისა და მხედრობისა მათისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"თანა-მბრძოლთათვის და დამორჩილებისა ქვეშე ფერხთა მათთა ყოველთა მტერთა და მბრძოლთა უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სამეუფოისა ქალაქისა ამის ჩვენისა, და წმიდისა ამის ტაძრისა (მონასტრისა) და ყოვლისა ქალაქებისა და სოფლებისა, და სარწმუნოებით მკვიდრთა მათ შინა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"კეთილ-შეზავებისათვის ჰაერთასა, კეთილ-გამოღებისათვის ნაყოფთა ქვეყანისათა და ჟამთა მშვიდობისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მენავეთა, მოგზაურთა, სნეულთა, მშრომელთა, ტყვეთა ხსნისა და ცხოვრებისა მათისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ხსნად ჩვენდა ყოვლისაგან ჭირისა, რისხვისა და იწროებისა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცვენ ჩვენ, ღმერთო, შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლადწმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩვენისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩვენი ქრისტესა ღმერთსა ჩვენსა შევვედროთ"},{"t":"say","role":"choir","who":"გუნდი","text":"შენ, უფალო."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ შვენის შენდა ყოველი დიდება, პატივი და თაყვანისცემა, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ"},{"t":"rubric","text":"დიაკვნები ლოცვა-კურთხევას აიღებენ მღვდელმთავრისგან."},{"t":"say","role":"choir","who":"გუნდი","text":"ნეტარ არს კაცი..."},{"t":"rubric","text":"II დიაკონი იღებს კურთხევას გადის ჩრდილოეთ კარიდან და მაცხოვრის ხატთან ამბობს მცირე კვერექსს,"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცვენ ჩვენ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლადწმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩვენისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა, და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩვენი, ქრისტესა ღმერთსა ჩვენსა შევვედროთ. გუნდი: შენ, უფალო."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ შენი არს სიმტკიცე, და შენი არს სუფევა, და ძალი, და დიდება მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე. გუნდი: ამინ I დიაკონი აიღებს სასაკმევლეს და მივა მღვდელმთავართან, რომელიც დაასხამს საკმეველს, დიაკონი აკმევს საკურთხეველს და სრულად ტაძარს წესისაებრ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო ღაღადვყავი."},{"t":"rubric","text":"ლოცვა საიდუმლოდ."},{"t":"rubric","text":"მწუხრი, დილეულ და სამხრად, გაქებთ, გაკურთხებთ, გმადლობთ და გევედრებით შენ, მეუფეო ყოველთაო, წარმართე ლოცვაი ჩვენი, ვითარცა საკმეველი შენ წინაშე, და ნუ მისდრეკ გულთა ჩვენთა სიტყვათა მიმართ უკეთურებათასა, არამედ, გვიხსნენ მომნადირებელთაგან სულისა ჩვენისათა, რამეთუ შენდა მიმართ, უფალო, უფალო, თვალნი ჩვენნი შენ გესვენ, და ნუ გვარცხვენ ჩვენ უფალო ღმერთო ჩვენო: რამეთუ შვენის შენდა ყოველი დიდება, პატივი და თაყვანის-ცემა, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ. უფალო ღაღადვყავის დიდების მუხლზე დიაკონი აკურთხებინებს სასაკმევლეს მღვდელმთავარს, წინამძღვარი, დიაკონი და მნათე (სანთლით) მაღალდასაჯდომელის გავლიან ჩრდილოეთის კარით გამოდიან. I დიაკონი სასაკმევლეს გადაიტანს მარცხენა ხელში მარჯვენაში დაიჭერს გინგილას შევა აღსავლის კარით, მღვდელმთავარს გინგილით მიუთითებს აღსავლის კარზე"},{"t":"say","role":"deacon","who":"დიაკონი","text":"აკურთხე მაღალყოვლადუსამღვდელოესო მეუფეო წმიდა შესავალი."},{"t":"rubric","text":"მღვდელმთავარი დასახავს ჯვარს აღსავლის კარს, I დიაკონი გამოდის ისევ აღსავლის კარით და აწდას მუხლის დასრულების შემდეგ სასაკმევლით გამოსახავს ჯვარს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სიბრძნით აღემართენით."},{"t":"rubric","text":"დიაკონი შედის აღსავლის კარით აკმევს ტრაპეზს წინა მხრიდან 3-გზის, მაღალდასაჯდომელს 3-გზის, მღვდელმთავარს 3-გზის."},{"t":"say","role":"choir","who":"გუნდი","text":"ნათელი მხიარული..."},{"t":"rubric","text":"წინამძღვარი და დიაკვნები ემთხვევიან ტრაპეზს, მაღალდასაჯდომელთან თაყვანისცემა, მობრუნდებიან და მღვდელმთავარს დაუხრიან თავს. დგანან პირისახით მეუფისკენ (დასავლეთით) წინამძღვარი შუაში მისგან მარჯვნივ I დიაკონი I დიაკონის გვერდით III დიაკონი, წინამძღვრის მარცხნივ II დიაკონი."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მოხედენ."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"მშვიდობა ყოველთა."},{"t":"rubric","text":"წინამძღვარი ჯვარს არ გამოსახავს, მოიდრეკს თავს."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"სიბრძნით. ვარდგომა ფსალმუნი დავითისი."},{"t":"rubric","text":"კვირიაკესა მწუხრად, ხმა 8"},{"t":"rubric","text":"აქა აკურთხევდით უფალსა, ყოველი მონანი უფლისანი. მუხლი: რომელი სდგათ სახლსა უფლისასა, ეზოთა სახლისა ღმრთისა ჩვენისასა. ორშაბათსა მწუხრად, ხმა 4"},{"t":"rubric","text":"უფალსა შეესმინ ჩემი, ღაღადებასა ჩემსსა მისა მიმართ. მუხლი: ხადილსა ჩემსა ესმა ჩემი ღმერთსა სიმართლისა ჩემისასა."},{"t":"rubric","text":"სამშაბათსა მწუხრად, ხმა 1"},{"t":"rubric","text":"წყალობა შენი უფალო, თანა-მავალ-მეყავნ მე ყოველთა დღეთა ცხოვრებისა ჩემისათა. მუხლი: უფალმან მწყოს მე და არაი მაკლდეს, ადგილსა მწვანვილსა მუნ დამამკვიდრა მე."},{"t":"rubric","text":"ოთხშაბათსა მწუხრად, ხმა 5"},{"t":"rubric","text":"ღმერთო სახელითა შენითა მაცხოვნე მე, და ძალითა შენითა მისაჯო მე. მუხლი: ღმერთო ისმინე ლოცვისა ჩემისაი, ყურად-იხუენ სიტყვანი პირისა ჩემისანი."},{"t":"rubric","text":"ხუთშაბათსა მწუხრად, ხმა 6"},{"t":"rubric","text":"შეწევნა ჩემი უფლისა მიერ, რომელმან ქმნა ცანი და ქვეყანაი."},{"t":"say","role":"verse","who":"მუხლი","text":"აღვიხილენ თვალნი ჩემნი მთათა, ვინა მოვიდეს შეწევნად ჩემდა?"},{"t":"rubric","text":"პარასკევსა მწუხრად, ხმა 7"},{"t":"rubric","text":"ღმერთი ჩემი მწე ჩემდა არს, რამეთუ წყალობამან მისმან იმსთოს ჩემდამო."},{"t":"say","role":"verse","who":"მუხლი","text":"მიხსენ მე მტერთა ჩემთაგან ღმერთო, და მათგან რომელნი აღდგომილ არიან ჩემ ზედა განმარინე მე."},{"t":"rubric","text":"შაბათსა მწუხრად, ხმა 6"},{"t":"rubric","text":"უფალი სუფევს, შვენიერება შეიმოსა."},{"t":"say","role":"verse","who":"მუხლი","text":"შეიმოსა უფალმან ძალი და გარე შეირტყა."},{"t":"say","role":"verse","who":"მუხლი","text":"და რამეთუ დაამყარა სოფელი რათა არა შეიძრას."},{"t":"say","role":"verse","who":"მუხლი","text":"სახლსა შენსა შვენის სიწმინდე, უფალო სიგრძესა შინა დღეთასა."},{"t":"rubric","text":"ვარდგომა ხორციელ შაბათს და მიცვალებულთა მსახურებაზე"},{"t":"say","role":"verse","who":"მუხლი","text":"ალილუია, ალილუია, ალილუია."},{"t":"say","role":"verse","who":"მუხლი","text":"ნეტარ არს რომელი გამოირჩიე და შეიწყნარე უფალო, და სახსენებელი მათი იყოს თესლითი თესლამდე. მუხლი: სულმან მათმან კეთილთა შინა განისვენოს და ნათესავმან მათმან დაიმკვიდროს ქვეყანა."},{"t":"rubric","text":"ვარდგომა სულთმოფენობის წინა შაბათს"},{"t":"say","role":"verse","who":"მუხლი","text":"ალილუია, ალილუია, ალილუია. მუხლი: ნეტარ არს რომელი გამოირჩიე და შეიწყნარე უფალო. მუხლი: და სახსენებელი მათი იყოს თესლითი თესლამდე. მუხლი: სულმან მათმან კეთილთა შინა განისვენოს და ნათესავმან მათმან დაიმკვიდროს ქვეყანა. ბოლო მუხლის თქმისას მიბრუნდებიან ყველა ისევ თავს დაუხრიან მაღალდასაჯდომელს, ხოლო შემდეგ მღვდელმთავარს. II და III დიაკონი ჯვარედინად ვალენ კვერექსებზე. (საწინასწარმეტყველოს ძველი აღთქმის საკითხავებზე დაიკეტება აღსავლის კარი ლიტიამდე, ხოლო თუ მოციქულის ხსენებაა და იკითხება ახალი აღთქმის საკითხავი მაშინ არ დაიხურება აღსავლის კარი). II დიაკონი ამბობს მრჩობლ კვერექსს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ვსთქვათ ყოველთა, ყოვლითა სულითა, და ყოვლითა გონებითა ჩვენითა ვსთქვათ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"უფალო ყოვლისა-მპყრობელო, ღმერთო მამათა ჩვენთაო, გევედრებით, ისმინე და შეგვიწყალენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვიწყალენ ჩვენ ღმერთო, დიდითა წყალობითა შენითა, გევედრებით, ისმინე და შეგვიწყალენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით ღვთივდაცულისა ერისა ჩვენისა, მთავრობისა და მხედრობისა მისისათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით უწმიდესისა და უნეტარესისა, სრულიად საქართველოს კათოლიკოს-პატრიარქისა და მცხეთა-თბილისის მთავარე-პისკოპოსისა, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტისა დიდისა მეუფისა მამისა ჩვენსა ი ლ ი ა ს ა თ ვ ი ს, და სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრისა მაღალყოვ-ლადუსამღვდელოესისა სენაკისა და ჩხოროწყუს მიტროპოლიტისა შიოსათვის, და მაღალყოვლადუ-სამღვდელოესისა ქუთათელ-გაენათელი მიტროპოლიტისა იოანესათვის და ყოველთა ქრისტეს მიერ ძმათა ჩვენთათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით სანატრელთა და მარადის მოსახსენებელთა, წმიდათა მართლმადიდებელთა პატრიარქთა, კეთილმსახურთა მეფე-თა და კეთილმორწმუნეთა დედოფალთა და აღმაშენებელთა წმიდისა ამის ტაძრისათა (მონასტრისათა) და ყოველთა პირველ დაძინებულთა მამათა და ძმათა, აქა მდებარეთა, და ყოვე-ლთა მართლმადიდებლობით აღსრულებულთათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით წყალობისა, სიცოცხლისა, მშვიდობისა, სიმრთელისა, ცხოვრე-ბისა, შეწევნისა, შენდობისა და მიტევებისა ცოდვათა, მონათა ღვთისათა, ძმათა წმიდისა ამის ტაძრისათა (ან მონასტრისათა)."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით ნაყოფის-შემომწირველთათვის და კეთილის-მყოფელთა წმიდისა და ყოვლად-პატიოსნისა ამის ტაძრისა და ამას შინა მშრომელთა, მგალობელთა და აქა მდგომარეთა ერთათვის, რომელნი მოელიან შენ მიერ დიდსა და მდიდარსა წყალობასა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ მოწყალე და კაცთმოყვა-რე ღმერთი ხარ, და შენდა დიდებასა აღვავ-ლენთ, მამისა და ძისა და წმიდისა სულისა აწდა მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"choir","who":"მედავითნე","text":"და ღირსმყვენ..."},{"t":"rubric","text":"III დიაკონი თხოვნითი კვერექსი."},{"t":"say","role":"deacon","who":"დიაკონი","text":"აღვასრულოთ სამწუხრო ვედრებაი ჩვენი უფალსა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცვენ ჩვენ, ღმერთო, შენითა მადლითა. გუნდი: უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მწუხრი ყოველი სრულიად, სიწმიდით, მშვიდობით და უცოდველად, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ანგელოზი მშვიდობისა, სარწმუნო წინამძღვარი, მცველი სულთა და ხორცთა ჩვენთა, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შენდობა და მოტევება ცოდვათა და უსჯულოებათა ჩვენთა, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"კეთილნი და უმჯობესნი სულთა ჩვენ-თანი და მშვიდობაი სოფლისა, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შემდგომნი ჟამნი ცხოვრებისა ჩვენისანი მშვიდობით და სინანულით აღსრულებად, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ქრისტიანობითნი აღსასრულნი ცხოვრე-ბისა ჩვენისანი, უჭირველნი, ურცხვენელნი, მშვიდობითნი, და კეთილი სიტყვის-გება წინაშე საშინელსა სამსჯავროსა ქრისტესსა ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლად-წმიდისა, უხრწნელისა, უფროს-ად კურთხეულისა, დიდებულისა დედოფლისა ჩვენისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა, და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი, და ურთიერთ არს, და ყოველი ცხოვრება ჩვენი ქრისტესა ღმერთსა ჩვენსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ, უფალო"},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ სახიერი და კაცთმოყვარე ღმერთი ხარ, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"მშვიდობა ყოველთა."},{"t":"rubric","text":"ჯვარს არ გამოსახავს."},{"t":"say","role":"choir","who":"გუნდი","text":"და სულისაცა შენისა თანა."},{"t":"say","role":"deacon","who":"დიაკონი","text":"თავნი ჩვენნი უფალსა მოუდრიკნეთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო."},{"t":"head","text":"ლოცვა მოდრეკით"},{"t":"prayer","text":"უფალო ღმერთო ჩვენო, რომელმან მოჰსდრიკენ ცანი და გარდამოხედ ცხო-ვრებისა-თვის ნათესავისა კაცთასა, მო-ხედენ მონათა შენთა ზედა, და სამკვი-დრებელსა შენსა ზედა, რამეთუ შენ ხარ საშინელი და კაცთ-მოყვარე მსა-ჯული მონათა შენთა, რომელთა მოუდრეკიან თავნი თვისნი, და დაუმ-დაბლებიან ქედნი მათნი, რამეთუ არა კაცთა მიერსა ეძიებენ შეწევნასა, არამედ შენ მიერსა ითხოვენ წყალობასა, და შენსა ეძიებენ ცხოვრებასა, რათა დაიცვნე ყოველსა ჟამსა, და შემდგო-მსაცა მწუხრსა, და მომავალსაცა ღამესა ყოვლისა წინა-აღდგომთა მტე-რთა საცთურისაგან, და ამაოთა გულის სიტყვათა, და ბოროტთა განზრა-ხვათა საეშმაკოთა:"},{"t":"say","role":"priest","who":"მღვდელი","text":"იყავნ სიმტკიცე სუფევისა შენისა კურთხეულ, და დიდებულ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"თუ პურის კურთხევაა მღვდელმთავარი საკურთხეველში შეიმოსავს ოლარს, სამაჯურებს, მანტიას, მცირე ომოფორს და ბარტყულას, სტიქაროსნები დიკირ-ტრიკირით და რიპიდებით გადიან და ამბიონთან. გაიღება აღსავლის კარი გამოვლენ ჯერ დიაკონები, შემდეგ მღვდლები და ბოლოს მღვდელმთავარი და მიდიან ყველანი სტოაში."},{"t":"rubric","text":"მღვდელმთავრიდან მარჯვნივ მღვდლების შემდეგ დგას I დიაკონი მის გვერდით III დიაკონი. I დიაკონის მოპირდაპირედ დგას II დიაკონი. დიკირ-ტრიკირი და რიპიდები დგანან მღვდელმთავართან. (ტრიკირი მღვდელმთავრიდან მარჯვნივ დიკირი-მარცხნივ.) დიაკვნები მღვდელმთავარს დაუხრინ თავს შემდეგ ერთმანეთს."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აცხოვნე, ღმერთო, ერი შენი, და აკურთხე სამკვიდრებელი შენი, მოხედენ სოფელსა შენსა წყალობითა და მოწყალებითა, აღამაღლე რქა ქრისტიანეთა მართლმადიდებელთა, და გარდამოავლინენ ჩვენ ზედა მდიდარნი წყალობანი შენი, მეოხებითა ყოვლად-წმიდისა დედოფლისა ჩვენისა ღმრთისმშობელისა, და მარადის ქალწულისა მარიამისათა, ძლიერებითა პატიოსნისა და ცხოველსმყოფელისა ჯვარისათა, ძლიერებითა ჯვარისა ვაზისათა; მეოხებითა პატიოსანთა უსხეულოთა ზეცისა ძალთათა, პატიოსნისა, დიდებულისა, წინასწარ-მეტყველისა, წინამორ-ბედისა და ნათლისმცემელისა იოანესითა, წმიდათა დიდებულთა, და ყოვლად-ქებულთა მო-ციქულთა: ანდრია პირველწოდებულისა, სიმონ კანანელისა და მათათასითა, ბართლომე და თადეოზისათა წმიდისა დედისა ჩვენისა, მოციქულთა სწორისა ქალწულისა ნინო ქართველთა განმანათლებელისათა, წმიდა მოცი-ქულთა სწორთა: მეფისა მირიანისა და დედო-ფლისა ნანასითა; წმიდათა შორის მამათა ჩვენთა, და მსოფლიოთა დიდთა მოძღვართა და მღვდელთ-მთავართა, ბასილი დიდისა, გრიგოლი ღმრთის-მეტყველისა, და იოანე ოქროპირისათა, წმიდათა შორის მამისა ჩვენისა ნიკოლოზ მირონ-ლუკიის მთავარეპისკოპოსისა და საკვირველთმოქმედისათა, და წმიდათა დიდებულთა და ღვაწლის-მძლეთა მოწამეთა: წმიდისა მთავარ-მოწამისა ძლევაშემოსილისა გიორგისათა, და წმიდათა მოწამეთა არგვეთის მთავართა დავით და კონსტანტინესითა, წმიდათა ღირსთა და ღმერთშემოსილთა მამათა ჩვენთა იოანე ზედაზნელისა და მისთა თორმეტთა მოწაფეთა და წმიდათა იოანე, ექვთიმე და გიორგი მთაწმინდელთა, წმიდათა კეთილმსახურთა მეფეთა ბაგრატ III-ისა, დავით აღმაშენებელისა და თამარისათა, და წმიდათა და მართალთა მშობელთა ღმრთისათა იოაკიმ და ანასითა, (და წმიდისა სახელი, რომლისა არს ტაძარი), და ყოველთა წმიდათა შენთათა, გევედრებით შენ მრავალმოწყალეო ღმერთო, შეისმინე ჩვენ ცოდვილთა ვედრება, და შეგვიწყალენ ჩვენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ 40 გზის."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"მერმეცა გევედრებით ღვთივდაცულისა ერისა ჩვენისა, მთავრობისა და მხედრობისა მისისათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ 30 გზის."},{"t":"say","role":"deacon","who":"III დიაკონი","text":"მერმეცა გევედრებით უწმიდესისა და უნეტარესისა, სრულიად საქართველოს კათოლიკოს-პატრიარქისა და მცხეთა-თბილისის მთავარეპისკოპოსისა, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტისა დიდისა მეუფისა მამისა ჩვენსა ი ლ ი ა ს ა თ ვ ი ს, და სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყ-დრისა მაღალყოვლადუსამღვდელოესისა სენაკისა და ჩხოროწყუს მიტროპოლიტისა შიოსათვის, და მაღალყოვლადუსამღვდელოესისა ქუთათელ-გაენათელი მიტროპოლიტისა იოანესათვის და ყოველთა ქრისტეს მიერ ძმათა ჩვენთათვის და, ყოვლისა სულისა ქრისტიანისა, ჭირვეულისა და დაწუნებულისა, მვედრებელისა წყალობისათვის ღვთისა და შეწევნისათვის, დაცვისათვის წმიდისა ამის ტაძრისათა(მონასტრისა), მშვიდობისა და დაცვისათვის ყოვლისა სოფლისა, კეთილად დგომისათვის წმიდათა ღვთისა ეკლესიათა, და ცხოვრებისა და შეწევნისათვის, რომელნი მას შინა შიშითა ღვთისათა შვრებიან და მსახურებენ, მამანი და ძმანი ჩვენნი, და რომელნი ვერ მოვიხსენეთ, ანუ რომელნი განშორებულ არიან ჩვენგან, განკურნებისათვის სნეულთასა, განსვენებისათვის და მიტევებისა ცოდვათა სანატრელთა და მარადის მოხსენებულთა ყოველთა პირველ დაძინებულთა მამათა და ძმათა ჩვენთა, აქა მდებარეთა და ყოვე-ლთაგან, მართლმადიდებლობით აღსრულებულთა, განთავისუფლებისათვის ტყვეთასა და მშვიდობისათვის მსახურთა და მსახურებულთა ძმათა ჩვენთათვის, რომელნი აწ მსახურებენ და უმსახურებიან წმიდისა ამის ტაძრისათვის(მონასტრისა) ვსთქვათ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ 50 გზის."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"რათა დაიცვას უფალმან ღმერთმან ჩვენმან სამეუფო ქალაქი ესე ჩვენი და წმიდა ესე ტაძარი (მონასტერი) და ყოველნი ქალაქნი და სოფელნი სიყმილისაგან, სრვისა, ძრვისა, დანთქმისაგან, ცეცხლისა და მახვილისა, უცხო-თესლთა ზედა მოსვლისაგან, ბრძოლისა და სიკუდიდ-შემოსილისა წყლულებისა, რათა მოწყალე გვექმნეს ჩვენ ღმერთი კეთილად დგომისათვის სახიერებითა და კაცთმოყვარეობითა თვისითა, და გარეწარაქციოს რისხვა, მარად დღე ჩვენ ზედა მომავალი, და გვიხსნეს ჩვენ სამართლად ჩვენ ზედა მოწევნულისა რისხვისაგან, და შეგვიწყალნეს ჩვენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"rubric","text":"აღმოსავლეთისაკენ შებრუნდებიან დიაკვნები."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მერმეცა ვევედრნეთ, რათა შეისმინოს უფალმან ღმერთმან ხმაი ვედრებისა ჩვენ ცოდვილთასა და შეგვიწყალნეს ჩვენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"შეისმინე ჩვენი, ღმერთო, მაცხოვარო ჩვენო, სასოო ყოველთა კიდეთა ქვეყანისაო, და რომელნი არიან ზღვათა შინა შორის, და მლხინებელ და მოწყალე ეყმენ, მეუფეო, შეცოდებათა ჩვენთა, და შეგვიწყალენ ჩვენ."},{"t":"prayer","text":"რამეთუ მოწყალე და კაცთმოყვარე ღმერთი ხარ, და შენდა დიდებასა აღვავლენთ, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"დიაკვნები შებრუნდებიან დასავლეთისაკენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობა ყოველთა. გუნდი: და სულისაცა შენისა თანა. დიაკონი: თავნი ჩვენნი უფალსა მოუდრიკნეთ. გუნდი: შენ უფალო."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მეუფეო მრავალმოწყალეო უფალო იესო ქრისტე ღმერთო ჩვენო, მეოხებითა ყოვლადწმიდისა დედოფლისა ჩვენისა ღმრთისმშობელისა, და მარადის ქალწულისა მარიამისათა, ძლიერებითა პატიოსნისა და ცხოველსმყოფელისა ჯვარისათა, ძლიერებითა ჯვარისა ვაზისათა; მეოხებითა პატიოსანთა უსხეულოთა ზეცისა ძალთათა, პატიოსნისა, დიდებულისა, წინასწარ-მეტყველისა, წინამორბედისა და ნათლის-მცემე-ლისა იოანესითა, წმიდათა დიდებულთა, და ყოვლად-ქებულთა მოციქულთა: ანდრია პირ-ველწოდებულისა, სიმონ კანანელისა და მათათასითა, ბართლომე და თადეოზისათა წმიდისა დედისა ჩვენისა, მოციქულთა სწორისა ქალწულისა ნინო ქართველთა განმანათლებელისათა, წმიდა მოციქულთა სწორთა: მეფისა მირიანისა და დედოფლისა ნანასითა; წმიდათა შორის მამათა ჩვენთა, და მსოფლიოთა დიდთა მოძღვართა და მღვდელთ-მთავართა, ბასილი დიდისა, გრიგოლი ღმრთის-მეტყველისა, და იოანე ოქროპირისათა, წმიდათა შორის მამისა ჩვენისა ნიკოლოზ მირონ-ლუკიის მთავარეპისკოპოსისა და საკვირველთმოქმედისათა, და წმიდათა დიდებულთა და ღვაწლის-მძლეთა მოწამეთა: წმიდისა მთავარ-მოწამისა ძლევაშემოსილისა გიორგისათა, და წმიდათა მოწამეთა არგვეთის მთავართა დავით და კონსტანტინესითა, წმიდათა ღირსთა და ღმერთშემოსილთა მამათა ჩვენთა იოანე ზედაზნელისა და მისთა თორმეტთა მოწაფეთა და წმიდათა იოანე, ექვთიმე და გიორგი მთაწმინდელთა, წმიდათა კეთილმსახურთა მეფეთა ბაგრატ III-ისა, დავით აღმაშენებელისა და თამარისათა, და წმიდათა და მართალთა მშობელთა ღმრთისათა იოაკიმ და ანასითა, (და წმიდისა სახელი, რომლისა არს ტაძარი), და ყოველთა წმიდათა შენთათა, კეთილმითვალულ ჰყავ ვედრება ჩვენი, მოგვანიჭე ჩვენ შენდობა შეცოდებათა ჩვენთა, დაგვიფარენ ჩვენ საფარველითა ფრთეთა შენთათა, ვარსდევნენ ჩვენგან ყოველი მტერნი და მბრძოლნი ჩვენნი, დაამშვიდე ცხოვრება ჩვენი, უფალო შეგვიწყალენ ჩვენ, და სოფელი შენი, და აცხოვნენ სულნი ჩვენნი, ვითარცა სახიერ ხარ და კაცთმოყვარე."},{"t":"rubric","text":"ასამაღლებლის შემდეგ სასულიერონი გადმოდიან შუა ტაძარში, ეპისკოპოსი დგება მაღალდასაჯდომელთან."},{"t":"rubric","text":"წმიდაო ღმერთოს შემდეგ:"},{"t":"say","role":"deacon","who":"I დიაკონი ამბიონზე","text":"ერთად ვსთქვათ (და ნელი ტემპით ხალხთან ერთად იტყვის მამაო ჩვენო, პირით მრევლისკენ)."},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ შენი არს სუფევა, ძალი და დიდება, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"rubric","text":"დიაკონი ასამაღლებლის დროს უბრუნდება თავის ადგილს. II დიაკონი მამაო ჩვენოს ასამაღლებელზე სასაკმევლეს აკურთხებინებს მღვდელმთავარს და ტროპრების დროს აკმევს გამზადებულ პურს ოთხივე მხრიდან 3-გზის."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. ღვთისმშობელო ქალწულო გიხაროდენ... (გ გზის) ან ტროპარი დღესასწაულისა."},{"t":"rubric","text":"მესამეჯერ კმევის შემდეგ აკმევს ანალოღიის ხატს და მღვდელმთავარს და უკმევს 9-გზის."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"უფლისა მიმართ ვილოცოთ. გუნდი: უფალო შეგვიწყალენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"უფალო იესო ქრისტე ღმერთო ჩვენო, რომელმან აკურთხენ ხუთნი პურნი და ხუთ ათასნი განაძღენ, ეგრეთვე აკურთხენ პურნიცა ესე, ხვარბალი, ღვინო და ზეთი, და განამრავლენ ესენი წმიდასა ამას ტაძარსა, და ქალაქსა ამას შინა, და ყოველსა ქვეყანასა და ერსა შენსა ზედა და რომელთა მიიღონ ამათგან სარწმუნოებით, მიეც მათ განწმედა, რამეთუ შენ ხარ, რომელი აკურთხევ და განწმენდ ყოველთავე, ქრისტე ღმერთო ჩვენო, და შენდა დიდებასა აღვავლენთ, თანა დაუსაბამოთ მამით შენით, და ყოვლად წმიდით, სახიერით და ცხოველსმყოფელით სულით შენითურთ, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. იყავნ სახელი შენი კურთხეულ ამიერითგან და უკუნისამდე..."},{"t":"rubric","text":"მღვდელმთავარი ამბიონზე 33 ფსალმუნის შემდეგ დასახავს დიკირ-ტრიკირით ჯვარს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"კურთხევა უფლისა თქვენ ზედა მისითა მადლითა და კაცთმოყვარეობითა, ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"rubric","text":"თუ აღდგომის პერიოდია ქრისტე აღსდგა 3-გზის."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. დიდება მაღალთა შინა... გ გზის. უფალო ბაგენი ჩემნი... ბ გზის."},{"t":"rubric","text":"მღვდელმთავარი და სამღვდელოება შემობრძანდებიან აღსავლის კარით საკურთხეველში და დადგები ტრაპეზთან. დიაკვნები გვერდითა კარით შევლენ საკურთხეველში, დიდება მაღალიანის შემდეგ დაიხურება აღსავლის კარი და განიმოსება მღვდელმთავარი."}],"toc":[{"text":"დასაწყისი","i":0},{"text":"103-ე ფსალმუნი","i":12},{"text":"ლოცვა ა","i":15},{"text":"ლოცვა ბ","i":17},{"text":"ლოცვა გ","i":19},{"text":"ლოცვა დ","i":21},{"text":"ლოცვა ე","i":23},{"text":"ლოცვა ვ","i":25},{"text":"ლოცვა ზ","i":27},{"text":"დიდი კვერექსი","i":29},{"text":"უფალო ღაღადვყავი","i":66},{"text":"ლოცვა მოდრეკით","i":146},{"text":"კურთხევა და დასასრული","i":180}]},{"id":"matins","name":"ცისკარი","subtitle":"წესი და განგება ცისკრისა","blocks":[{"t":"rubric","text":"დიდ მარხვაში სადაგში ცისკარი მოებმის შუაღამიანს. აღსავლის კარი დახურულია, კრეტსაბმელი ღიაა"},{"t":"say","role":"priest","who":"მღვდელი","text":"კურთხეულ არს ღმერთი ჩუენი ყოვლადვე აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"მედავითნე","text":"ამინ. დასაწყისი ლოცვები. ით და კ ფსალმუნი, ტროპრები"},{"t":"rubric","text":"მღვდელი და დიაკონი აკმევენ სრულად საკურთხეველს, კანკელს მთელს ტაძარს და მრევლს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვიწყალენ ჩუენ ღმერთო დიდითა წყალობითა შენითა გევედრებით ისმინე და შეგვიწყალენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით ღვთივდაცულისა ერისა ჩუენისა, მთავრობისა და მხედრობისა მისისათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით უწმინდესისა და უნეტა-რესისა, სრულიად საქართველოს კათოლიკოს-პატრიარ-ქისა და მცხეთა-თბილისის მთავარეპისკოპოსისა, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტისა დიდისა მეუფისა მამისა ჩუენსა ი ლ ი ა ს ა თ ვის, და სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრისა მაღალყოვლადუსამღვდელოესისა სენაკისა და ჩხოროწყუს მიტროპოლიტისა შიოსათვის, და მაღალყოვლადუსამღვდელოესისა ქუთათელ-გაენათელი მიტროპოლიტისა იოანესათვის და ყოველთა ქრისტეს მიერ ძმათა ჩუენთათვის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით უწმინდესისა და უნეტა-რესისა, სრულიად საქართველოს კათოლიკოს-პატრიარ-ქისა და მცხეთა-თბილისის მთავარეპისკოპოსისა, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტისა დიდისა მეუფისა მამისა ჩუენსა ი ლ ი ა ს ა თ ვის, და სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრისა მაღალყოვლადუსამღვდელოესისა სენაკისა და ჩხოროწყუს მიტროპოლიტისა შიოსათვის, და მაღალყოვლადუსამღვდელოესისა ქუთათელ-გაენათელი მიტროპოლიტისა იოანესათვის და ყოველთა ქრისტეს მიერ ძმათა ჩუენთათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით ყოველთა ძმათა და ყოველთა ქრისტიანეთათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ მოწყალე და კაცთმოყვარე ღმერთი ხარ, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. სახელითა უფლისათა მაღალყოვლადუსამღვდელოესო მეუფეო გვაკურთხენ."},{"t":"say","role":"priest","who":"მღვდელი","text":"დიდება წმიდასა თანა არსსა, და ცხოველს-მყოფელსა, და განუყოფელსა სამებასა, ყოვლადვე, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. დიდება მაღალთა შინა ღმერთსა ქვეყანასა ზედა მშვიდობა და კაცთა შორის სათნოება. (გ-გზის). უფალო ბაგენი ჩემნი აღაღვენ და პირი ჩემი უთხრობდეს ქებულებასა შენსა (ბ-გზის)."},{"t":"say","role":"choir","who":"მედავითნე","text":"ექვსფსალმუნება."},{"t":"rubric","text":"ფსალმუნების პირველ ნაწილის შემდეგ წინამძღვარი გადის აღსავლის კარის წინ კითხულობს ლოცვებს, მეორე ნაწილს დასრულებისას დიდებაზე II დიაკონი იღებს კურთხევას გამოდის ჩრდილოეთის კარით და ამბობს მშვიდობიან კვერექსს."},{"t":"head","text":"ლოცვა ა"},{"t":"prayer","text":"გმადლობ შენ უფალო ღმერთო ჩუენო, რომელმან აღმადგინენ ჩუენ სარეცელთაგან ჩუენთა, და მოეც პირსა ჩუენსა სიტყვაი ქებისა, თაყუ-ანის-ცემად და ხდად სახელსა შენსა წმიდასა, და ვედრებად მოწყალებათა შენთა და სიტკბოებათა, რომელი ყოვ-ლადვე გიჩუენებიეს საცხოვრებელად ჩუენდა, და აწცა გარდამოავლინე შეწევნაი შენი მდგომარეთა ამათ ზედა წინაშე პირსა წმიდისა დიდებისა შენისასა, რომელნი მოელიან შენ მიერ მდიდარდ წყალობასა, და მიეც მათ ყოვლადვე შიშით და სიყვარულით მარადის მსახურებად შენდა, ქება, გალობა, და თაყვანის-ცემა, გამოუთქმელისა სათნოებისა შენისა: რამეთუ შვენის შენდა ყოველი დიდება პატივი და თაყვანის-ცემა, მა-მისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ბ"},{"t":"prayer","text":"ღამითგან აღიმსთობს სული ჩუენი შენდამი ღმერთო ჩუენო, რამეთუ ნათელ არიან ბრძანებანი შენნი ქვეყანასა ზედა, სიმართლისა და სიწმიდისა აღსრულებად შიშითა შენითა, გონიერ მყვენ ჩუენ, რამეთუ შენ გადიდებთ, ჭეშმარიტებით, ჭეშმარიტსა ღმერთსა ჩუენსა, მოყავ ყური შენი, და ისმინე ჩუენ, და მიხსენ უფალო ყოველნი ესე აქა მყოფნი, და ჩუენ თანა მლოცველნი კაცად კაცადისა სახელები, და გვაცხოვნენ ჩუენ ძალითა შენითა, და აცხოვნე ერი შენი, და წმიდა ჰყავ სამკვი-დრებელი შენი. მშვიდობა სოფელსა მოანიჭე, ეკლესიათა შენთა, მღვ-დელთა, ხელმწიფესა ჩუენსა, და ყოვე-ლსა ერსა შენსა: რამეთუ კურთხეულ არს და დიდე-ბულ ყოვლად პატიოსანი და დიდად შვენიერი სახელი შენი, მამისა, და ძი-სა, და წმიდისა სულისა, აწდა მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა გ"},{"t":"prayer","text":"ღამითგან აღიმსთობნ სულნი ჩუენნი შენდამი ღმერთო, რამეთუ ნათელ არიან ბრძანებანი შენნი, გვასწავენ ჩუენ ღმერთო სიმართლენი და მცნებანი შენნი. განანათლენ თვალნი გონებათა ჩუენთანი, ნუ უკუე დავიძინოთ ცოდ-ვათა შინა სიკვდიდ, და განიოტე ყო-ველი წყვდიადი გულთაგან ჩუენთა, და მოგვანიჭე ჩუენ სიმართლისა იგი მზეი და უვნებელად ცხოვრებაი ჩუენი დაიცევ ბეჭდითა სულისა შენისა წმიდისათა, წარმართენ სლვანი ჩუენნი გზასა მშვიდობისასა, მომეც ჩუენ ცისკარი და დღეი მხიარულებით. რათა შენდა ცისკრისა ლოცვასა შევსწირვიდეთ: რამეთუ შენი არს სიმტკიცე, და შენი არს სუფევა, ძალი და დიდება, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა დ"},{"t":"prayer","text":"მეუფეო წმიდაო, რომელი წმიდა ხარ და მიუწვდომელ, რომელმან სთქუ ბნელისაგან ნათელი გამობრწყინვე-ბად, რომელმან განგვისვენენ ჩუენ ღამესა ამას ძილითა, და აღგვადგინენ დიდების მეტყველებად და ვედრებად შენისა სათნოებისა, ვედრებულ იქმენ თვისისა მოწყალებისაგან, და შე-გვიწყალენ ჩუენ რომელნი ესე აწცა თაყვანის-გცემთ, და მსგავსად ძა-ლისა ჩუენისა გმადლობთ შენ, და მომანიჭე ჩუენ ყოველნივე საცხოვრე-ბელად თხოვა, და გამოგვაჩინენ ჩუენ ნათლისად და დღისა, და მკვიდრად სა-უკუნეთა მათ კეთილთა შენთა. მოიხსე-ნე, უფალო, სიმრავლითა მოწყალებათა შენთათა ყოველი ერი შენი, თანა მყოფი და თანა მლოცველი ჩუენნი, და შორის მყოფნი ძმანი ჩუენნი ქვეყანასა, და ზღვასა, და ყოველსა ადგილსა უფ-ლებისა შენისასა, მვედრებელთა შე-ნისა კაცთ-მოყვარეობისა და შეწევნი-სათა, და ყოველთავე მოგვეც შენი დიდი წყალობაი, რათა ცხოვნებულნი სულით და ხორცით ყოვლადვე ვეგნეთ, და კადნიერებით ვადიდებდეთ საკვი-რველსა და კურთხეულსა სახელსა შენ მამისა, და ძისა, და წმიდისა სულისა აწ და მარადის, და უკუნითი უკუნისამდე, ამინ. რამეთუ ღმერთი წყალობისა, მო-წყალებისა და კაცთ-მოყვარეობისა ხარ და, შენდა დიდებასა აღვავლენთ მა-მისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ე"},{"t":"prayer","text":"კეთილთა საუნჯეო, წყაროსა დაუწყვედელისაო, მამაო წმიდაო საკვირველთ მოქმედო, ყოვლად ძლიერო, ყოვლისა მპყრობელო, ყოველნი შენ თაყვანის-გცემთ, და ვევედრებით შენთა წყალობათა და შენთა მოწყალებათა ვხადით შემწედ და ხელის აღმპყრობელად სიმდაბლისა ამის ჩუენისა, მოგვიხსენენ, უფალო, მონანი შენნი, და შეიწირე ჩუენ ყოველთაგან საცისკრო ესე ვედრებაი, ვითარცა საკმეველი შენ წინაშე, და ნუვის ერთსაცა ჩუენგანსა განგდებულ ჰყოფ, არამედ ჩუენ ყოველნი გვრვაწენ სათნოებითა შენითა, მოიხსენე, უფალო, რომელნი იღვიძებენ და გალობენ სადიდებელად შენდა, და მხოლოდ შობილისა ძისა შენისა, და ღვთისა ჩუენისა, და წმიდისა სულისა შენისა: ეყმენ მათ შემწე და ხელის აღმპყრობელ, და შეიწირე თხოვაი მათი ზეცისა საცნაურსა შენსა საკურთხეველსა:"},{"t":"prayer","text":"რამეთუ შენ ხარ ღმერთი ჩუენი, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ვ"},{"t":"prayer","text":"გმადლობ შენ, უფალო ღმერთო ცხო-ვრებისა ჩუენისაო, რამეთუ ყოვე-ლსავე იქმ ქველის მოქმედებად ცხოვრებისა ჩუენსა-თვის, რათა სამა-რადისოდ შენდა მომართ ვხედვიდეთ მაცხოვრისა და მხსნელისა სულთა ჩუენთასა, რამეთუ შენ განგვისვენენ წარსრულითა ამით კერძითა ღამისათა, და აღმადგინენ ჩუენ სარეცელთაგან ჩუენთა, და დამადგინენ თაყვანის-ცემად პატიოსნისა სახელისა შენისა, რომლისა თვისცა გევედრებით შენ, უფალო, მომეც ჩუენ მადლი და ძალი, რათა ღირს ვიქმნნეთ გალობად შენდა გულისხმის-ყოფით და ლოცვად დაუცადებლად, და შიშით, და ძრწოლით თვისისა ცხოვრებისა ქმნად, შეწევნითა ქრისტეს შენისათა: მოიხსენე, უფალო, ღამით შენდა მღაღადებელთა, და შეისმინე მათი, და შეიწყალენ, და შემუსრენ ქვეშე ფერხთა მათთა ყოველნი უხილავნი და წინა აღმდგომნი მტერნი. რამეთუ შენ ხარ მეუფე მშვიდობისა, და მაცხოვარი სულთა ჩუენთა, და შენდა დიდებასა აღვავლენთ, მა-მისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ზ"},{"t":"prayer","text":"ღმერთო და მამაო უფლისა ჩუენისა იესო ქრისტესო, რომელმან აღმადგინენ ჩუენ ძილისაგან სარეცელთა ჩუენთასა, და შემომკრიბენ ჩუენ ჟამსა ამას ლოცვისასა, მომეც ჩუენ მადლი აღებასა პირისა ჩუენისასა, და შეიწირე ჩუენ ძალისაებრ ვედრებაი, და მასწავენ ჩუენ სიმართლენი შენი, რამეთუ რაი ვილოცოთ, ვითარ ჯერ არს, არა უწყით, არა თუ შენ ღმერთო წმიდითა სულითა შენითა მიმიძღვე ჩუენ, ამის-თვის, გევედრებით შენ, რაიცა რა ვჰსცოდეთ ვიდრე ამად ჟამადმდე, სიტყვით, გინა საქმით, ანუ გონებით, ნებსით, გინა უნებლიეთ, გვილხინე, მოგვიტევე და შეგვინდევ, რამეთუ უკეთუ უსჯულოებათაებრ მიაგებდე, უფალო, უფალო, ვინმე დაუთმოს, რამეთუ შენ მიერ არს ლხინება, და შენ მიერ არს გამოხსნა, შენ მხოლო ხარ წმიდა, შემწე, ძლიერი შესავედრებელი ცხოვრებისა ჩუენისა, და შენ მიერ არს გალობა ჩუენი მარადის:"},{"t":"prayer","text":"იყავნ სიმტკიცე სუფევისა შენისა კურთხეულ, და დიდებულ, მამისა, და ძისა და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ჱ"},{"t":"prayer","text":"უფალო ღმერთო ჩუენო, რომელმან უდებებაი ძილისა ჩუენისა განმ-ძარცვე ჩუენგან, და მიწოდე ჩუენ წოდებითა წმიდითა ღამესა შინა აღპყრობასა ხელთა ჩუენთასა, და აღსარებად შენდა სასჯელთა-თვის სიმარ-თლისა შენისათა, შეიწყნარენ ვე-დრებანი ჩუენნი, მდაბალნი აღსარებანი, ღამითნი მსახურებანი, მოგვმადლე ჩუენ, ღმერთო, სარწმუნოებაი ურცხვენელი, სასოებაი მტკიცე, სიყ-ვარული შეუორგულებელი. აკურ-თხენ შესავალნი ჩუენნი, და გამოსა-ვალნი, საქმენი, ქმნანი, სიტყვანი, და მოგებანი. და მომანიჭენ ჩუენ მიწევნა დასაბამსა დღისასა, მგალობელად, მაკურთხებელად, და მაქებელად, გამოუთქმელსა სიტკბოებისა და სათნოებისა შენსა: რამეთუ კურთხეულ არს ყოვლად პატიოსანი სახელი შენი, და დიდებულ მეუფება შენი, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა თ"},{"t":"prayer","text":"გამოაბრწყინვე გულთა შინა ჩუენთა, მეუფეო კაცთ-მოყვარეო, ნათელი მიუწთომელი, და გონებისა ჩუენისა თვალნი განახვენ, განცდად სახარებისა შენისა ქადაგებითა, და დასდევ ჩუენ ზედა ნეტართა მათ მცნებათა შენთა შიში, რათა ყოველ-სავე ხორციელი გულის-თქმა დავსთ-რგუნოთ, და სულიერი მოქალაქობა მოვიგოთ, და ყოველსავე სათნოდ შენდა ვზრახვიდეთ და ვიქმოდეთ: რამეთუ შენ ხარ განმწმენდელი და განმანათლებელი ჩუენი, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ი"},{"t":"prayer","text":"უფალო ღმერთო ჩუენო, რომელმან სინანულისა მიერ მოტევება ცოდვათა კაცთა მოანიჭე, და მსგავსად ბრალთა ჩუენთა შენდობისა და აღსარებისა და-ვით წინასწარმეტყველისა მიერ სინანული შესანდობელად გვიჩუენე, შენ მეუფეო, მრავალთა და დიდთა ცოდ-ვათა შინა დაცემულნი ესე შეგვიწყა-ლენ, დიდითა შენითა წყალობითა, და მრავლითა მოწყალებითა შენითა აღხოცე უსჯულოება ჩუენი, რამეთუ შენ წინაშე ვჰსცოდეთ, უფალო, რამელმან უჩინონი და დაფარულნი გულთა კაც-თანი უწყნი, და შენ მხოლოსა გაქვს ხელმწიფებაი მიტევებად ცოდვათა, და აწცა გული წმიდა დაბადე ჩუენ თანა, და სულითა მთავრობისათა დამამტკი-ცენ ჩუენ, და სიხარული მაცხოვარებისა შენისა მასწავენ ჩუენ, და ნუ განმაგდებ ჩუენ პირისა შენისაგან, არამედ სათნო იყავ ვითარცა სათნომან და კაცთ-მოყვარემან ღმერთმან, ვიდრე უკანასკნელთა აღმოფშვინვად-მდე ჩუენდამდე შეწირვად შენდა მსხვერპლი სიმართლისა, და საკვე-რთხი სათნო წინაშე შენსა საკურთხეველსა: წყალობითა, და მოწყალებითა, და კაცთ-მოყვარეობითა, მხოლოდ-შობილისა ძისა შენისათა, რომლისა თანა კურთ-ხეულ ხარ, თანა ყოვლად წმიდით და სათნოით, და ცხოველს-მყოფელით სულით შენითურთ, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა ია"},{"t":"prayer","text":"რმერთო, ღმერთო ჩუენო, რომელმან ნებითა შენითა დაბადენ ზეცისა ძალნი, შენ შეგივრდებით და გევედრებით: მიითვალე ჩუენ ყოველთა დაბადე-ბულთა შენთა მიერ ქება, მსგავსად ძალისაებრ ჩუენისა, და სიმდიდრისა მის ნიჭისა შენისაგან მოგვეც ჩუენ, რამეთუ შენდა მოგვიდრეკიან ყოველთა მუხლნი, ზეცისათა, და ქვეყანისათა, და ქვესკნელისათა, და ყოველი სული დაბადებული აქებს მიუწვდომელსა დი-დებასა შენსა, ვითარცა შენ მხოლო ხარ ღმერთი ჭეშმარიტი და მრავალ-მოწყალე: რამეთუ შენ გიგალობენ ყოველნი ძალნი ცათანი, და შენი არს სუფევა, და ძალი და დიდება, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"head","text":"ლოცვა იბ"},{"t":"rubric","text":"გაქებთ, გიგალობთ, გაკურთხევთ, და გმადლობთ შენ, ღმერთო მამათა ჩუენთაო, რამეთუ თანა წარმჰხადენ აჩრდილნი ღამისანი, არამედ ვევე-დრებით შენსა სათნოებასა: მლხინებელ ეყმენ შეცოდებათა ჩუენთა, და შეიწირე ვედრება ჩუენი დიდითა წყა-ლობითა შენითა, რამეთუ შენდა მომართ მოვივლტით მოწყალისა, და ყოვლად ძლიერისა ღვთისა. გამოაბ-რწყინვე გულთა შინა ჩუენთა ჭე-მარიტი მზე სიმართლისა შენისა, და განანათლენ გონებანი, და საცნობელნი ჩუენნი ყოველნი დაიჩუენ, რათა ვითარცა დღესა შინა შვენიერად ვიდო-დეთ გზასა მცნებათა შენთასა, და მივიწივნეთ საუკუნოსა მას ცხოვრე-ბისა, რამეთუ შენგან არს წყარო ცხოვრებისა, და ღირს ვიქმნეთ ჩუენ შვებად ნათელსა შენსა გამოუთქ-მელსა: რამეთუ შენ ხარ ღმერთი ჩუენი, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ზეგარდამო მშვიდობისა და ცხოვრე-ბისათვის სულთა ჩუენთასა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მშვიდობისათვის ყოვლისა სოფლისა, კეთილად დგომისათვის წმიდათა ღმრთისა ეკლესიათა, და ყოველთა ერთობისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"წმიდისა ამის ტაძრისათვის (მონასტრისათვის), სარწმუნოებითა, სასოებითა და შიშითა ღმრთისათა შემავალთა ამას შინა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"უწმინდესისა და უნეტარესისა, სრულიად საქართველოს კათოლიკოს-პატრიარქი-სა და მცხეთა-თბილისის მთავარეპისკოპოსისა, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტისა დიდისა მეუფისა მამისა ჩუენისა ი ლ ი ა ს ა თ ვის, და სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრისა მაღალყოვლადუსა-მღვდელოესისა სენაკისა და ჩხოროწყუს მიტროპოლიტისა შიოსათვის, და მაღალყოვლადუსამღვ-დელოესისა ქუთათელ-გაენათელი მიტროპოლიტისა იოანესათვის, პატიოსანთა მღვდელთა, ქრისტეს მიერ დიაკონთა და ყოვლისა სამღვდელოისა დასისა და ერისა მათისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ღვთივდაცულისა ერისა ჩუენისა, მთავრობისა და მხედრობისა მათისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"თანა-მბრძოლთათვის და დამორჩილებისა ქვეშე ფერხთა მათთა ყოველთა მტერთა და მბრძოლთა უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სამეუფოისა ქალაქისა ამის ჩუენისა, და წმიდისა ამის ტაძრისა (მონასტრისა) და ყოვლისა ქალაქებისა და სოფლებისა, და სარწმუნოებით მკვიდრთა მათ შინა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"კეთილ-შეზავებისათვის ჰაერთასა, კეთილ-გამოღებისათვის ნაყოფთა ქვეყანისათა და ჟამთა მშვიდობისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მენავეთა, მოგზაურთა, სნეულთა, მშრომელთა, ტყვეთა ხსნისა და ცხოვრებისა მათისათვის, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ხსნად ჩუენდა ყოვლისაგან ჭირისა, რისხვისა და იწროებისა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცუენ ჩუენ, ღმერთო, შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლადწმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩუენისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩუენი ქრისტესა ღმერთსა ჩუენსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ, უფალო."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ შვენის შენდა ყოველი დიდება, პატივი და თაყვანისცემა, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ღმერთი უფალი და გამოგვიჩნდა ჩუენ, კურთხეულ არს მომავალი სახელითა უფლისათა."},{"t":"rubric","text":"მუხლი ა. აუარებდით უფალსა, რამეთუ კეთილ, რამეთუ უკუნისამდე არს წყალობაი მისი."},{"t":"rubric","text":"მუხლი ბ. ყოველი თესლები გარე მომადგეს მე და სახელითა უფლისათა ვერეოდი მათ."},{"t":"rubric","text":"მუხლი გ. არა მოვკვდე, არამედ ვსცხონდე, და განვსთქვნე მე საქმენი უფლისანი."},{"t":"rubric","text":"მუხლი დ. ლოდი, რომელ შეურაცხყვეს მაშენებელთა, ესე იქმნა თავ კიდეთა, უფლისა მიერ იყო ესე და არს საკვირველ წინაშე თვალთა ჩუენთა."},{"t":"rubric","text":"მიცვალებულთა მსახურებაზე:"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ალილუია, ალილუია, ალილუია. მუხლი: ნეტარ არს რომელი გამოირჩიე და შეიწყნარე უფალო, და სახსენებელი მათი იყოს თესლითი თესლამდე. მუხლი: სულმან მათმან კეთილთა შინა განისვენოს და ნათესავმან მათმან დაიმკვიდროს ქვეყანა."},{"t":"rubric","text":"მშვიდობიანი კვერექსის ასამაღლებლის შემდეგ, სტიქაროსნები შემოსავენ მღვდელმთავარს სრულად."},{"t":"rubric","text":"იკითხება I სტიქოლოგია (ფსალმუნის კანონი)"},{"t":"rubric","text":"II დიაკონი იტყვის პირველ მცირე კვერექსს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცუენ ჩუენ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლადწმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩუენისა ღვთის-მშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩუენი, ქრისტესა ღმერთსა ჩუენსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ შენი არს სიმტკიცე, და შენი არს სუფევა, და ძალი, და დიდება, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"იკითხება II სტიქოლოგია. III დიაკონი იტყვის მეორე მცირე კვერექსს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცუენ ჩუენ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლადწმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩუენისა ღვთის-მშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩუენი, ქრისტესა ღმერთსა ჩუენსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო."},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ სათნო, და კაცთმოყვარე ღმერთი ხარ, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"II სტიქოლოგიის წარდგომა."},{"t":"say","role":"choir","who":"გუნდი","text":"აქებდით სახელსა... ან: ნეტარ არიან უბიწონი..."},{"t":"rubric","text":"მეორე მცირე კვერექსის შემდეგ დიაკვნები სანთლებით დადგებიან აღსავლის კართან, სადიდებელის გალობის დაწყებისთანავე გააღებენ და გამოვლენ აღსავლის კარით."},{"t":"rubric","text":"მღვდელმთავარი დადგება შუა ტაძარში მაღალდასაჯდომელთან, მღვდელმთავარს წინამძღვარი მიაწოდებს ანთებულ სანთლებს, რომელთაც უნაწილებს სამღვდელოებას."},{"t":"rubric","text":"დიკირ-ტრიკირი (ტრიკირი-მაცხოვრის ხატის მხარეს, დიკირი ღვთისმშობლის ხატის მხარეს) და რიპიდები ელოდებიან მღვდელმთავარს შუა ხატთან."},{"t":"rubric","text":"იკმევა საკურთხეველი, კანკელი და ტაძარი სრულად."},{"t":"rubric","text":"II დიაკონი და III დიაკონი და თავს დაუხრის მღვდელმთავარს, II დიაკონი შევა საკურთხეველში სახარების გამოსაბრძანებლად, III დიაკონი მცირე კვერექსი შუა ტაძარში."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცუენ ჩუენ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლად-წმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩუენისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩუენი, ქრისტესა ღმერთსა ჩუენსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"რამეთუ კურთხეულ არს სახელი შენი, და დიდებულ მეუფება შენი, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"II დიაკონი ანტიფონების დასრულების შემდეგ აღსავლის კარიდან მღვდელმთავარს დაუხრის თავს, ემთხვევა ტრაპეზს, აიღებს სახარებას და აღსავლის კარით გამოაბრძანებს ამბიონზე და აამაღლებს."},{"t":"say","role":"deacon","who":"ა დიაკონი","text":"სიბრძნით წარდგომა ფსალმუნი დავითისი..."},{"t":"rubric","text":"საცისკრო წარდგომები რვა ხმათა"},{"t":"rubric","text":"ხმა ა"},{"t":"rubric","text":"აწ აღვსდგე იტყვის უფალი, დავსდვა ცხოვრება და განვცხადნე მას ზედა."},{"t":"say","role":"verse","who":"მუხლი","text":"სიტყუანი უფლისანი არიან სიტყვა წმიდა."},{"t":"rubric","text":"ხმა ბ"},{"t":"rubric","text":"განიღვიძე უფალო ღმერთო ჩემო ბრძანებითა მით რომელ ამცენ, და კრებული ერთა გარე მოგადგეს შენ."},{"t":"say","role":"verse","who":"მუხლი","text":"უფალო ღმერთო ჩემო, შენ გესავ, მაცხოვნე მე."},{"t":"rubric","text":"ხმა გ"},{"t":"rubric","text":"თქუთ წარმართთა შორის, რამეთუ უფალი სუფევს, და რამეთუ წარმართა სოფელი, რომელი არა შეიძრას."},{"t":"say","role":"verse","who":"მუხლი","text":"უგალობდით უფალსა გალობითა ახლითა, უგალობდით უფალსა ყოველი ქვეყანა."},{"t":"rubric","text":"ხმა დ"},{"t":"rubric","text":"აღსდეგ უფალო შემეწიენ ჩუენ, და მიხსენ ჩუენ სახელისა შენისათვის."},{"t":"say","role":"verse","who":"მუხლი","text":"ღმერთო ყურთა ჩუენთა გუესმა ჩუენ და მამათა ჩუენთა გვითხრეს ჩუენ."},{"t":"rubric","text":"ხმა ე"},{"t":"rubric","text":"აღსდეგ უფალო ღმერთო ჩემო ამაღლდინ ხელი შენი, რამეთუ შენ სუფევ უკუნისამდე."},{"t":"say","role":"verse","who":"მუხლი","text":"აღგიარო შენ უფალო ყოვლითა გულითა ჩემითა, და მიუთხრა მე ყოველი საკვირველება შენი."},{"t":"rubric","text":"ხმა ვ"},{"t":"rubric","text":"უფალო აღადგინე ძალი შენი, და მოვედ ცხოვრებად ჩუენდა."},{"t":"say","role":"verse","who":"მუხლი","text":"რომელი ჰმწყსი ისრაილსა მოიხილე, რომელი უძღვი ვითარცა ცხვარსა იოსებსა."},{"t":"rubric","text":"ხმა ზ"},{"t":"rubric","text":"აღსდეგ უფალო ღმერთო ჩემო ამაღლდინ ხელი შენი, და ნუ დაივიწყებ გლახაკთა შენთა სრულიად."},{"t":"say","role":"verse","who":"მუხლი","text":"აღგიარო შენ უფალო ყოვლითა გულითა ჩემითა, და მიუთხრა მე ყოველი საკვირველება შენი."},{"t":"rubric","text":"ხმა ჱ"},{"t":"rubric","text":"სუფევს უფალი უკუნისამდე, ღმერთი შენი სიონ თესლითი თესლამდე."},{"t":"say","role":"verse","who":"მუხლი","text":"აქებს სული ჩემი უფალსა, ვაქებდე უფალსა ცხოვრებასა ჩემსა."},{"t":"say","role":"deacon","who":"დიაკონი","text":"უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ წმიდა ხარ შენ, ღმერთო ჩუენო, და რომელი წმიდათა შორის განისვენებ, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოველი სული აქებდით უფალსა."},{"t":"say","role":"verse","who":"მუხლი","text":"აქებდით ღმერთსა წმიდათა შორის მისთა, აქებდით მას სამყაროთა ძალისა მისისათა."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოველი სული."},{"t":"say","role":"choir","who":"გუნდი","text":"აქებდით უფალსა."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ღირსყოფად ჩუენდა სმენად წმიდისა სა-ხარებისა უფალსა ღმერთსა ჩუენსა ვევე-დრნეთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სიბრძნით აღემართენით და ისმინეთ წმიდა სახარება."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობა ყოველთა."},{"t":"rubric","text":"II დიაკონი წამოვა და სახარებას მოაბრძანებს მღვდელმთავართან, მას თან გამოჰყვებიან დიკირ-ტრიკირი და რიპიდები. სახარების კითხვისას ეპისკოპოსი მიტრას მოიხდის."},{"t":"say","role":"choir","who":"გუნდი","text":"და სულისაცა შენისა თანა."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"(სახელი) წმიდისა სახარებისა საკითხავი."},{"t":"say","role":"choir","who":"გუნდი","text":"დიდება შენდა უფალო, დიდება შენდა."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მოხედენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"კითხულობს სახარებას..."},{"t":"rubric","text":"კითხვის დასრულების შემდეგ II დიაკონი სახარებას ისევ ამბიონზე ააბრძანებს და დადგება სახით მღვდელმთავრისაკენ (ვიდრე არ დასრულდება გალობა „აღდგომა ქრისტესი ვიხილეთ“) გალობის დასრულების შემდეგ ჩამოაბრძანებს და დაასვენებს სახარებისთვის გამზადებულ ანალოღიაზე (მხოლოდ შაბათ საღამოს-კვირის ცისკარზე, დანარჩენს შემთხვევებში ყოველთვის შებრძანდება აღსავლის კარით და დაასვენებს ტრაპეზზე)."},{"t":"rubric","text":"I დიაკონი სახარების ამბიონზე ყოფნის დროს დადგება ანალოღიის ხატთან, როდესაც II დიაკონი სახარებას დაასვენებს ანალოღიაზე ორივე მათგანი ემთხვევიან II დიაკონი სახარებას, ხოლო I დიაკონი ხატს და თავს დაუხრიან მღვდელმთავარს, შემდეგ ერთმანეთს I დიაკონი წავა ამბიონზე მაცხოვრის ხატთან. II დიაკონი დაგება პირველი დიაკონის ადგილზე (III დიაკონის მოპირდაპირედ)."},{"t":"say","role":"deacon","who":"ა დიაკონი","text":"აცხოვნე, ღმერთო, ერი შენი, და აკურთხე სამკვიდრებელი შენი, მოხედენ სოფელსა შენსა წყალობითა და მოწყალებითა, აღამაღლე რქა ქრისტიანეთა მართლმადიდებელთა, და გარდამოავლინე ჩუენ ზედა მდიდარნი წყალობანი შენნი, მეოხებითა ყოვლადწმიდისა დედოფლისა ჩუენისა ღმრთის-მშობელისა, და მარადის ქალწულისა მარიამისათა, ძლიერებითა პატიოსნისა და ცხოველსმყოფელისა ჯვარისათა, ძლიე-რებითა ჯვარისა ვაზისათა; მეოხებითა პატიოსანთა უსხეულოთა ზეცისა ძალთათა, პატიოსნისა, დიდებულისა, წინასწარმეტყველისა, წინა-მორბედისა და ნათლისმცემელისა იოანესითა, წმიდათა დიდებულთა, და ყოვლად-ქებულთა მოცი-ქულთა: ანდრია პირველწოდებულისა, სვიმონ კანანელისა და მათათასითა; წმიდისა დედისა ჩუენისა, მოციქულთა სწორისა ქალწულისა ნინო ქართველთა განმანათლებელისათა, წმიდა მოციქულთა სწორთა: მეფისა მირიანისა და დედოფლისა ნანასითა; წმიდათა შორის მამათა ჩუენთა, და მსოფლიოთა დიდთა მოძღვართა და მღვდელთმთავართა, ბასილი დიდისა, გრიგოლი ღმრთისმეტყველისა, და იოანე ოქროპირისათა, წმიდათა შორის მამისა ჩუენისა ნიკოლოზ მირონლუკიის მთავარეპისკოპოსისა და საკვირ-ველთმოქმედისათა და წმიდათა დიდებულთა და ღვაწლისა-მძლეთა მოწამეთა: წმიდისა დიდმო-წამისა ძლევაშემოსილისა გიორგისა, წმიდათა ღირსთა და ღმერთშემოსილთა მამათა ჩუენთა იოანე ზედაზნელისა და მისთა თორმეტთა მოწაფეთა და წმიდათა იოანე, ექვთიმე და გიორგი მთაწმინდელთა, წმიდათა კეთილმსახურთა მეფე ბაგრატ გ-ისა, დავით აღმაშენებელისა და თამარისათა, და წმიდათა და მართალთა მშობელთა ღმრთისათა იოაკიმ და ანასითა, (და წმიდისა სახელი, რომლისა არს ტაძარი), და ყოველთა წმიდათა შენთათა, გევედრებით შენ მრავალ-მოწყალეო ღმერთო, შეისმინე ჩუენ ცოდვილთა ვედრება, და შეგვიწყალენ ჩუენ."},{"t":"say","role":"priest","who":"მღვდელი","text":"წყალობითა, და მოწყალებითა, და კაცთმოყვარეობითა, მხოლოდშობილისა ძისა შენისათა, რომლისა თანა კურთხეულ ხარ, თანა ყოვლად წმიდით, სათნოით და ცხოველს მყოფელით სულით შენითურთ, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ"},{"t":"rubric","text":"აღესრულება ზეთისცხება."},{"t":"rubric","text":"ა-გ გალობა, შემდეგ."},{"t":"rubric","text":"II დიაკონი მცირე კვერექსი"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცუენ ჩუენ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლად-წმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩუენისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩუენი, ქრისტესა ღმერთსა ჩუენსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ შენ ხარ ღმერთი ჩუენი, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"დ-ვ გალობა."},{"t":"rubric","text":"III დიაკონი იტყვის მცირე კვერექსს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცუენ ჩუენ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლად-წმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩუენისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩუენი, ქრისტესა ღმერთსა ჩუენსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო."},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ შენ ხარ მეუფე მშვიდობისა, და მაცხოვარი სულთა ჩუენთა, შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"მღვდელმთავარი ზეთისცხების დასრულების შემდეგ, ამბიონზე და სამივე მხარეს სახავს ჯვარს."},{"t":"say","role":"choir","who":"გუნდი","text":"ისპოლა ეტი დესპოტა."},{"t":"rubric","text":"კვერთხი მაცხოვრის ხატთან რჩება"},{"t":"rubric","text":"საკურთხეველში I დიაკონი ტრაპეზთან გამოართმევს მიტრას და დააბრძანებს ტრაპეზზე."},{"t":"rubric","text":"VII გალობის დასრულების შემდეგ, II დიაკონი აკურთხებინებს მღვდელმთავარს სასაკმევლეს და იწყებს კმევას, აკმევს საკურთხეველს, აღსავლის კარს, მაცხოვრის ხატს და შეჩერდება ღვთისმშობლის ხატთან, საკითხავის დასრულების შემდეგ გამოსახავს სასაკმევლით ჯვარს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ღვთისმშობელსა დედასა ნათლისასა გალობით ვადიდებდეთ."},{"t":"rubric","text":"გააგრძელებს სრულ კმევას."},{"t":"rubric","text":"აღდგომას"},{"t":"rubric","text":"ადიდებს სული ჩემი სამისა დღისა საფლავით აღდგომილსა ქრისტესსა ცხოვრების მომცემელსა."},{"t":"rubric","text":"თომას კვირას"},{"t":"rubric","text":"შენ დიდებულო ქალწულო დედაო ნათლისაო გონებითა წმიდითა ვითარცა უზესთაესსა ყოველთასა ყოველნი გადიდებთ."},{"t":"rubric","text":"ამაღლებას"},{"t":"rubric","text":"ადიდებს სული ჩემი ქვეყანით ზეცად ამაღლებულსა ქრისტესსა ცხოვრების მომცემელსა."},{"t":"rubric","text":"სულთმოფენობას"},{"t":"rubric","text":"მოციქულთა რა იხილეს გარდამოსვლა ნუგეშინისმცემელისა დაუკვირდათ ვითარ სახითა ცეცხლისა ენათათა გამოჩნდა სულიწმიდა."},{"t":"rubric","text":"შობას"},{"t":"rubric","text":"ადიდე სულო ჩემო უპატიოსნესი და უდიდებულესი მაღლისა მხედრობათა ქალწული ყოვლად წმიდა ღვთის-მშობელი."},{"t":"rubric","text":"ნათლისღებას"},{"t":"rubric","text":"ადიდე სულო ჩემო უპატიოსნესი მაღლისა მხედრობათა ქალწული ღვთის-მშობელი ყოვლადწმიდა."},{"t":"rubric","text":"ღვთისმშობლის შობას"},{"t":"rubric","text":"ადიდებს სული ჩემი ყოვლად დიდებულსა შობასა ღმთისა დედისასა."},{"t":"rubric","text":"ჯვართამაღლებას"},{"t":"rubric","text":"ადიდებს სული ჩემი ყოვლად პატიოსანსა ჯვარსა უფლისასა."},{"t":"rubric","text":"ღვთისმშობლის ტაძრად მიყვანებას"},{"t":"rubric","text":"ანგელოზთა რა იხილეს შესვლა ყოვლადწმიდისა დაუკვირდათ ვითარ ქალწული შევალს წმიდასა შინა წმიდათასა."},{"t":"rubric","text":"მირქმას"},{"t":"rubric","text":"ღვთისმშობელო ქალწულო სასოებაო ქრისტიანეთაო დაგვიფარე, დაგვიცე და გვაცხოვნე რამეთუ შენ ზედა დაგვიძს სასოება."},{"t":"rubric","text":"ხარებას"},{"t":"rubric","text":"აუწყებდით ქვეყანა სიხარულსა დიდსა აქებდით ზეცისა ღმრთისა დიდებასა."},{"t":"rubric","text":"ფერიცვალება"},{"t":"rubric","text":"ადიდე სულო ჩემო თაბორს ზედა ფერიცვალება უფლისა."},{"t":"rubric","text":"ღვთისმშობლის მიძინება"},{"t":"rubric","text":"ანგელოზთა მიცვალება ყოვლადწმიდისა იხილეს დაუკვირდათ ვითარ ქალწული აღვალს ქვეყანით ზეცად."},{"t":"rubric","text":"წინადაცვეთას"},{"t":"rubric","text":"ადიდე სულო ჩემო სჯულისაებრ ხორცითა წინადაცვეთა უფლისა."},{"t":"rubric","text":"კვართისა საუფლოსა"},{"t":"rubric","text":"ადიდებს სული ჩემი ცხოვრების მომცემელსა კვართსა უფლისასა."},{"t":"rubric","text":"ბზობას"},{"t":"rubric","text":"მოწაფეთა რა იხილეს, შესლვა ქრისტესი იერუსალიმს შინა, დაუკვრდათ ვითარ ყრმანი და ჩჩვილნი ერთა თანა ურწმუნოთა უგალობდენ ოსანნასა."},{"t":"rubric","text":"ვაიკითხება IX გალობა."},{"t":"rubric","text":"I დიაკონი კვერექსი."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცუენ ჩუენ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლად-წმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩუენისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩუენი, ქრისტესა ღმერთსა ჩუენსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო."},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ შენ გიგალობენ ყოველნი ძალნი ცათანი, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"წმიდა არს უფალი ღმერთი ჩუენი."},{"t":"say","role":"verse","who":"მუხლი ა","text":"რამეთუ წმიდა არს უფალი ღმერთი ჩუენი."},{"t":"say","role":"verse","who":"მუხლი ბ","text":"ყოველსა ერსა ზედა ღმერთი ჩუენი."},{"t":"rubric","text":"დიაკონი შედის სამხრეთის კარით."},{"t":"rubric","text":"აქებდითის დიდების მუხლზე I დიაკონი მღვდელმთავარს მიაწოდებს მიტრას, ხოლო სტიქაროსნები დიკირ-ტრიკირს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"დიდება შენდა რომელმან მოგვფინე ნათელი."},{"t":"say","role":"choir","who":"გუნდი","text":"დიდება მაღალიანი."},{"t":"rubric","text":"მღვდელმთავარი ამბიონზე მრევლს გადასახავს ჯვარს დიკირ-ტრიკირით შევა."},{"t":"rubric","text":"დიაკონები დადგებიან ტრაპეზთან, I და III დიაკვნები მეუფისგან მარჯვნივ II დიაკონი მარცხნივ, ვიდრე არ დასრულდება დიდება მაღალიანი."},{"t":"rubric","text":"წმიდაო ღმერთოზე წინამძღვარი აიღებს კურთხევას მღვდელმთავრისგან გავა აღსავლის კარით და შემოაბრძანებს სახარებს და დაასვენებს ტრაპეზზე. დიდების მუხლზე II-III დიაკონი მივლენ მაღალდასაჯდომელთან აიღებენ კურთხევას და ჯვარედინად გავლენ კვერექსებზე."},{"t":"rubric","text":"II დიაკონი იტყვის კვერექსს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვიწყალენ ჩუენ ღმერთო, დიდითა წყალობითა შენითა, გევედრებით, ისმინე და შეგვიწყალენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით ღვთივდაცულისა ერისა ჩუენისა, მთავრობისა და მხედრობისა მათისათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით უწმიდესისა და უნეტარესისა, სრულიად საქართველოს კათოლიკოს-პატრიარქისა და მცხეთა-თბილისის მთავარ-ეპისკოპოსისა, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტისა დიდისა მეუფისა მამისა ჩუენსა ი ლ ი ა ს ა თ ვის, და სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრისა მაღალყოვ-ლადუსამღვდელოესისა სენაკისა და ჩხოროწყუს მიტროპოლიტისა შიოსათვის, და მაღალყოვლადუ-სამღვდელოესისა ქუთათელ-გაენათელი მიტროპოლიტისა იოანესათვის და ყოველთა ქრისტეს მიერ ძმათა ჩუენთათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით სანატრელთა და მარადის მოსახსენებელთა, წმიდათა მართლმადიდებელთა პატრიარქთა, კეთილმსახურთა მეფეთა და კეთილმორწმუნეთა დედოფალთა და აღმაშენებელთა წმიდისა ამის ტაძრისათა (მონასტრისათა) და ყოველთა პირველ დაძინე-ბულთა მამათა და ძმათა, აქა მდებარეთა, და ყოველთა მართლმადიდებლობით შესვენებულთათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით წყალობისა, სიცოცხლისა, მშვიდობისა, სიმრთელისა, ცხოვრე-ბისა, შეწევნისა, შენდობისა და მიტევებისა ცოდვათასა, მონათა ღვთისათა, ძმათა წმიდისა ამის ტაძრისათა (ან მონასტრისათა)."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით ნაყოფის შემომწირველთათვის და კეთილისმყოფელთა წმიდისა და ყოვლადპატიოსნისა ამის ტაძრისა და ამას შინა მშრომელთა, მგალობელთა და აქ მდგო-მარეთა ერთათვის, რომელნი მოელიან შენ მიერ დიდსა და მდიდარსა წყალობასა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ გ-გზის."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"რამეთუ მოწყალე და კაცთმოყვარე ღმერთი ხარ, და შენდა დიდებასა აღვავლენთ, მამისა და ძისა და წმიდისა სულისა აწდა მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"III დიაკონი იტყვის კვერექსს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"აღვასრულოთ საცისკრო ვედრება ჩუენი უფალსა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგვიწყალენ და დაგვიცუენ ჩუენ, ღმერთო, შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგვიწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"დღე ყოველი სრულიად, სიწმიდით, მშვიდობით და უცოდველად, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ანგელოზი მშვიდობისა, სარწმუნო წინა-მძღვარი, მცველი სულთა და ხორცთა ჩუენთა, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შენდობა და მოტევება ცოდვათა და უსჯულოებათა ჩუენთა, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"კეთილნი და უმჯობესნი სულთა ჩუე-ნთანი და მშვიდობა სოფლისა, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შემდგომნი ჟამნი ცხოვრებისა ჩუენისანი მშვიდობით და სინანულით აღსრულებად, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ქრისტიანობითნი აღსასრულნი ცხოვრე-ბისა ჩუენისანი, უჭირველნი, ურცხვენელნი, მშვიდობითნი, და კეთილი სიტყვისგება წინაშე საშინელისა მსაჯვროსა ქრისტესსა ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლად-წმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩუენისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა, და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი, და ურთიერთ არს, და ყოველი ცხოვრება ჩუენი ქრისტესა ღმერთსა ჩუენსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ, უფალო."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ ღმერთი წყალობისა და მოწყალებისა ხარ, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"კვერექსის ბოლო მუხლზე სტიქაროსნები აანთებენ დიკირ-ტრიკირს და ბოლო ასამაღლებლის შემდეგ გადიან ამბიონზე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობა ყოველთა. გუნდი: და სულისაცა შენისა თანა. დიაკონი: თავნი ჩუენ უფალსა მოუდრიკნეთ. გუნდი: შენ უფალო."},{"t":"say","role":"priest","who":"საიდუმლოდ მღვდელმან","text":""},{"t":"prayer","text":"რმერთო წმიდაო, რომელი დამკვიდრე-ბულ ხარ მაღალთა შინა, და ყოვლისა მხედველითა თვალითა შენითა ხედავ ყოველთა დაბადებულთა შენთა, შენდა მოგვიდრეკიან ქედნი გულთა და ხორცთა ჩუენთანი, და გევედრებით შენ წმიდაო წმიდათაო, მოყავ ხელნი შენი უხილავი წმიდით სამკვიდრებელით შენით და გვაკურთხენ ჩუენ ყოველნი, და რაოდენნი რა გცოდეთ ნებსით, ანუ უნებლიეთ, ვითარცა სათნომან და კაცთ-მოყვარემან ღმერთმან შეგვინდევ, და მოგვანიჭენ ჩუენ ქვეყანისა, და ზეცისა კეთილი სათნოებითა შენითა:"},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ შენი არს მოწყალება, და მაცხოვარება, ღმერთო ჩუენო, და შენდა დიდებასა აღვავლენთ, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სიბრძნით."},{"t":"say","role":"choir","who":"გუნდი","text":"სახელითა უფლისათა მაღალყოვლადუსამღვდელოესო მეუფეო გვაკურთხენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"რომელი კურთხეულ არს ქრისტე ღმერთი ჩუენ, ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. დაამტკიცე ღმერთო და განაძლიერე ღვთივდაცული ერი ჩუენ და მეუფება მისი, წმიდა მართლმადიდებელი სარწმუნოება და მართლმადიდებელნი ქრისტიანენი უკუნითი უკუნისამდე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ყოვლადწმიდაო ღვთისმშობელო გვაცხოვნენ ჩუენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უპატიოსნესსა ქერუბიმთასა და აღმატებით უზესთაესსა სერაფიმთასა განუხ-რწნელად მშობელსა სიტყვისა ღვთისასა, მხოლოსა ღვთისმშობელსა გალობით ვადიდებდეთ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"დიდება შენდა ქრისტე ღმერთო, სასოებაო ჩუენო დიდება შენდა."},{"t":"say","role":"choir","who":"გუნდი","text":"დიდება მამასა და ძესა და წმინდასა სულსა, აწ და მარადის და უკუნითი უკუნისამდე. ამინ. უფალო შეგვიწყალენ გ-გზის. სახელითა უფლისათა მაღალყოვლადუსამღვდელოესო მეუფეო გვაკურთხენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მკვდრეთით აღდგომილმან ქრისტემან ჭეშმარიტმან ღმერთმან ჩუენმან, მეოხებითა ყოვლად უხრწნელისა დედისა თვისისათა, წმიდათა და ყოვლად ქებულთა მოციქულთა, ღირსთა და ღმერთშემოსილთა მამათა ჩუენთა, (წმიდისა, რომლისა არს სახელობის ტაძარი ესე, და წმიდისა, რომლისა ხსენებასა აღვასრულებთ), წმიდათა და მართალთა მშობელთა ღვთისათა იოაკიმ და ანასითა და ყოველთა წმიდათა, შეგვიწყალნეს და გვაცხოვნეს ჩუენ, ვითარცა სათნო არს და კაცთმოყვარე."},{"t":"rubric","text":"ეპისკოპოსი გამოსახავს დიკირ-ტრიკირით ჯვარს 3 მხარეს."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. უფალო შეგვიწყალენ გ-გზის."},{"t":"rubric","text":"კვერთხი შევა სამხრეთ კარებით საკურთხეველში. დაიხურება აღსავლის კარი და კრეტსაბმელი."},{"t":"rubric","text":"განიმოსება მღვდელმთავარი."},{"t":"rubric","text":"ა ჟამნი"},{"t":"rubric","text":"ჟამნობის დასასრულს:"},{"t":"say","role":"choir","who":"მედავითნე","text":"სახელითა უფლისათა მაღალყოვლადუსამღვდელოესო მეუფეო გვაკურთხენ."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"ღმერთო მიწყალენ ჩუენ და მაკურთხენ ჩუენ, გამოაჩინე პირი შენი ჩუენ ზედა და შეგვიწყალენ ჩუენ."},{"t":"say","role":"choir","who":"მედავითნე","text":"ამინ."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"ქრისტე ნათელო ჭეშმარიტო, რომელი განანათლებ და წმიდა ჰყოფ ყოველსა კაცსა, მომავალსა სოფლად, გამოაჩინე ჩუენ ზედა ნათელი პირისა შენისა, რათა ვიხილოთ ჩუენ ნათელი შენი მიუწვდომელი, და წარმართენ სლვანი ჩუენნი ქმნად მცნებათა შენთა, მეოხებითა უხრწნელისა ღვთისმშობელისათა, და ყოველთა წმიდათა შენთათა."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. ზესთა მბრძოლისა ჩემისთვის..."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"დიდება შენდა ქრისტე ღმერთო, სასოებაო ჩუენო დიდება შენდა."},{"t":"say","role":"choir","who":"გუნდი","text":"დიდება მამასა და ძესა და წმინდასა სულსა, აწ და მარადის და უკუნითი უკუნისამდე. ამინ. უფალო შეგვიწყალენ გ-გზის."},{"t":"rubric","text":"სახელითა უფლისათა მაღალყოვლადუსამღვდელოესო მეუფეო გვაკურთხენ."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"მკვდრეთით აღდგომილმან ქრისტემან ჭეშმარიტმან ღმერთმან ჩუენმან, მეოხებითა ყოვლად უხრწნელისა დედისა თვისისათა, წმიდათა და ყოვლად ქებულთა მოციქულთა (წმიდისა, რომლისა არს სახელობის ტაძარი ესე, და წმიდისა, რომლისა ხსენებასა აღვასრულებთ), წმიდათა და მართალთა მშობელთა ღვთისათა იოაკიმ და ანასითა და ყოველთა წმიდათა, შეგვიწყალნეს და გვაცხოვნეს ჩუენ, ვითარცა სათნო არს და კაცთმოყვარე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. უფალო შეგვიწყალენ გ-გზის."},{"t":"rubric","text":"დასრულების შემდეგ გაიღება აღსავლის კარი და მღვდელმთავარი გამოდის ამბიონზე გამოსახავს სამივე მხარეს ჯვარს."},{"t":"say","role":"choir","who":"გუნდი","text":"ისპოლა ეტი დესპოტა. მრავალჟამიერ."},{"t":"rubric","text":"აკურთხებს ხალხს, ემთხვევა შუა ხატს, მივა სტოაში წინასწარ გამზადებულ არწივზე, გამოსახავს ჯვარს პირით აღმოსავლეთით (საკურთხევლისაკენ)"},{"t":"say","role":"choir","who":"მგალობლები","text":"ისპოლა ეტი დესპოტა."},{"t":"rubric","text":"დაიხურება აღსავლის კარი და კრეტსაბმელი."}],"toc":[{"text":"დასაწყისი","i":0},{"text":"ექვსფსალმუნი","i":17},{"text":"ლოცვა ა","i":19},{"text":"ლოცვა ბ","i":21},{"text":"ლოცვა გ","i":23},{"text":"ლოცვა დ","i":25},{"text":"ლოცვა ე","i":27},{"text":"ლოცვა ვ","i":30},{"text":"ლოცვა ზ","i":32},{"text":"ლოცვა ჱ","i":35},{"text":"ლოცვა თ","i":37},{"text":"ლოცვა ი","i":39},{"text":"ლოცვა ია","i":41},{"text":"ლოცვა იბ","i":43},{"text":"ღმერთი უფალი","i":73},{"text":"პოლიელეი","i":101},{"text":"სახარების წინ","i":146},{"text":"სახარება","i":152},{"text":"აქებდითსა","i":239},{"text":"დიდება მაღალიანი","i":241}]},{"id":"liturgy","name":"ლიტურგია","subtitle":"წმიდისა იოანე ოქროპირისა","blocks":[{"t":"rubric","text":"დაირეკება სამეუფო ზარი."},{"t":"rubric","text":"შემოდის მღვდელმთავარი დასავლეთის კარით."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"დასავლეთის კართან ხვდება სინზე დასვენებული ჯვრით."},{"t":"rubric","text":"მაცხოვრის ხატის მხარეს I დიაკონი (სასაკმევლით) მის გვერდით II დიაკონი. (სანთლით) III დიაკონი (სანთლით) დგება I დიაკონის უკან."},{"t":"rubric","text":"სტოაში წინასწარ გამზადებულ არწივთან დგანან ორი სტიქაროსანი მანტიით, სტიქაროსანი კვერთხით (მღვდელმთავრისგან მარცხნივ) და ორი სტიქაროსანი რიპიდებით."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"სიბრძნით"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"უპატიოსნესსა ქერუბიმთასა და აღმატებით უზესშთაესსა სერაბიმთასა, განუხრწნელად მშობელსა სიტყვისა ღვთისასა, მხოლოსა ღვთისმშობელსა გალობით ვადიდებ-დეთ. (აღდგომიდან წარგზავნამდე: განათლდი განათლდი.)"},{"t":"rubric","text":"დიდება, აწდა და. უფალო შეგჳწყალენ (3 გზის), სახელითა უფლისათა მაღალყოვლადუსამღვდელოესო მეუფეო გვაკურთხენ."},{"t":"rubric","text":"მღვდელმთავარი სტოაში წინასწარ გამზადებულ არწივზე დადგება, ერთი სტიქაროსანი გამოართმევს კვერთხს (ყოველდღიური კვერთხი) და მიაწოდებს დიდ კვერთხს (მსახურების კვერთხი ორი გველით). ორი სტიქაროსანი მოაცმევს მანტიას, მღვდელი მღვდელმთავარს მიაწოდებს ჯვარს ლანგრით, ის ემთხვევა ჯვარს, ამთხვევიებს მღვდლებს და ბოლოს ისევ წინამძღვარს და ლანგარზე დაასვენებს."},{"t":"rubric","text":"დიაკონი წავლენ აღსავლის კარისკენ და გაჩერდებიან ამბიონთან. I დიაკონი კმევა კმევით მოდის უკან. (უკმევს ვიდრე არ ემთხვევა მეუფე ანალოღიაზე დასვენებულ ხატებს.) მღვდელმთავარს მოაცილებენ რიპიდები ამბიონამდე და დგანან ვიდრე არ დამთავრდება შემთხვევის ლოცვები."},{"t":"say","role":"deacon","who":"I დიაკონი კითხულობს შემთხვევის ლოცვებს","text":""},{"t":"say","role":"deacon","who":"დიაკონი","text":"გვაკურთხენ მაღალყოვლადუსამღვდელოესო მეუფეო."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"კურთხეულ არს ღმერთი ჩუჱნ, ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ამინ, დიდება შენდა ღმერთო ჩუჱნო დიდება შენდა. მეუფეო ზეცათაო... წმიდაო ღმერ-თო გ-გზის, დიდება-აწდა. ყოვლადწმიდაო სამებაო... უფალო შეგჳწყალენ გ-გზის. დიდება-აწდა, მამაო ჩუენო..."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"რამეთუ შენი არს..."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ამინ. მიწყალენ ჩუჱნ, უფალო, შეგჳწ-ყალენ ჩუჱნ, რამეთუ ყოველსავე სიტყვის-მიცე-მისაგან უღონო ვართ, გარნა ამას ვედრებასა შენ, მეუფისა სახიერისა, ცოდვილნი ესე შევს-წირავთ. მიწყალენ ჩუჱნ, უფალო შეგჳწყალენ ჩუჱნ."},{"t":"rubric","text":"დიდება მამასა და ძესა და წმიდასა სულსა."},{"t":"rubric","text":"უფალო, შეწგჳწყალენ ჩუჱნ, რამეთუ შენ გესავთ, ნუ განგჳრისხდები ჩუჱნ ფრიად, და ნუცა მოიხსენებ უსჯულოებათა ჩუჱნთა, არამედ მოიხილე ჩუჱნ ზედა წყალობით, ვითარცა სახიერ ხარ, და გჳხსენ ჩუჱნ სამართლად რისხვისაგან შენისა, რამეთუ შენ ხარ ღმერთი ჩუჱნი, და ჩუჱნ ვართ ერნი შენნი, ყოველნივე ქმნულნი ხელითა შენ-თანი ვართ და სახელი შენი წოდებულ არს ჩუჱნ ზედა, და შეგჳწყალენ ჩუჱნ."},{"t":"rubric","text":"აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"მოწყალების კარი განგვიღე, კურთხეულო ღმრ-თისმშობელო, რათა, რომელნი ესე შენ გესავთ, არა დავეცნეთ, არამედ განვერნეთ წინა-აღმ-დგომთა მტერთაგან, რამეთუ შენ ხარ ცხოვრება ნათესავისა ქრისტიანეთასა."},{"t":"rubric","text":"მღვდელმთავარი გადაცემს კვერთხ სტიქაროსანს და ემთხვევა მაცხოვრის ხატს"},{"t":"say","role":"deacon","who":"დიაკონი","text":"უხრწნელსა ხატსა შენსა თაყვანის ვცემთ ქველის-მოქმედ და ვითხოვთ შენდობასა ცოდვათა ჩუჱნთასა. ქრისტე ღმერთო, განზრა-ხვით სათნო-იყავ აღსვლა ხორცითა ჯვარსა ზედა, რათა იხსნე, რომელი შექმენ მონებისაგან მტერისა, ვინაცა მადლობით გიღაღადებთ: სიხარულით აღმავსენ ყოველნი, ვითარცა მაცხოვარმან ჩუჱნმან, მოსრულმან ცხოვრებად ყოვ-ლისა სოფლისა."},{"t":"rubric","text":"მღვდელმთავარი ემთხვევა ღვთისმშობლის ხატს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სახიერებისა წყარო ხარ შენ, წყალობასა შენსა ღირს მყვენ, ღვთისმშობელო, მო-ხედენ ერსა შეცოდებულსა, ყოვლად წმიდაო, და აჩუჱნე მარადის ძლიერება შენი, რამეთუ შენ გესავთ და გიხაროდენსა გიღაღადებთ, ვითარცა იგი ოდესმე უხორცოთა მთავარმან გაბრიელ გიღაღადა."},{"t":"rubric","text":"მღვდელმთავარი ემთხვევა მიძინების ხატს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შობასა ქალწულებაჲ დაიმარხე და მიცვალებასა სოფელი არა დაუტევე, ღმრთის-მშობელო, მიხუედ ცხორებად დედა ეგე ცხოვ-რებისა, და აწ მეოხებითა შენითა იჴსნი სიკუდი-ლისაგან სულთა ჩუჱნთა."},{"t":"rubric","text":"მღვდელმთავარი ემთხვევა იოანე ნათლისმცემლის ხატს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"წინა-მორბედო და ნათლის-მცემელო იოანე, უდაბნოსა მოქალაქეო, რომელსა გესმა საღმრთო იგი ჴმა მამისა, რომელი ღირს-იქმენ ძისა და უფლისა ნათლის-ცემად და იქმენ მხილველ სულისა წმიდისა, და ყოველთა გვიქადაგე ნათლისღება სინანულისა, ჩუჱნ ცოდვილთაცა მეოხ-გვეყავ, რათა ლოცვითა შენითა მოვიღოთ შენდობა ცოდვათა."},{"t":"rubric","text":"მღვდელმთავარი დადგება აღსავლის კარში"},{"t":"say","role":"deacon","who":"დიაკონი","text":"უფალო გარდამოავლინე ხელი შენი მაღლით სამკვიდრებელით შენით, და განმა-ძლიერე მე მსახურებასა ამას შენსა ზედა, დაუსჯელად წარდგომად წინაშე საშინელსა საკურთხეველსა შენსა, და შეწირვად შენდა უსისხლო იგი მსხვერპლი, რამეთუ შენი არს ძალი, უკუნითი უკუნისამდე.ამინ."},{"t":"rubric","text":"მღვდელმთავარი მობრუნდება დასავლეთით დაიჭერს კვერთხს დასახავს ჯვარს და გაემართება შუა ტაძარში მაღალდასაჯდომელთან."},{"t":"say","role":"choir","who":"გუნდი","text":"ტონ დესპოტი"},{"t":"rubric","text":"რიპიდები შედიან საკურთხეველში."},{"t":"rubric","text":"I დიაკონი დგება კანკელის მაცხოვრის ხატთან პირისახით მღვდელმთავრისაკენ (დასავლეთით)."},{"t":"rubric","text":"II დიაკონი ღვთისმშობლის კანკელის ხატთან (სასაკმევლით) პირისახით მღვდელმთავრისაკენ (დასავლეთით)."},{"t":"rubric","text":"III დიაკონი სამხრეთის კარით შედის საკურთხეველში შესამოსელი გამოაქვს აღსავლის კარით და მიდის მღვდელმთავრთან."},{"t":"rubric","text":"როდესაც მღვდელმთავრი ანაფორას განიმოსავს:"},{"t":"say","role":"deacon","who":"II დიაკონი","text":"უფლისა მიმართ ვილოცოთ, უფალო შეგჳწყალენ."},{"t":"rubric","text":"და აკმევს ვიდრე შემოსვა სრულად არ დასრულდება"},{"t":"say","role":"deacon","who":"I დიაკონი იტყვის","text":""},{"t":"rubric","text":"სტიქარი:"},{"t":"rubric","text":"იხარებს სული შენი უფლისა მიმართ, რომელმან შთაგაცვა შენ სამოსელი ცხოვრებისა და კუარ-თი სიხარულისა შეგმოსა შენ; ვითარცა სიძესა დაგადგა გვირგვინი და, ვითარცა სძალი, სამ-კაულითა შეგამკო შენ."},{"t":"rubric","text":"ოლარი:"},{"t":"rubric","text":"კურთხეულ არს ღმერთი, რომელი გარდამოავლენს მადლსა თჳსსა მღვდელთმთავართა თჳსსა ზედა, ვითარცა ნელსაცხებელსა თავსა ზედა, გარდამომავალსა წუერთა ზედა, წუ-ერთა ზედა აარონისათა, რომელი გარდამოვალნ სამხართა ზედა სამოსლისა მისისათა."},{"t":"rubric","text":"სარტყელი:"},{"t":"rubric","text":"კურთხეულ არს ღმერთი, რომელმან გარეშე-გარტყა შენ ძალი და დასდვა უბიწოდ გზაჲ შენი, განამტკიცნა ფერხნი შენნი, ვითარცა ირემთანი, და მაღალთა ზედა დაგადგინა შენ."},{"t":"rubric","text":"მარჯვენა სამკლავე:"},{"t":"rubric","text":"მარჯვენე შენი, უფალო, დიდებულ არს ძალითა, მარჯვენემან ხელმან შენმან, უფალო, მოსრნა მტერნი და სიმრავლითა დიდებისა შენისათა შე-მუსრნა მხდომნი იგი."},{"t":"rubric","text":"მარცხენა სამკლავე:"},{"t":"rubric","text":"ხელთა უფლისათა შეგქმნეს შენ და დაგბადეს შენ, გულის-ჴმა გიყუეს შენ და გასწავეს მცნე-ბანი მისნი."},{"t":"rubric","text":"ენქერი:"},{"t":"rubric","text":"შეიბ მახვილი შენი წელთა შენთა, ძლიერო, შუენიერებითა შენითა და სიკეთითა შენითა, და გარდააცუ და წარემართე, და სუფევდი ჭეშმარიტებისათჳს, და სიმშჳდისა და სიმართლისა, და გიძღოდის შენ საკჳრველად მარჯუენე შენი, ყოვლადვე, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"ბისონი:"},{"t":"rubric","text":"მღვდელთ-მთავართა შენთა, უფალო, შეიმოსონ სიმართლე და წმიდანი შენნი სიხარულით იხარე-ბდენ, ყოვლადვე, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"ამ დროს გამოდის წინამძღვარი მიტრით და ჯვარ-პანაღიით აღსავლის კარით, ხოლო სტიქაროსნები დიკირ-ტრიკირით გვერდითა კარით."},{"t":"rubric","text":"ომოფორი:"},{"t":"rubric","text":"მხართა ზედა, ქრისტე, შეცთომილი კაცობრივი ბუნებაჲ აღიხვენ, ამაღლდი და მიჰგვარე ღმე-რთსა და მამასა, ყოვლადვე, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"ჯვარი:"},{"t":"rubric","text":"უკუეთუ ვისმე უნებს შემოდგომად ჩემდა, უარ-ჰყოს თავი თჳსი, სთქვა უფალმან, და აღიღოს ჯუარი თჳსი და შემომიდგეს მე, ყოვლადვე, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"პანაღია:"},{"t":"rubric","text":"გული წმიდაჲ დაჰბადოს შენთანა ღმერთმან და სული წრფელი განგიახლოს გუამსა შენსა, ყოვ-ლადვე, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"მიტრა:"},{"t":"rubric","text":"დაგადგა უფალმან თავსა შენსა გვირგვინი ქვისა მისგან პატიოსნისა, ცხოვრებაჲ სთხოვე მას, და მოგცეს შენ განგრძობაჲ დღეთა, ყოვ-ლადვე, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"მღვდელმთავარს დიკირ-ტრიკირი მიაწოდებენ სტიქაროსნები."},{"t":"rubric","text":"დიკირ-ტრიკირის მიწოდებისას:"},{"t":"rubric","text":"ესრეთ ბრწყინევდინ ნათელი შენი წინაშე კაცთა, რათა იხილნენ საქმენი შენნი კეთილნი და ადიდებდენ მამასა შენსა ზეცათასა, ყოვლადვე, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"მღვდელმთავარი ოთხივე მხარეს დასახავს ჯვარს. ამ დროს სამღვდელოება გამოდის აღსავლის კარით."},{"t":"say","role":"choir","who":"მგალობლები","text":"ტონ დესპოტინ კი ერხი აიმონ კირიე პილატე, ისპოლა ელტი დესპოტა, ისპოლა ელტი დესპოტა, ისპოლა ელტი დესპოტა."},{"t":"rubric","text":"სტიქაროსნები დიკირ-ტრიკირით წამოვლენ ამბიონისკენ, დიაკვნებთან ერთად თავს დაუხრიან მღვდელმთავარს და შედიან საკურთხეველში, ხოლო დიაკვნები დგებიან სამღვდელოებასთან ერთად შუა ტაძარში."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მეუფეო ზეცათაო, ნუგეშინისმცემელო, სულო ჭეშმარიტებისაო, რომელი ყოვე-ლგან ხარ და ყოველსავე აღავსებ მადლითა შენითა, საუნჯეო კეთილთაო, მომნიჭებელო ცხოვ-რებისაო, მოვედ და დაემკვიდრე ჩუჱნ შორის და წმიდა მყვენ ჩუჱნ ყოვლისაგან ბიწისა და აცხოვნენ, სახიერო, სულნი ჩუჱნნი."},{"t":"rubric","text":"დიდება მაღალთა შინა ღმერთსა, და ქვეყანასა ზედა მშვიდობა და კაცთა შორის სათნოება."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"უფალო ბაგენი ჩემნი აღახვენ და პირი ჩემი უთხრობდეს ქებულებასა შენსა"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"დიდება მაღალთა შინა ღმე-რთსა, და ქვეყანასა ზედა მშვიდობა და კაცთა შორის სათნოება."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"უფალო ბაგენი ჩემნი აღახვენ და პირი ჩემი უთხრობდეს ქებულებასა შენსა"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"დიდება მაღალთა შინა ღმერ-თსა, და ქვეყანასა ზედა მშვიდობა და კაცთა შორის სათნოება."},{"t":"say","role":"deacon","who":"III დიაკონი","text":"ჟამი არს მსახურებად უფლისა მა-ღალყოვლადუსამღვდელოესო მეუფეო გვაკუ-რთხენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"კურთხეულს არს ღმერთი ჩუჱნ ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"ამინ. ლოცვა ჰყავ ჩუენთვის მაღალყოვლადუსამღვდელოესო მეუფეო."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"წარგიმართოს უფალმან სლ-ვანი შენნი."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მოგვიხსენე ჩუენ მაღალყოვლადუსამღვდელოესო მეუფეო"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მოგიხსენოს შენ უფალმან ღმე-რთმან სასუფეველსა თვისსა ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"ამინ."},{"t":"rubric","text":"წინამძღვარი და დიაკვვნები აიღებენ კურთხევას მღვდელმთავარისაგან, წინამძღვარი სამხრეთის კარით შედის საკურთხეველში ხოლო I დიაკონი დგება მაცხოვრის ხატის წინ."},{"t":"rubric","text":"წინამძღვარი და დიაკონთან ერთად დაუხრიან თავს მღვდელმთავარს."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"გვაკურთხენ მაღალყოვლადუსამღ-ვდელო-ესო მეუფეო."},{"t":"rubric","text":"მხედველი მღვდელმთავრისაკენ."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"კურთხეულ არს მეუფება, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"rubric","text":"სახარებით ტრაპეზზე გამოსახავს ჯვარს."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ზეგარდამო მშჳდობისა და ცხოვრე-ბისათჳს სულთა ჩუჱნთასა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მშჳდობისათჳს ყოვლისა სოფლისა, კეთილად დგომისათჳს წმიდათა ღმრთისა ეკლესიათა და ყოველთა ერთობისათჳს, უფლისა მი-მართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"წმიდისა ამის ტაძრისათჳს, სარწმუნო-ებითა, სასოებითა და შიშითა ღმრთისათა შემავალთა ამას შინა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"უწმიდესისა და უნეტარესისა, სრულიად საქართველოს კათოლიკოს-პატრიარქისა და მცხეთა-თბილისის მთავარეპისკოპოსისა, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტისა დიდისა მეუფისა მამისა ჩუჱნისა ი ლ ი ა ს ა თ ჳ ს, და სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრისა მაღალყოვლადუსამღვდელო-ესისა სენაკისა და ჩხოროწყუს მიტროპოლიტისა შიოსათჳს, და მაღალყოვლადუსამღვდელოესისა ქუთათელ-გაენათელი მიტროპოლიტისა იოანესათჳს, პატიოსანთა მღვდელთა, ქრისტეს მიერ დიაკონთა და ყოვლისა სამღვდელოჲსა დასისა და ერისა მათისათჳს, უფლისა მიმართ ვილოცოთ."},{"t":"rubric","text":"სტიქაროსნები გამოდიან ხელბანვაზე (წყალის ჭურჭელი გადის სამკვეთლოს მხრიდან). ადგილობრივი მღვდელმთავრის მოხსენიებაზე წინამძღვარი, დიაკვნები, სტიქაროსნები შებრუნდებიან მისკენ და დაუხრიან თავს. სტიქაროსნები ასრულებენ ხელბანვას, II დიაკონი უკითხავს ხელბანვის ლოცვას."},{"t":"rubric","text":"ხელბანის ლოცვა:"},{"t":"prayer","text":"დავიბანე უბრალოებით ხელნი ჩემნი, და გარე მოვადეგ საკურთხეველსა შენსა უფალო, სმენად ჩემდა ჴმა ქე-ბისა შენისა, და მითხრობად ყოველი საკვირველება შენი, უფალო შევი-ყვარე შვენიერებაჲ სახლისა შენისა, და ადგილი საყოფელი დიდებისა შენისა, ნუ წარწყმედ უღმრთოთა თანა სულსა ჩემსა, და კაცთა მოსისხლეთა თანა ცხოვრებასა ჩემსა, რომელთა ჴელნი მათნი უსჯულოებასა შინა არიან, და მარჯვენე მათი აღივსო ქრთამითა, ხო-ლო მე უმანკოებითა ჩემითა ვიდოდე, მიჴსენ მე უფალო და მიწყალე მე, ფერჴი ჩემი დასდგა სიწრფოებით ეკლესიასა შინა გაკურთხო შენ უფალო."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ღვთივდაცულისა ერისა ჩუჱნისა, მთავრობისა და მხედრობისა მათისათჳს, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"თანა-მბრძოლთათჳს და დამორჩილებისა ქვეშე ფერხთა მათთა ყოველთა მტერთა და მბრძოლთა უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სამეუფოისა ქალაქისა ამის ჩუჱნისა, და ყოვლისა ქალაქებისა და სოფლებისა, და სარწმუნოებით მკჳდრთა მათ შინა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"კეთილ-შეზავებისათჳს ჰაერთასა, კეთი-ლგამოღებისათჳს ნაყოფთა ქუჱყანისათა და ჟამთა მშჳდობისათჳს, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მენავეთა, მოგზაურთა, მშრომელთა, ტყვეთა ჴსნისა და ცხოვრებისა მათისათჳს, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ჴსნად ჩუჱნდა ყოვლისაგან ჭირისა, რის-ხჳსა და იწროებისა, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგჳწყალენ და დაგვიცუჱნ ჩუჱნ, ღმერთო, შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლად-წმიდისა, უხრწნელისა, უფრო-სად კურთხეულისა, დიდებულისა დედოფლისა ჩუჱნისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თჳსნი და ურთიერთარს და ყო-ველი ცხოვრება ჩუჱნი ქრისტესა ღმერთსა ჩუჱ-ნსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ, უფალო."},{"t":"rubric","text":"პირველი ანტიფონის საიდუმლო ლოცვა:"},{"t":"prayer","text":"უფალო ღმერთო ჩუჱნო, რომლისა სიმტკიცე განუზომელ, და დიდება მიუწვთომელ, რომლისა წყალობა აურა-ცხელ, და კაცმოყვარება მიუთხრობელ არს, შენ მეუფეო, მოწყალებისაებრ შენისა, მოიხილე ჩუჱნ ზედა, და წმი-დასა ამას სახლსა ზედა, და ჰყვენ ჩუჱნთანა და თანა მლოცველთა ჩუჱნ-თა თანა, მდიდრად წყალობანი და მოწ-ყალებანი შენნი:"},{"t":"say","role":"priest","who":"წინამძღვარი","text":"რამეთუ შვენის შენდა ყოველი დიდება, პატივი და თაყვანისცემა, მამისა და ძი-სა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ"},{"t":"rubric","text":"ასამაღლებელის ბოლოს წინამძღვარი აღსავლის კარიდან, I დიაკონი ადგილიდან და სტიქაროსნები ამბიონიდან ერთად ლოცვა-კურთხევას მღვდელმთავრისაგან. I დიაკონი და სტიქაროსნები შედიიან საკურთხეველში."},{"t":"say","role":"choir","who":"გუნდი","text":"პირველი აღსავალი"},{"t":"rubric","text":"II მღვდელი მივა მეუფესთან და აიღებს კურთხევას (ემთხვეა ხელზე) და წამოვა საკურთხეველში (ჩრდილოეთ და სამხრეთ კარებით) მას უკან გაჰყვებიან II -III დიაკონი (ამ შემთხევაში ხელზე სამთხვევად აღარ მიდიან.) II დიაკონი დადგება მაცხოვრის ხატთან III დიაკონი ღვთისმშობლის ხატთან."},{"t":"rubric","text":"II დიაკონი იტყვის კვერექს"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგჳწყალენ და დაგვიცუჱნ ჩუჱნ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლადწმიდისა, უხრწნელისა, უფრო-სად კურთხეულისა, დიდებულისა დედოფლისა ჩუჱნისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩუჱნი, ქრისტესა ღმერთსა ჩუჱნსა შევვედროთ"},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო"},{"t":"rubric","text":"მეორე ანტიფონის საიდუმლო ლოცვა"},{"t":"prayer","text":"უფალო ღმერთო ჩუჱნო, აცხოვნე ერი შენი, და აკურთხე სამკვიდრებელი შე-ნი, სავსება ეკლესიისა შენისა დაი-ცევ, წმიდა-ჰყვენ მოყვარენი სახლისა შენისა შვენიერებისანი, შენ იგი ნაცვ-ლად ადიდენ ღუთაებრივითა ძალითა შენითა და ნუ დამიტევებ ჩუჱნ მოსავთა შენდამი:"},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ შენი არს სიმტკიცე და შენი არს სუფევა და ძალი და დიდება, მამისა და ძისა და წმიდისა სულისა აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"choir","who":"გუნდი","text":"მეორე აღსავალი"},{"t":"rubric","text":"III დიაკონი იტყვის კვერექს"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგჳწყალენ და დაგვიცუჱნ ჩუჱნ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლადწმიდისა, უხრწნელისა, უფრო-სად კურთხეულისა, დიდებულისა დედოფლისა ჩუჱნისა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი და ურთიერთარს და ყო-ველი ცხოვრება ჩუჱნი, ქრისტესა ღმერთსა ჩუჱნსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო"},{"t":"rubric","text":"III ანტიფონის საიდუმლო ლოცვა"},{"t":"prayer","text":"ზიართა ამათ, ერთ ჴმობითა ლოცვათა ჩუჱნდა მომნიჭებელო, და ორთა და სა-მთა შეთქმულთა სახელითა შენითა, თხოვათა აღსრულებისა აღმთქმელო: შენ აწცა მონათა შენთა თხოვანი უმ-ჯობესისა მიმართ სრულ-ჰყვენ, აწინდელსაცა ამას საუკუნესა მეცნი-ერებასა ჭეშმარიტებისა შენისასა მომ-ცემელმან, ხოლო მერმისა ცხოვრებისა ჩუჱნსა მომნიჭებელმან ჩუჱნდა:"},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ სახიერი და კაცთმოყვარე ღმერთი ხარ და შენდა დიდებასა აღვავლენთ, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"ასამაღლებელზე II და III დიაკონი თავს დაუხრის ეპისკოპოსს და შედიან საკურთხეველში. სტიქაროსანები კვერთხს და წიგნს შეიტანენ საკურთხეველში."},{"t":"say","role":"choir","who":"გუნდი","text":"მესამე აღსავალი."},{"t":"rubric","text":"მესამე აღსავლის დიდების მუხლზე წინამძღვარი და I დიაკონი ემთხვევიან ტრაპეზს და აღსავლის კარიდან თავს დაუკრავენ მეუფეს, წინამძღვარი I დიაკონს მიაწვდის სახარებას."},{"t":"rubric","text":"გამოსვლა ხდება შემდეგი თანმიმდევრობით: კვერთხი, რიპიდი, ტრიკირი, II დიაკონი სასაკმევლით, უკან მიყვება I დიაკონი სახარებით, დიკირი, რიპიდი და მხოლოდ შემდეგ წინამძღვარი და სამღვდელოება. მაღალდასაჯდომელის გავლით ჩრდილოეთ კარიდან ხდება გამოსვლა, ამბიონიდან მეუფეს შემოუვლიან და დადგებიან."},{"t":"rubric","text":"კვერთხი მიდის ამბიონზე, ტრიკირი და I რიპიდი მეუფისაგან მარჯვნივ დგება, II რიპიდი და დიკირი მარცხნივ."},{"t":"rubric","text":"I დიაკონი მეუფის მარჯვნივ რომ მოექცევა, სახარებას გადაიტანს მარცხენა ხელზე მარჯვენაში დაიჭერს გინგილას და მიმართავს მეუფეს (გინგილას გაიშვერს აღსავლის კარისკენ)."},{"t":"say","role":"deacon","who":"დიაკონი","text":"უფლისა მიმართ ვილოცოთ, უფალო შეგ-ჳწყალენ. (ჩუმად)"},{"t":"rubric","text":"ლოცვა გამოსვლისა"},{"t":"prayer","text":"მეუფეო უფალო ღმერთო ჩუჱნო, რომელმან დააწესენ ცათა შინა განწყო-ბილნი მჴედრობანი ანგელოსთანი და მთავარ-ანგელოსთანი, მსახურებად დიდებისა შენისა, ჰყავ შესლვასა ჩუ-ჱნსა თანა წმიდათაცა ანგელოსთა შე-სლვა, თანა მწირველად ჩუჱნდა, და თანა დიდების-მეტყველებად შენისა სა-ხიერებისა:"},{"t":"prayer","text":"რამეთუ შვენის შენდა ყოველი დიდება, პატივი და თაყვანის-ცემა, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე, ამინ."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აკურთხე მაღალყოვლადუსამღვდელოესო მეუფეო წმიდა შესავალი."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"კურთხეულ არს შესავალი წმიდათა შენთა, ყოვლადვე, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"rubric","text":"აკურთხებს შესავალს და ემთხვევა სახარებას."},{"t":"rubric","text":"I დიაკონი წამოვა და დადგება აღსავლის კარის წინ."},{"t":"rubric","text":"II დიაკონი საცეცხლურით მიუძღვის კმევით სახარებას (აღსავლის კარში არც აამაღლებთ და არც ჯვარს გამოვსახავთ მხოლოდ კმევით შევა) პირდაპირ უკმევს ტრაპეზს გ-გზის წინა მხრიდან, მაღალდასაჯდომელს გ-გზის და შემდეგ სახარებას გ-გზის, რომელიც უპყრია I დიაკონს."},{"t":"rubric","text":"აწდას მუხლის დასრულების შემდეგ I დიაკონი აამაღლებს სახარებას გამოსახავს ჯვარს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სიბრძნით აღემართენით."},{"t":"rubric","text":"შევა საკურთხეველში, ტრაპეზზე დაასვენებს სახარებას შემდეგ ემთხვევა სახარებას და ტრაპეზს და თავს დაუკრავს მღვდემთავარს. სტიქაროსნები მიაწოდებენ ეპისკოპოსს დიკირ ტრიკირს."},{"t":"say","role":"choir","who":"გუნდი","text":"მოვედით თაყვანისვცეთ..."},{"t":"rubric","text":"ეპისკოპოსი მიბრძანდება ამბიონზე გამოსახავს მრევლს სამივე მხარეს დიკირ-ტრიკირით ჯვარს, შევა აღსავლით კარით საკურთხეველში (I დიაკონი მიაწოდებეს მღვდელმთავარს საცეცხლურს), ეპისკოპოსი დიკირით და საცეცხლურით დიაკონი ტრიკირით შეასრულებენ საკურთხევლის, კანკელის და ხალხის კმევას. შემოვა ეპისკოპოსი საკურთხეველში ემთხევა სახარებასა და წმიდა ტრაპეზს."},{"t":"say","role":"choir","who":"გუნდი","text":"ისპოლა ელტი დესპოტა(გრძელი); ტროპარ-კონდაკს წმინდის."},{"t":"rubric","text":"ლოცვა საწმიდაოს ქებისა"},{"t":"prayer","text":"ღმერთო წმიდაო, რომელი წმიდათა ში-ნა განისვენებ, რომელი სამწმიდითა ჴმითა სერაფიმთა მიერ იგალობები, და ქერუბიმთა მიერ იდიდებისმეტყველები, და ყოველთაგან ზეცისა ძალთა თაყ-ვანის-იცემები, რომელმან არა არსისაგან არსად მოიყვანენ ყოველნი, რომელმან დაბადე კაცი ხატად და მსგავ-სად შენდა, ყოვლითავე მადლითა შენი-თა შეამკევ, და მისცემ მვედრებელთა სიბრძნესა და გულის ხმის ყოფასა, და არა შეურაცხ-ჰყოფ ცოდვილთა, არამედ განუწესებ სინანულსა საცხოვ-რებელად, რომელმან ღირს მყვენ ჩუჱნ მდაბალნი, და უღირსნი მონანი შენნი, ჟამსაცა ამას დგომად წინაშე დიდებისა წმიდისა საკურთხეველისა შენისა, და თანამდებისა თაყვანის-ცემისა, და დიდების-მეტყველებისა შეწირვად შენ-და, შენ მეუფეო შეიწირე პირთაგანცა ჩუჱნ ცოდვილთასა სამ წმიდაჲ გალობაჲ, და მომხედენ ჩუჱნ სიტკ-ბოებითა შენითა, მოგვიტევენ ჩუჱნ ყოველნი შეცოდებანი ჩუჱნნი, ნებსითნი და უნებლიეთნი, წმიდა ჰყვნენ ჩუჱნნი სულნი და ჴორცნი, და მომეც ჩუჱნ ღირ-სებით მსახურებაჲ შენი ყოველთა დღეთა ცხოვრებისა ჩუჱნისათა, მეოხებითა ყოვლად წმიდისა ღვთის-მშობელისათა, და ყოველთა წმიდათა საუ-კუნითგან სათნო ყოფილთა შენთათა: რამეთუ წმიდა ხარ, ღმერთო ჩუ-ჱნო, და შენდა დიდებასა აღვავლენთ, მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აკურთხე მაღალყოვლადუსამღვდელო-ესო მეუფეო ჟამი სამწმიდაოსი."},{"t":"rubric","text":"ეპისკოპოსი დასახავს ჯვარს, დიაკონი ემთხვევა მის მარჯვენას. გავა აღსავლის კარით და დადგება მაცხოვრის ხატთან."},{"t":"rubric","text":"ტროპარების დასრულების შემდეგ."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"უფალო აცხოვნე კეთილმსახური და ისმინე ჩუენი."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო აცხოვნე კეთილმსახური და ისმინე ჩუენი."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ღვთივდაცული ერი ჩუჱნი და მეუფება მისი, მრავალჟამიერ."},{"t":"say","role":"choir","who":"გუნდი","text":"ღვთივდაცული ერი ჩუჱნ და მეუფება მისი, მრავალჟამიერ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"უწმიდესი და უნეტარესი, სრულიად სა-ქართველოს კათოლიკოს პატრიარქი და მცხეთა-თბილისის მთავარეპისკოპოსი, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტი, დიდი მეუფე, მა-მაჲ ჩუჱნ ილია, მრავალჟამიერ."},{"t":"say","role":"choir","who":"გუნდი","text":"უწმიდესი და უნეტარესი, სრულიად სა-ქართველოს კათოლიკოს პატრიარქი და მცხეთა-თბილისის მთავარეპისკოპოსი, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტი, დიდი მეუფე, მა-მაჲ ჩუჱნ ილია, მრავალჟამიერ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრე, მაღალყოვლადუსამღვდელოესი, სენაკისა და ჩხოროწყუს მიტროპოლიტი შიო, მრავალჟამიერ."},{"t":"say","role":"choir","who":"გუნდი","text":"სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრე, მაღალყოვლადუსამღვდელოესი, სენაკისა და ჩხოროწყუს მიტროპოლიტი შიო, მრავალჟამიერ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლადსამღვდელონი მიტროპოლიტნი, მთავარეპისკოპოსნი და ეპისკოპოსნი, და მაღალ-ყოვლადუსამღვდელოესი ქუთათელ-გაენათელი მიტროპოლიტი იოანე, მრავალჟამიერ."},{"t":"say","role":"choir","who":"გუნდი","text":"ყოვლადსამღვდელონი მიტროპოლიტნი, მთავარეპისკოპოსნი და ეპისკოპოსნი, და მაღალ-ყოვლადუსამღვდელოესი ქუთათელ-გაენათელი მიტროპოლიტი იოანე, მრავალჟამიერ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"კეთილმორწმუნენი, ნაყოფის შემომწირველნი და კეთილისმყოფელნი წმიდისა და ყოვლადპატიოსნისა ამის ტაძრისა, და ამას შინა მშრომელნი, მგალობელნი, აქა მდგომარენი და ყოველნი მართლმადიდებელნი ქრისტეანენი, მრა-ვალჟამიერ."},{"t":"say","role":"choir","who":"გუნდი","text":"კეთილმორწმუნენი, ნაყოფის შემომწირველნი და კეთილისმყოფელნი წმიდისა და ყოვლადპატიოსნისა ამის ტაძრისა, და ამას შინა მშრომელნი, მგალობელნი, აქა მდგომარენი და ყოველნი მართლმადიდებელნი ქრისტეანენი, მრა-ვალჟამიერ."},{"t":"rubric","text":"ბოლო მუხლზე II დიაკონი გადააფარებს სახარებას გადასაფარაბელს."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"უფლისა მიმართ ვილოცოთ."},{"t":"rubric","text":"დიაკონი აღსავლის კართან პირით აღმოსავლეთით."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"რამეთუ წმიდა ხარ შენ ღმერ-თო ჩუჱნო და შენდა დიდებასა აღვავლენთ მა-მისა და ძისა და წმიდისა სულისა, აწ და მარადის."},{"t":"rubric","text":"სტიქაროსანი აწვდის ეპისკოპოსს დიკირს."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"და უკუნითი უკუნისამდე."},{"t":"rubric","text":"გაწვდილი გინგილით შემობრუნდება საათის ისრის მიმართულებით და შედის საკურთხეველში, ემთხვევა ტრაპეზს და მეუფის მარჯვნივ დგება."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. წმიდაო ღმერთო. გ-გზის."},{"t":"rubric","text":"ეპისკოპოსი ყოველმუხლზე სახარებაზე სახავს ჯვარს დიკირით, ბოლო წმიდაო ღმერთოზე წინამძღვარი მიაწოდებს მარცხნიდან ჯვარს ეპისკოპოსს. მეუფე დიდების მუხლზე გადის აღსავლით ამბიონზე მარჯვენა ხელში დიკირი უჭირავს მარცხენაში ჯვარი. დიაკონი აიღებს გადასაფარებელს სახარებიდან."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"უფალო, უფალო, გარდამოიხილე ზეცით ღმერთო იხილე და მოხედე ვენახსა ამას და განამტკიცე ესე რომელ დაასხა მარჯვენემან შენმან."},{"t":"rubric","text":"სამივე მხარეს სახავს ჯვარს."},{"t":"say","role":"choir","who":"გუნდი","text":"წმიდაო ღმერთო. გ-გზის"},{"t":"rubric","text":"ეპისკოპოსი შედის საკურთხეველში დიკირით გამოსახავს ჯვარს აღსავლის კარში."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"ბრძანე მაღალყოვლადუსამღვდელო-ესო მეუფეო."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"კურთხეულ არს მომავალი სა-ხელითა უფლისათა."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აკურთხე მაღალყოვლადუსამღვდელო-ესო მეუფეო მაღალდასაჯდომელი."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"კურთხეულ ხარ საყდართა ზედა დიდებისა მეუფებისა შენისათა, მჯდომარე ქერუბიმთა ზედა, ყოვლადვე, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"ამინ."},{"t":"prayer","text":"სამებისა გამოცხადებაჲ იორდანესა იქმნა თჳთ უკუჱ ყოვლად-საღმრთომან ბუნებამან, მამამან, ხმა-ჰყო: ესე ნა-თელღებული ძე ჩემი არს საყვარელი, ხოლო სული მოვიდა მსგავსისა მი-მართ. რომელსა აკურთხევენ ერნი და აღამაღლებენ უკუნისამდე. ამინ"},{"t":"rubric","text":"ეპისკოპოსი განიმოსავს დიდ ომოფორს. სტიქაროსანი მაღალდასაჯდომელზე მიაწოდებს ტრიკირს, მეუფე გამოსახავს ჯვარს, ეპისკოპოსი სამოციქულოს და სახარებას ისმენს მაღალდასაჯდომელზე."},{"t":"rubric","text":"I დიაკონი აკურთხებინებს მეუფეს სასაკმევლეს (საკმეველს დაასხამს მეუფე): აკურთხე მაღალყოვლადუსამღვდელოესო მეუფეო სასაკმევლე ესე."},{"t":"rubric","text":"II დიაკონი აკურთხებინებს სამოციქულოს. მეუფე მაკურთხეველ ხელს სამოციქულოზე დადებს და II დიაკონი ემთხვევა ხელზე და გამოდის აღსავლის კარით და დგება ანალოღიის ხატის წინ. I დიაკონი დგება აღსავლის კართან ტრაპეზის წინ."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მოხედენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობა ყოველთა."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"და სულისაცა შენისათანა."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"სიბრძნით."},{"t":"rubric","text":"იკმევა საკურთხეველი, კანკელი, მღვდელმთავარი და სამღვდელოება და შემდეგ მრევლი."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"წარდგომა, ფსალმუნი დავითისი... (კითხულობს წარდგომას)"},{"t":"say","role":"choir","who":"გუნდი","text":"იმეორებს წესისაებრ"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"სიბრძნით"},{"t":"say","role":"deacon","who":"II დიაკონი","text":"ასახელებს სამოციქულოს"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მოხედენ"},{"t":"rubric","text":"II დიაკონი კითხულობს სამოციქულოს"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობა შენდა."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"და სულისაცა შენისა თანა"},{"t":"say","role":"deacon","who":"II დიაკონი","text":"ალილუია ხმა (რომელ ხმაზეც არის)"},{"t":"say","role":"choir","who":"გუნდი","text":"ალილუია, ალილუია, ალილუია."},{"t":"rubric","text":"ლოცვა სახარების კითხვის წინ:"},{"t":"prayer","text":"გამოაბრწყინვე გულთა შინა ჩუჱნთა, კაცთმოყვარეო მეუფეო, ღვთის-მეც-ნიერებისა ნათელი მიუწვდომელი, და გონებისა ჩუჱნსა თვალნი განახვენ, განცდად სახარებისა შენისა ქადაგე-ბათა, და დასდევ ჩუჱნ ზედა ნეტართა მათ მცნებათა შენთა შიში, რათა ყო-ველი ჴორციელი გულის-თქმაჲ დავს-თრგუნოთ, და ყოველი სულიერი მოქა-ლაქობაჲ მოვიგოთ, და ყოველსავე სათნოდ შენდა ვზრახვიდეთ, და ვიქ-მოდეთ."},{"t":"prayer","text":"რამეთუ შენ ხარ განმანათლებელი სულთა და ჴორცთა ჩუჱნთა ქრისტე ღმერთო ჩუჱნო, და შენდა დიდებასა აღვავლენთ, თანა დაუსაბამოთ მამით შენით, და ყოვლად წმიდით და სახიე-რით, და ცხოველს მყოფელით სულით შენით, აწ და მარადის, და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"სამოციქულოს რომ დაასრულებს II დიაკონი, სტიქაროსნები აანთებენ დიკირ-ტრიკირს, გაამზადებენ რიპიდებს და სახარებას დაელოდებიან ამბიონზე."},{"t":"rubric","text":"წინამძღვარი და I დიაკონი ემთხვევიან ტრაპეზს (წინამძღვარი სახარებას და ტრაპეზს) წინამძღვარი მიაწვდის I დიაკონს სახარებას."},{"t":"rubric","text":"I დიაკონი მიაბრძანებს სახარებას მეუფესთან, მეუფე ემთხვევა სახარებას, დიაკონი გამოაბრძანებს სახარებას აღსავლის კარით (ტრაპეზის მარცხენა მხრიდან სამკვეთლოს მხრიდან) დადგება ანალოღიის ხატების წინ. მისგან მარჯვნივ დადგება ტრიკირი, მარცხნივ დიკირი და რიპიდები დადგებიან დიკირ-ტრიკირის წინ."},{"t":"rubric","text":"სახარების წინ მიდის III დიაკონი სინზე დადებული ომოფორით, აღსავლის კარით გარს შემოუვლის II დიაკონს, რომელიც ალილუიას მუხლებს კითხულობს, დაელოდება დასრულებას და წავლენ წინ III დიაკონი უკან II დიაკონი, ისევ აღსავლის კარით დაბრუნდებიან საკურთხეველში, სამოციქულო მარცხნივ (სამკვეთლოს მხარეს), ომოფორი მარჯვნივ (სადიაკვნეს მხარეს) შედიან და დადგებიან მეუფესთან რომელიც მაღალდასაჯდომელთან დგას. II დიაკონი ელოდება I დიაკონისა და მეუფეს დიალოგის დასრულებას."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აკურთხე მაღალყოვლადუსამღვდელოესო მეუფეო სიტყვანი კეთილმაუწყებელისა წმიდისა, დიდებულისა და ყოვლადქებულისა მო-ციქულისა და მახარებელისა (სახელი)."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ღმერთმან, ვედრებითა წმიდისა, დიდებულისა და ყოვლადქებულისა მოციქულისა და მახარებელისა (სახელი), გცეს შენ სიტყვაჲ, კეთილმითხრობისა ძალითა მრავლითა, აღსრულებლად სახარებისა, საყვა-რელისა ძისა თვისისა, უფლისა ჩუჱნსა იესო ქრისტესა."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ამინ. სიბრძნით აღემართენით და ისმინეთ წმიდა სახარება"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობა ყოველთა."},{"t":"say","role":"choir","who":"გუნდი","text":"და სულისაცა შენისათანა."},{"t":"say","role":"deacon","who":"დიაკონი","text":"(იოანესგან...) წმიდისა სახარებისა საკითხავი."},{"t":"say","role":"choir","who":"გუნდი","text":"დიდება შენდა უფალო დიდება შენდა."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"მოხედენ."},{"t":"rubric","text":"ამ დროს მეუფე დასახავს ჯვარს დიაკვნებს, ხელს დადებს სამოციქულოზე და ომოფორზე, ემთხვევიან მას დიაკვნები."},{"t":"say","role":"choir","who":"გუნდი","text":"დიდება შენდა უფალო, დიდება შენდა"},{"t":"rubric","text":"დიაკონი კითხულობს სახარებას, დასრულების შემდეგ"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობა შენდა კეთილის მთხ-რობელო."},{"t":"rubric","text":"I დიაკონი სახარებას წააბრძანებს საკურთხევლისაკენ, აღსავლის კართან მეუფე შეეგებება ემთხვევა სახარებას და დიაკონი დაასვენებს მას წმიდა ტრაპეზზე მისთვის განკუთვნილ ადგილზე და ტრაპეზის მარჯვენა მხარეს დადგება. მეუფე დასახავს დიკირ-ტრიკირით ჯვარს. III დიაკონი გამოდის ჩრდილოეთ კარიდან აცდის ეპისკოპოსს დიკირ-ტრიკირით ჯვარის გადასახვას და შემდეგ გადადის მაცხოვრის ხატთან კვერექსისათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"ისპოლა ეტი დესპოტა."},{"t":"rubric","text":"რიპიდები და დიკირ-ტრიკირები შემოვლიან საკურთხეველში."},{"t":"rubric","text":"ეპისკოპოსი წაიკითხავს ლოცვას, გაშლის ოდიკს გარდა ზედა ნაწილისა, მოიხნის მიტრას, რომელსაც გამოართმევს I დიაკონი და დადებს წმიდა ტრაპეზზე."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"ვსთქვათ ყოველთა ყოვლითა სულითა და ყოვლითა გონებითა ჩუჱნთა ვსთქვათ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"უფალო ყოვლისამპყრობელო, ღმერთო მამათა ჩუჱნთაო, გევედრებით, ისმინე და შეგ-ჳწყალენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგჳწყალენ ჩუჱნ ღმერთო, დიდითა წყა-ლობითა შენითა, გევედრებით, ისმინე და შეგ-ჳწყალენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით ღვთივდაცულისა ერისა ჩუჱნსა, მთავრობისა და მხედრობისა მისისათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"rubric","text":"ლოცვა შევრდომით სავედრებელი"},{"t":"prayer","text":"უფალო ღმერთო ჩუჱნო, აპყრობილი ესე ვედრებაჲ შეიწირე მონათა შენთაგან, და შეგჳწყალენ ჩუჱნ, სიმრავლისაებრ წყალობათა შენთასა, და მოწყალებანი შენნი გარდამოავლინენ ჩუჱნ ზედა, და ყოველსა ერსა შენსა ზედა, მომლოდნელთა მდიდრად შენ მიერისა წყალობისასა:"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით უწმიდესისა და უნეტარესისა, სრულიად საქართველოს კათოლიკოს-პატრიარქისა და მცხეთა-თბილისის მთავარ-ეპისკოპოსისა, დიდისა მეუფისა, მამისა ჩუჱნსა ი ლ ი ა ს ა თ ჳ ს, და სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრისა, მაღალყოვლადუსამღვდელოესისა, სენაკისა და ჩხოროწყუს მიტროპოლიტი შიოსათვის და მაღალყოვლადუ-სამღვდელოესისა ქუთათელ-გაენა-თელი მიტროპოლიტი იოანესათვის და ყოველთა ქრისტეს მიერ ძმათა ჩუჱნთათჳს."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით ძმათა ჩუჱნთა მღვდელთა, მღვდელ-მონაზონთა და ყოველთა ქრისტეს მიერ ძმათა ჩუჱნთათჳს"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით სანატრელთა და მარადის მოსახსენებელთა, წმიდათა მართლმადიდებელთა პატრიარქთა, კეთილმსახურთა მეფე-თა და კეთილმორწმუნეთა დედოფალთა და აღმაშენებელთა წმიდისა ამის ტაძრისათა (მონასტრისათა) და ყოველთა პირველ დაძინებულთა მამათა და ძმათა, აქა მდებარეთა, და ყო-ველთაგან მართლმადიდებლობით აღსრულებუ-ლთათჳს."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით წყალობისა, სიცოცხლისა, მშვიდობისა, სიმრთელისა, ცხოვრე-ბისა, შეწევნისა, შენდობისა და მიტევებისა ცოდ-ვათასა, მონათა ღვთისათა, ძმათა წმიდისა ამის ტაძრისათა (ან, წმიდისა ამის მონასტრისათა)"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით ნაყოფისშემომწირველთათვის და კეთილისმყოფელთა წმიდისა და ყოვლადპატიოსნისა ამის ტაძრისა და ამას შინა მშრომელთა, მგალობელთა და აქა მდგო-მარეთა ერთათვის, რომელნი მოელიან შენ მიერ დიდსა და მდიდარსა წყალობასა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ მოწყალე და კაცთმოყვარე ღმერთი ხარ, და შენდა დიდებასა აღვავლენთ, მამისა და ძისა და წმიდისა სულისა აწდა მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"მიცვალებულთა კვერექსი არ ვამბობთ კვირა დღეს და საუფლო დღესასწაულებზე."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგჳწყალენ ჩუჱნ, ღმერთო, დიდითა წყალობითა შენითა, გევედრებით ისმინე და შეგჳ-წყალენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმეცა გევედრებით განსვენებისათჳს სულთა მიცვალებულთა მონათა ღვთისათა (სახელები) და რათა შეენდვნეს მათ ყოველნი შეცოდებანნი ნებსითნი და უნებლიეთნი."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"say","role":"deacon","who":"დიაკონი","text":"რათა უფალმან ღმერთმან ჩუჱნმან დაა-წესოს სულნი მათნი, სადაცა მართალნი განისვენებენ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ გ-გზის"},{"t":"say","role":"deacon","who":"დიაკონი","text":"წყალობა ღვთისა და სასუფეველი ცათა და მიტევება ცოდვათა მათთა, ქრისტეს მიერ, უკვდავისა მეუფისა და ღმრთისა ჩუჱნსაგან, ვითხოვოთ, უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ უფალო, უფალო შეგჳწყა-ლენ."},{"t":"prayer","text":"ღმერთო სულთაო, და ყოველთა ჴორციელთაო, რომელმან სიკვდილი განა-ქარვე, და ეშმაკი დასთრგუნე, და ცხოვრება სოფელსა მოანიჭე, შენ უფალო განუსვენე სულთა მონათა შენთასა, (სახელი) ადგილსა ნათლი-სასა, ადგილსა მწვანვილოვანსა, ადგილსა განსასვენებელსა, სადა იგი არა არს სალმობა, მწუხარება, და სულთქმა, და ყოველნი ცოდვანი მათ მიერ ქმნილნი საქმითნი, სიტყვითნი და მოგონებითნი, ვითარცა სახიერმან და კაცთ-მოყვარემან ღმერთმან შეუნდ-ვენ, რამეთუ არა არს კაცი რომელი სცხოვნდეს, და არა სცოდოს, რამეთუ შენ მხოლო ხარ უცხო ყოვლისაგან ცოდვისა, და სიმართლე შენი სიმართლე არს საუკუნო, და სიტყვა შენი ჭეშმარიტ:"},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ შენ ხარ აღდგომა, და ცხოვ-რება და განსვენება მიცვალებულთა მონათა შენთა (სახელები), ქრისტე ღმერთო ჩუჱნო, და შენდა დიდებასა აღვავლენთ, თანა დაუსაბამოთ მამით შენით, და ყოვლად წმიდით სახიერით და ცხოველსმყოფელით სულით შენითურთ, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ილოცეთ, კათაკმეველნო, უფლისა მი-მართ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მორწმუნენო, კათაკმეველთათვის ვილოცოთ, რათა უფალმან იგინიცა შეიწყალნეს."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"და ასწავლოს მათ სიტყვა ჭეშმარი-ტებისა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"და გამოუცხადოს მათ სახარება სიმა-რთლისა."},{"t":"rubric","text":"გაიშლება ოდიკი სრულად."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეაერთნეს იგინი წმიდასა თჳსსა, კა-თოლიკე და სამოციქულოსა ეკლესიასა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"აცხოვნენ, შეეწიენ, შეიწყალენ და დაიცუჱნ იგინი, ღმერთო მადლითა შენითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"კათაკმეველნო, თავნი თქვენნი უფა-ლსა მოუდრიკენით."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ, უფალო."},{"t":"rubric","text":"ლოცვა კათაკმეველთათვის"},{"t":"prayer","text":"უფალო ღმერთო ჩუჱნო, რომელი მაღალთა შინა დამკვიდრებულ ხარ, და მდაბალთა ხედავ, რომელმან ცხო-ვრებისა-თჳს კაცთასა მოავლინე, მხოლოდშობილი ძე შენი და ღმერთი, და უფალი ჩუჱნ იესო ქრისტე, მოიხილე მო-ნათა შენთა კათაკმეველთა, მომდრეკელთა შენდა ქედთა მათთასა, და ღირს-ჰყუენ იგინი ჟამსა შინა კეთილსა, საბანელსა მეორედ შობისასა, მიტე-ვებასა ცოდვათასა, და სამოსელსა უხრწნელებისასა, შეაერთენ იგინი წმი-დასა შენსა კათოლიკე და სამოციქულოსა ეკლესიასა, და თანა-აღრაცხენ იგინი რჩეულსა შენსა სამწყსოსა:"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"რათა და ესენიცა ჩუჱნთანავე ადიდებდენ ყოვლადპატიოსანსა და დიდად შვე-ნიერსა სახელსა შენსა, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"rubric","text":"ეპისკოპოსი ღრუბლით გამოსახავს ჯვარს ოდიკზე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"რაოდენნი კათაკმეველნი ხართ, განვედით, კათაკმეველნო, განვედით, რაოდენნი კა-თაკმეველნი ხართ განვედით. ნუ ვინმე კათაკმეველთაგანნი, არამედ რაოდენნი მორწმუნენი ვართ, მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"rubric","text":"ლოცვა მორწმუნეთათვის პირველი"},{"t":"prayer","text":"გმადლობთ შენ უფალო ღმერთო ძალ-თაო, ღირს მყოფელსა ჩუჱნსა წარდგომად აწცა წმიდასა შენსა საკურ-თხეველსა, და შევრდომად შენთა მოწყალებათა ჩუჱნთა ცოდვათა-თჳს და ერისა უმეცრებისა-თჳს, მიითვალე ღმერთო ვედრებაჲ ჩუჱნ, მყუჱნ ჩუჱნ ღირს ყოფად შეწირვად შენდა ვედრებათა და ოხათა, და მსხვერპლთა უსისხლოთა ყოვლისა-თჳს ერისა შენი-სა, და კმა მყუჱნ, ჩუჱნ რომელნი დასხმენ მსახურებასა ამას შენსა, ძალითა სულისა შენისა წმიდისათა, უბრალოდ და დაუბრკოლებელად, წმიდითა მოწა-მებითა სვინდისისა ჩუჱნისათა, ხდად შენდა ყოველსა ჟამსა და ადგილსა, რათა მსმენელი ჩუჱნ, მწყალობელ ჩუჱნდა იყო, სიმართლითა შენისა სახიერებისათა:"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგჳწყალენ და დაგვიცუჱნ ჩუჱნ, ღმერთო, შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"სიბრძნით"},{"t":"say","role":"priest","who":"მღვდელი","text":"რამეთუ შვენის შენდა ყოველი დი-დება, პატივი და თაყვანის-ცემა, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ზე გარდამო მშვიდობისა და ცხოვრე-ბისათჳს სულთა ჩუჱნთასა, უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"მშვიდობისათვის ყოვლისა სოფლისა, კეთილად დგომისათვის წმიდათა ღვთისათა ეკლესიათა და ყოველთა ერთობისათვის, უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"წმიდისა ამის სახლისათვის, სარწმუნო-ებითა, კრძალულებით და შიშითა ღვთისათა შე-მავალთა ამას შინა, უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ხსნად ჩუჱნდა ყოვლისაგან ჭირისა, რის-ხვისა და იწროებისა, უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"rubric","text":"ლოცვა მორწმუნეთათვის მეორე"},{"t":"prayer","text":"კვალადცა, და მრავლ-გზის შენ შეგი-ვრდებით, და შენ გევედრებით სახიერო, და კაცთმოყვარეო, რათა მოხე-დვითა ვედრებასა ჩუჱნსა, განსწ-მიდნე სულნი ჩუჱნ და ჴორცნი ყოვ-ლისაგან შეგინებისა ჴორცთა და სულისა, და მომეც ჩუჱნ უბრალოდ და დაუსჯელად წარდგომად წმიდასა შენ-სა საკურთხეველსა. მომმადლენ, ღმე-რთო, ჩუჱნ თანა მლოცველთაცა წარმართებაჲ ცხოვრებისა, სარწმუნო-ებისა, და გულის-ჴმის-ყოფისა სული-ერისა, მოეც მათ ყოვლადვე შიშით და სიყვარულით მსახურთა შენთა, უბრა-ლოდ და დაუსჯელად მოღებად წმიდათა შენთა საიდუმლოთა, და ზეცისა სასუფეველსა ღირს ყოფად:"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგჳწყალენ, და დაგვიცუჱნ ჩუჱნ, ღმერთო, შენითა მადლითა"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"სიბრძნით"},{"t":"say","role":"priest","who":"მღვდელი","text":"რათა ძლიერებითა შენითა ყოვლადვე დაცულნი, შენდა დიდებასა აღვავლენთ, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე"},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"ამ დროს გადიან სტიქაროსნები ხელბანაზე (წყალის ჭურჭელი გადის სადიაკვნის მხრიდან)."},{"t":"rubric","text":"I დიაკონი აკმევს საკურთხეველს."},{"t":"prayer","text":"არავინ არს ღირს თანა შეკრული ჴორციელთა გულის თქმათა და გემოთა წარდგომად, ანუ მიახლებად, გინა მსახურებად შენდა, მეუფეო დიდები-საო, რამეთუ მსახურება შენი, დიდ არს და საშინელ თჳთ მათ ზეცისა ძალ-თადცა, არამედ რამეთუ გამოუთ-ქმელისა-თჳს და აურაცხელისა კაცთ-მოყვარებითა, უქცეველად და უცვა-ლებელად კაც იქმენ, და მღვდელ-მთა-ვრად ჩუჱნდა გამოსჩნდი, და მსახურებრივისა ამის და უსისხლოჲსა მსხ-ვერპლისა მღვდელ-მოქმედებაჲ მოგვანიჭე ჩუჱნ, ვითარცა მეუფემან ყო-ველთამან, რამეთუ შენ მხოლო, უფა-ლო ღმერთო ჩუჱნო, მეუფებ ცათა შინა და ქუჱეყანასა ზედა, საყდარსა ზედა ქერუბიმთასა მჯდომარე, სერაფიმთა უფალი, და მეუფე ისრაილისა, მხოლოო წმიდაო, და წმიდათა შორის განსვენებულო, შენ უკუჱ გევედრები, მხოლოსა სახიერსა და კეთილ მსმენელსა, მოიხილე ჩემ ცოდვილსა ზედა და უჴმარსა მონასა შენსა, და განსწმინდე სული ჩემი და გული ცნობისაგან ბოროტისა, და ღირს მიჩინე მე ძალითა სულისა შენისა წმიდისათა, შემოსილი მღუდელობისა მადლითა, წარდგომად წმიდისა ამის ტრაპეზისა შენისა, და მღუდელ-მოქმედებად წმიდისა უხრწ-ნელისა ჴორცისა შენისა და პატიოსნისა სისხლისა შენისა. რამეთუ შენდა მოვივლტი მომდრეკელი ქედისა ჩემისა, და გევედრები შენ, ნუ გარე მიიქცევ პირსა შენსა ჩემგან, ნუცა განმყოფ მე მონათა შენთაგან, არამედ ჯერ იჩინე შეწირვად შენდა, ჩემ ცოდეილისა და უღირსისა მონისა შენისა მიერ, მსხვერპლი ესე. რამეთუ შენ ხარ შემწირ-ველი და შეწირული, და შემწ-ყნარებელი და მიმცემელი, ქრისტე ღმე-რთო ჩუჱნო, და შენდა დიდებასა აღვავლენთ, თანა დაუსაბამოთ მამით შენით, და ყოვლად წმიდით სახიერით, და ცხოველს მყოფელით სულით შენი-თურთ, აწ და მარადის და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"მეუფე აღსავლის კარში აღასრულებს ხელბანვას (აქ ლოცვას არ ვუკითხავთ) შეიმოსება მცირე ომოფორით და ითქმება რომელი ქერუბიმთა. მეუფე დგას ტრაპეზის წინ, მისგან მარჯვნივ დგას I დიაკონი, შემდეგ III დიაკონი, მეუფეს მარცხნივ დგას II დიაკონი."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"რომელნი ქერუბიმთა საიდუმლოს ვემსგავსენით და ცხოველსმყოფელისა სა-მებისა, სამ-წმიდა-არსობისა გალობასა შევ-სწირავთ, ყოველივე მსოფლიო დაუტევოთ ზრუნვაჲ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"და ვითარცა მეუფისა ყოველთასა, შემ-წყნარებელთა ანგელოზთაებრ უხილავად ძღ-ვნის შემწირველთა წესთასა, ალილუია, ალი-ლუია, ალილუია."},{"t":"rubric","text":"ეპისკოპოსი მოიხსენიებს (დეკანოზობა თქვენი... მღვდელმონაზვნობა თქვენი... სამღვდელო დიაკვნობა თქვენი... მოიხსენოს უფალმა ღმერთმა სასუფეველსა თვისსა ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე.)"},{"t":"rubric","text":"ვპასუხობთ მოხსენებას მღვდელმთავრობა თქვენი მოიხსენოს უფალმა ღმერთმა სასუფეველსა თვისსა ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"rubric","text":"I დიაკონი მიაწვდის მიტრას, რომელსაც მეუფე დააბრძანებს სინზე, რომელიც უკავია III დიაკონს, II დიაკონი სასაკმევლით ელოდება სამკვეთლოსთან. ეპისკოპოსი აღსავლის კარში თავს მოიდრეკს ერს და გადაბრძანდება სამკვეთლოში."},{"t":"rubric","text":"I დიაკონი სამკვეთლოში აიღებს დიდ დაფარნას და გაშლილს დაახვედრებს მეუფეს და მიაწვდის."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"აღიღე მაღალყოვლადუსამღვდელო-ესო მეუფეო."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"აღიღეთ ხელნი თქვენნი წმიდათ მიმართ, და აკურთხევდით უფალსა."},{"t":"rubric","text":"მეუფე დიდ დაფარნას გაუკეთებს II დიაკონს, რომელიც აკურთხებინებს სასაკმევლეს და აკმევს კანკელს და მრევლს."},{"t":"head","text":"დიდი შესვლა"},{"t":"rubric","text":"III დიაკონი სინზე ომოფორით და მიტრით (პირდაპირ შედის აღსავლის კარით და ჩერდება ტრაპეზის მარჯვნივ), II დიაკონი სასაკმევლით, (აკმევს, კმევით შედის აღსავლის კარით, აკმევს ტრაპეზს წინიდან გ-გზის, მაღალდასაჯდომელს გ-გზის, გადმოდის ტრაპეზის მარცხენა მხარეს (ღვთისმშობლის კანკელის ხატის უკან) და დგება აღსავლის კართან და ელოდება ეპისკოპოსს). I დიაკონი ფეშხუმით (აღსავლის კარში ელოდება მეუფეს)."},{"t":"rubric","text":"წინამძღვარი ბარძიმით (აღსავლის კართან, ღვთისმშობლის ხატთან ელოდება მეუფეს)."},{"t":"rubric","text":"დიკირ-ტრიკირი და რიპიდი (ჩერდებიან ამბიონზე ბარძიმ-ფეშხუმის მარჯვნივ და მარცხნივ)"},{"t":"rubric","text":"ეპისკოპოსი სამკვეთლოში განიმოსავს მცირე ომოფორს, გავა საკურთხეველში III დიაკონის სინიდან აიღებს მიტრას და დააბრძანებს ტრაპეზზე."},{"t":"rubric","text":"II დიაკონი ხელში მიაწვდის სასაკმევლეს (ემთხვევა ხელზე) ეპისკოპოსი უკმევს ფეშხუმს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"დიაკვნობა შენი მოიხსენოს უფალმან ღმერთმან სასუფეველსა თვისსა ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე. ამინ."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მღვდელთავრობა თქვენი მოიხსენოს უფალმან ღმერთმა სასუფეველსა თვისსა ყოვ-ლადვე აწ და მარადის და უკუნითი უკუნისამდე. ამინ."},{"t":"rubric","text":"ეპისკოპოსი დაუბრუნებს II დიაკონს სასაკმევლეს, გამოართმევს I დიაკონს ფეშხუმს და გამოდის ამბიონზე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ღვთივ დაცული ერი ჩუენი და მეუფება მისი მოიხსენოს უფალმან ღმერთმან სასუფეველსა თვისსა ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე. ამინ."},{"t":"rubric","text":"ეპისკოპოსი დააბრძანებს ფეშხუმს ტრაპეზზე. I დიაკონი სამხრეთის კარით შედის საკურთხეველში. ეპისკოპოსი უკმევს ბარძიმს რომელიც უპყრია წინამძღვარს და დგას აღსავლის კართან."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მღვდლობა შენი მოიხსენოს უფალმან ღმერთმა სასუფეველსა თჳსსა ყოვ-ლადვე აწ და მარადის და უკუნითი უკუნისამდე. ამინ."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"მღვდელთავრობა თქვენი მოიხსენოს უფალმან ღმერთმა სასუფეველსა თვისსა ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე. ამინ."},{"t":"rubric","text":"დაუბრუნებს II დიაკონს სასაკმევლეს, გამოართმევს წინამძღვარს ბარძიმს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"უწმიდესი და უნეტარესი, სრულიად საქართველოს კათოლიკოს-პატრიარქი, და მცხეთა-თბილისის მთავარეპისკოპოსი, დიდი მეუფე მამაჲ ჩუჱნ ილია, მოიხსენოს უფალმან ღმერთმან სასუფეველსა თვისსა, ყოვლადვე, აწ და მარადის და უკუნითი უკუნისამდე. ამინ"},{"t":"rubric","text":"სრულიად საქართველოს კათოლიკოს-პატრიარქის მოსაყდრე, მაღალყოვლადუსამღვდელოესი, სენაკისა და ჩხოროწყუს მიტროპოლიტი შიო, მოიხსენოს უფალმან ღმერთმან სასუფეველსა თვისსა, ყოვლადვე, აწ და მარადის და უკუნითი უკუნისამდე. ამინ"},{"t":"rubric","text":"(აქ მოიხსენებს ვინც უნდა)"},{"t":"rubric","text":"ეპისკოპოსი გადასცემს წინამძღვარს ბარძიმს."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"მაღალყოვლადუსამღვდელოესი ქუთათელ-გაენათელი მიტროპოლიტი იოანე, მოიხსენოს უფალმან ღმერთმან სასუფეველსა თჳსსა, ყოვლადვე, აწ და მარადის და უკუნითი უკუნისამდე. ამინ."},{"t":"rubric","text":"კეთილ მორწმუნენი, ნაყოფის შემომწირველნი და კეთილის მყოფელნი წმიდისა და ყოვლად პატიოსნისა ამის ტაძრისა, და ამას შინა მშრომელნი, მგალობელნი, თქუენ აქა მდგომარენი, მვე-დრებელნი და ყოველნი მართლმადიდებელნი ქრისტიანენი, მოიხსენოს უფალმან ღმერთმან სასუფეველსა თვისსა, ყოვლადვე, აწ და მარადის და უკუნითი უკუნისამდე. ამინ."},{"t":"rubric","text":"წინამძღვარი დაასვენებს ბარძიმს წმიდა ტრაპეზზე. სამღვდელოება აღსავლის კარით შედიან საკურთხეველში. რიპიდებიც შედიან საკურთხეველში."},{"t":"rubric","text":"II დიაკონი I დიაკონს მისცემს სასაკმევლეს და დიდ დაფარნას, III დიაკონი ტრაპეზიდან აიღებს მიტრას."},{"t":"say","role":"choir","who":"მგალობლები","text":"და ვითარცა მეუფისა ყოველთასა შემწყნარებელთა, ანგელოზთაებრ უხილავად ძღვნის შემწირველთა წესთასა, ალილუია, ალილუია, ალილუია."},{"t":"rubric","text":"I დიაკონი სასაკმევლეს ასუნელებიებს მეუფეს დიდ დაფარნას და მიაწვდის სასაკმევლეს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"შვენიერმან იოსებ, ძელისაგან გარდამოხსნა უხრწნელი ხორცი შენი, და არმენაკითა წმინდითა წარგრაგნა, სუნნელებითა შემურვილი, ახალსა საფლავსა დაგდვა."},{"t":"rubric","text":"საფლავსა შინა ჴორცითა, ჯოჯოხეთს შინა სული-თა, ვითარცა ღმერთი, ხოლო სამოთხეს ავაზაკისა თანა, და საყდართა მამისა და სულისა თანა იყავ ქრისტე, ყოვლისა აღმავსებელ გარე შემოუწერელო."},{"t":"rubric","text":"ვითარცა ცხოვრება შემოსილ, ვითარცა ნამდვილ სამოთხისა უშვენიერეს და ყოვლისა სამეფოჲსა სასძლოისა უბრწყინვალეს გამოსჩნდა, ქრისტე, საფლავი შენი, წყარო იგი ჩუჱნისა აღდგომისა."},{"t":"rubric","text":"კმევისას"},{"t":"rubric","text":"შვენიერმან იოსებ, ძელისაგან გარდამოხსნა უხრწნელი ხორცი შენი, და არმენაკითა წმინდითა წარგრაგნა, სუნნელებითა შემურვილი, ახალსა საფლავსა დაგდვა."},{"t":"rubric","text":"კეთილი უყავ, უფალო, ნებითა შენითა სიონსა და აღაშენნენ ზღუდენი იერუსალიმისანი, მაშინ გთნდეს მსხვერპლი სიმართლისა, შესაწირავი და ყოვლადდასაწველი; მაშინ შეიწირნენ საკუ-რთხეველსა შენსა ზედა ზვარაკნი."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მომიხსენე მე, ძმაო და თანამწირველო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"სული წმიდა მოვიდეს შენ ზედა, და ძალი მაღლისა გფარვიდეს შენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ხოლო იგივე სული თანა-მოქმედ-გვექმნას ჩუჱნ, ყოეელთა დღეთა ცხოვრებისა ჩუჱნსათა."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ამინ. ლოცვა-ჰყავ ჩემთვის, მაღალყოვლადუსამღვდელოესო მეუფეო."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"წარგიმართოს შენ სვლანი შენნი."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მომიხსენე მე, მაღალყოვლადუსამღვდელოესო მეუფეო."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მოგიხსენოს შენ უფალმან ღმერთმან სასუფეველსა თვისსა, ყოვლადვე, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ამინ."},{"t":"sep"},{"t":"rubric","text":"მღვდელთან მსახურებისას"},{"t":"say","role":"priest","who":"მღვდელი","text":"მომიხსენე მე, ძმაო და თანამწირველო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მოიჴსენოს უფალმან ღმერთმან მღვდლობა შენი სასუფეველსა თჳსსა."},{"t":"rubric","text":"ლოცვა ჰყავთ ჩემთჳს მაღალყოვლადუსამღვდელოესო მეუფეო."},{"t":"say","role":"priest","who":"მღვდელი","text":"სული წმიდა მოვიდეს შენ ზედა, და ძალი მაღლისა გფარვიდეს შენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ხოლო იგივე სული თანა-მოქმედ-გვექმნას ჩუჱნ, ყოეელთა დღეთა ცხოვრებისა ჩუჱნსათა."},{"t":"sep"},{"t":"rubric","text":"I დიაკონი გამოართმევს მეუფეს სასაკმევლეს და შემოუკმევს ტრაპეზს გარშემო და მეუფეს თ-გზის. III დიაკონი მეუფეს მიაწვდის მიტრას."},{"t":"rubric","text":"ეპისკოპოსი ამბიონზე სახავს დიკირ-ტრიკირით ჯვარს."},{"t":"say","role":"choir","who":"გუნდი","text":"ისპოლა ეტი დესპოტა."},{"t":"rubric","text":"(სამღვდელმთავრო მსახურებაზე აღსავლის კარები და კრეტსამბელი არ იკეტება)"},{"t":"say","role":"deacon","who":"II დიაკონი","text":"აღუსრულოთ ვედრება ჩუჱნი უფალ-სა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"წინადაგებულთა პატიოსანთა ძღვენთათჳს, უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"წმიდისა ამის ტაძრისათვის (მონასტრისათჳს), სარწმუნოებითა, სასოებითა და შიშითა ღვთისათა შემავალთა ამას შინა, უფლისა მი-მართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ჴსნად ჩუჱნდა ყოვლისაგან ჭირისა, რისხვისა და იწროებისა, უფლისა მიმართ ვილოცოთ."},{"t":"rubric","text":"ლოცვა დაგებისა შემდგომად დადგმისა საღმრთოთა ძღვენთასა წმიდასა ზედა ტრაპეზსა."},{"t":"prayer","text":"უფალო ყოვლისა მპყრობელო, ღმერთო მამათა ჩუჱნთაო, რომელი შეიწირავ მსხვერპლსა ქებისასა მათგან, რომე-ლნი გხადიან შენ ყოვლითა გულითა, მიითვალე ჩუჱნცა ცოდვილთა ვედრე-ბაჲ, და შეიწირე წმიდასა შენსა საკურთხეველსა, და კმა მყუჱნ ჩუჱნ შეწირვად შენდა ძღვენთა და მსხვე-რპლთა სულიერთა, ჩუჱნთა ცოდვათა-თჳს, და ერისა უმეცრებისა-თჳს, და ღირს მყუჱნ ჩუჱნ პოვნად მადლსა წი-ნაშე შენსა, კეთილ მითვალულ ყოფად შენდა მსხვერპლი ჩუჱნ, და დამკჳდ-რებად სულსა მადლისა შენისასა სახიერსა ჩუჱნ ზედა, და წინა მდებარეთა ამათ ძღვენთა ზედა, და ყოველსა ერ-სა შენსა:"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგჳწყალენ და დაგვიცუჱნ ჩუჱნ, ღმერთო, შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"დღე ყოველი აღსრულებად, სიწმიდით, მშვიდობით და უცოდველად, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ანგელოზი მშვიდობისა, სარწმუნო წინა-მძღვარი, მცველი სულთა და ხორცთა ჩუჱნთა, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შენდობა და მოტევება ცოდვათა და უსჯულოებათა ჩუჱნთა, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"კეთილნი და უმჯობესნი სულთა ჩუჱნ-თანი და მშვიდობა სოფლისა, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შემდგომნი ჟამნი ცხოვრებისა ჩუჱნისანი მშვიდობით და სინანულით აღსრულებად, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ქრისტეანობითნი აღსასრულნი ცხოვრე-ბისა ჩუჱნსანი, უჭირველნი, ურცხვენელნი, მშჳდობითნი, და კეთილი სიტყვისგება წინაშე საშინელისა სამსჯავროსა ქრისტესსა ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვმადლენ, უფალო."},{"t":"say","role":"deacon","who":"დიაკონი","text":"ყოვლადწმიდისა, უხრწნელისა, უფრო-სად კურთხეულისა, დიდებულისა დედოფლისა ჩუჱნსა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა, და ყოველთა წმიდათა მომხსენებელთა, თავნი თვისნი, და ურთიერთ არს, და ყოველი ცხოვრება ჩუჱნი ქრისტესსა ღმერთსა ჩუჱნსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ, უფალო."},{"t":"say","role":"priest","who":"მღვდელი","text":"მოწყალებათათვის მხოლოდშობილისა ძისა შენისათა, რომლისა თანა კურთხეულ ხარ, თანა ყოვლადწმიდით და სახიერით და ცხოველს-მყოფელით სულით შენითურთ, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობა ყოველთა."},{"t":"rubric","text":"I დიაკონი გამოართმევს მიტრას და დადებს ტრაპეზზე."},{"t":"say","role":"deacon","who":"II დიაკონი (მაცხოვრის ხატთან)","text":"ვიყვარებოდეთ ურთიერთარს რათა ერთობით აღვიარებდეთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მამასა და ძესა და წმიდასა სულსა, სა-მებასა ერთარსებასა და განუყოფელსა."},{"t":"rubric","text":"ეპისკოპოსი ემთხვევა ტრაპეზს"},{"t":"say","role":"bishop","who":"მღვდელმთავარი და მღვდლები (ჩუმად)","text":"შეგიყუარო შენ, უფალო, ძალო ჩემო, უფალო დამამტკიცებელო ჩემო, და შესავედრებელო ჩემო (გ-გზის)."},{"t":"rubric","text":"დადგება ტრაპეზისგან მარჯვნივ და მღვდლები მოდიან ტრაპეზის მარცხნიდან ემთხვევიან ფეშხუმს, ბარძიმს ტრაპეზს და შემდეგ მეუფეს."},{"t":"rubric","text":"ერთმანეთს ემთხვევიან და იტყვიან: ქრისტე არს ჩუენ შორის. არს და იყოს."},{"t":"say","role":"deacon","who":"II დიაკონი (მაცხოვრის ხატთან)","text":"კარნი, კარნი, სიბრძნით მოხედენ."},{"t":"rubric","text":"მეუფე დგება ტრაპეზთან თავდახრილი მის გარშემო სამღვდელოება რომელნიც აიღებენ დიდ დაფარნას და ამოძრავებენ ძღვნის ზემოდან. (იერარქიულად უმცირესი მღვდელი ამბობს მრწამსს)"},{"t":"say","role":"choir","who":"გუნდი","text":"მრწამს ერთი ღმერთი, მამა, ყოვლისა მპყრობელი, შემოქმედი ცათა და ქუეყანისა, ხი-ლულთა ყოველთა და არა ხილულთა;"},{"t":"rubric","text":"და ერთი უფალი იესუ ქრისტე, ძე ღმრთისა მხოლოდშობილი, მამისაგან შობილი უწინარეს ყო-ველთა საუკუნეთა."},{"t":"rubric","text":"ნათელი ნათლისაგან, ღმერთი ჭეშმარიტი ღვთისაგან ჭეშმარიტისა, შობილი და არა ქმნილი, თანაარსი მამისა, რომლისაგან ყოველი შეიქმნა."},{"t":"rubric","text":"რომელი ჩუენთვის, კაცთათვის და ჩუენისა ცხო-ვრებისათვის გარდამოხდა ზეცით, და ხორცნი შეისხნა სულისაგან წმიდისა და მარიამისაგან ქალწულისა, და განკაცნა."},{"t":"rubric","text":"და ჯუარს ეცვა ჩუენთვის პონტოელისა პილატესზე და ივნო, და დაეფლა."},{"t":"rubric","text":"და აღსდგა მესამესა დღესა მსგავსად წერილისა."},{"t":"rubric","text":"და ამაღლდა ზეცად, და მჯდომარე არს მარ-ჯვენით მამისა."},{"t":"rubric","text":"და კუალად მომავალ-არს დიდებით, განსჯად ცხოველთა და მკუდართა, რომლისა სუფევისა არა არს დასასრულ."},{"t":"rubric","text":"და სული წმიდა, უფალი და ცხოველს-მყოფელი, რომელი მამისაგან გამოვალს, მამისა თანა და ძისა თანა თაყუანის-იცემების და იდიდების, რომელი იტყოდა წინასწარმეტყველთა მიერ."},{"t":"rubric","text":"ერთი, წმიდა, კათოლიკე და სამოციქულო ეკლესია. აღვიარებ ერთსა ნათლისღებასა მოსატევ-ებელად ცოდვათა."},{"t":"rubric","text":"მოველი აღდგომასა მკუდრეთით."},{"t":"rubric","text":"და ცხოვრებასა მერმისსა მის საუკუნესასა, ამინ."},{"t":"rubric","text":"მეუფე ემთხვევა დიდ დაფარნას."},{"t":"rubric","text":"I დიაკონი მრწამსში სულიწმინდის მუხლზე აიღებს მიტრას და მისცემს მეუფეს. სტიქაროსნები აანთებენ დიკირ-ტრიკირს."},{"t":"say","role":"deacon","who":"II დიაკონი (მაცხოვრის ხატთან)","text":"ვსდგეთ კეთი-ლად ვსდგეთ შიშით, მოხედენ წმიდასა ამას შესაწირავსა მშვიდობით შეწირვადსა"},{"t":"say","role":"choir","who":"გუნდი","text":"მშვიდობა შესაწირავი ქებისა."},{"t":"rubric","text":"და შემოდის სამხრეთ კარით და დგება ტრაპეზის მარცხნიდან."},{"t":"rubric","text":"სტიქაროსნები აწვდიან მეუფეს დიკირ-ტრიკირს."},{"t":"say","role":"choir","who":"გუნდი","text":"წყალობა, მშვიდობა, შესაწირავი ქები-სა."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მადლი უფლისა ჩუჱნსა იესო ქრისტესი, და სიყვარული ღვთისა და მამისა, და ზიარება სულისა წმიდისა, იყავნ თქვენ ყო-ველთა თანა."},{"t":"rubric","text":"ეპისკოპოსი გადის ამბიონზე დიკირ-ტრიკირით და გამოსახავს ჯვარს."},{"t":"say","role":"choir","who":"გუნდი","text":"და სულისაცა შენისა თანა."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ზე გვაქუნდინ გულნი."},{"t":"rubric","text":"ჯვარს გამოსახავს მეორეჯერ დიკირ-ტრიკირით."},{"t":"say","role":"choir","who":"გუნდი","text":"გვაქვს უფლისა მიმართ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ვმადლობდეთ უფალსა."},{"t":"rubric","text":"ეპისკოპოსი გამოსახავს ჯვარს მესამეჯერ. სტიქაროსნები გამოართმევენ დიკირ-ტრიკირს საკურთხეველში."},{"t":"say","role":"choir","who":"გუნდი","text":"ღირს არს და მართალ თაყვანის-ცემა მა-მისა და ძისა და წმიდისა სულისა, სამებისა ერთ არსებისა და განუყოფელისა."},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"ღირს არს და მართალ შენდა ქებად, შენდა კურთხევად, შენდა გალობად, შენდა მადლობად, შენდა თაყვანის-ცე-მად, ყოველსა ადგილსა მეუფებისა შენისასა, რამეთუ შენ ხარ ღმერთი გამოუთარგმანებელი, მოუგონებელი, უხილავი, მიუწთომელი, მარადის ხარ, ვითარცა იგი ხარ შენ, და მხოლოდ შობილი ძე შენი, და სული შენი წმიდა, რამეთუ შენ არა არსისაგან ყოფად მომიყვანენ ჩუჱნ, და დაცემულნი კვა-ლად აღმადგინენ, და არა განეყენე, ყოვლისა ქმნად, ვიდრემდის ზეცად აღ-მიყვანენ ჩუჱნ, და მოგვმადლე ჩუჱნ სასუფეველი მერმისა: ამათ ყოველთა-თჳს გმადლობთ შენ, და მხოლოდ შო-ბილსა ძესა შენსა, და სულსა შენსა წმიდასა, ყოველთა-თჳს, რომელ უწყით, და რომელ არა უწყით, საჩინოთა და უჩინოთა ქველის-მოქმედებათა ჩუჱნ-და მომართ ქმნილთა, გმადლობთ შენ შეწირვისაცა ამის-თჳს, რომლისა ჴელ-თაგან ჩუჱნთა შეწირვა ღირს იჩინე, დაღათუ შენსა გარემოს სდგანან, ათა-სეულნი მთავარ-ანგელოზთანი, და ბე-ვრეულნი ანგელოზთანი, ქერუბიმნი და სერაფიმნი, ექუს-ვქუს ფრთენი, მრავალ-თვალნი, აღპყრობილნი ფრთე-ებითა:"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ძლევისა გალობისა, მგალო-ბელნი, მხმობელნი, მღაღადებელნი და მეტყველნი."},{"t":"say","role":"choir","who":"გუნდი","text":"წმიდაო, წმიდაო, წმიდაო უფალო საბაოთ სავსე არიან ცანი და ქვეყანა დიდებითა შენითა, ოსანა მაღალთა შინა კურთხეულ არს მომავალი სახელითა უფლისათა, ოსანა მაღალთა შინა"},{"t":"rubric","text":"II დიაკონი ვარსკვლავს დაიჭერს გინგილიანი ხელით დასახავს ძღვენს ჯვარს (მცირედ დააკაკუნებს რომ ნაწილი არ წამოყვეს ვარსკვლავს) გაწმინდავს ღრუბლით დაკეცავს და დადებს ტრაპეზზე დიდ დაფარნაზე."},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"შემდგომად ამათ სანატრელთა ძალთა ჩუჱნცა, მეუფეო კაცთ-მოყვარეო, ვჴ-მობთ, და ვიტყვით, წმიდა ხარ და ყოვ-ლადწმიდა შენ, და მხოლოდშობილი ძე შენი, და სული შენი წმიდა, და დიდად შეუენიერ დიდება შენი, რომელმან სოფელი შენი ესრეთ შეიყვარე, ვიდრე მიცემადმდეცა მხოლოდ შობილისა ძისა შენისა, რათა ყოველსა, რომელსა რწმენეს მისსა მიმართ არა წარ-სწყმდეს, არამედ აქუნდეს ცხოერებაჲ საუკუნო, რომელი იგი მოვიდა რა, და ყოველი ჩუჱნ-თჳს განგებულება სრულ-ჰყო, ღამესა, რომელსა მიეცემო-და, უფროსღა მისცემდა თავსა თჳსსა ცხოვრებისა-თჳს სოფლისა, მოიღო პური წმიდათა ზედა უხრწნელთა და უბი-წოთა ჴელთა, გმადლობდა და აკუ-რთხა, და წმიდა-ჰყო, და განსტეხა, და მისცა წმინდათა მისთა მოწაფეთა და მოციქულთა, მეტყველმან:"},{"t":"rubric","text":"ეპისკოპოსს შემოსავენ მცირე ომოფორით. მოიხსნის მიტრას. I დიაკონი დააბრძანებს მას ტრაპეზზე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მიიღეთ და სჭამეთ, ესე არს ხორცი ჩემი, თქვენთჳს განტეხილი, მისატევებელად ცოდვათა."},{"t":"rubric","text":"სამივე დიაკონი გინგილას გაიშვერენ წმიდა ძღვენისკენ."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"prayer","text":"მსგავსადვე და სასმელისა ყოვლად სერობისა, სთქუა:"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"სუთ ამისაგან ყოველთა, ესე არს სისხლი ჩემი ახლისა აღთქმისა, თქვენთჳს და მრავალთათჳს დათხეული, მისატევებელად ცოდვათა."},{"t":"rubric","text":"სამივე დიაკონი გინგილას გაიშვერენ წმიდა ძღვენისკენ."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"მომჴსენებელნი უკუჱ საცხოვრებე-ლისა ამის მცნებისა, და ყოველთა ჩუჱნ-თჳს ქმნილთა, ჯვრისა, დაფლვისა სამ დღე, და აღდგომისა, ზეცად აღსვ-ლისა, მარჯვენით დაჯდომასა, მეორისა და დიდებულისა კუალად მოსლვისა:"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"შენნი შენთაგან, შენდა შემწი-რველნი ყოველთა და ყოველის-თჳს."},{"t":"rubric","text":"I დიაკონი აამაღლებს წმიდა ძღვენს ღვთის წინაშე და გამოსახავს ჯვარს."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ გიგალობთ, შენ გაკურთხევთ, შენ გმადლობთ, უფალო, და გევედრებით შენ, ღმერ-თო ჩუენო."},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"მერმეცა შევსწირავთ შენდა სიტყვი-ერსა ამას, და უსისხლოსა მსხვერპ-ლსა, და გხადით შენ, და შეგივრდებით, და გევედრებით, გარდამოავლინე სუ-ლი შენი წმიდა ჩუჱნ ზედა, და წინა მდებარეთა ძღვენთა ზედა."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"უფალო, რომელმან ყოვლად-წმიდა სული შენი ჟამსა მესამესა მოციქულთა შენთა გარდამოუვლინე და განანათლენ იგინი, მას, სახიერო, ნუ მიმიღებ ჩემგან, არამედ განმიახლენ მვედრებელსა შენსა"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"გული წმიდა დაბადე ჩემთანა ღმერთო და სული წრფელი განმიახლე გვამსა ჩემსა."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"უფალო, რომელმან ყოვლად-წმიდა სული შენი ჟამსა მესამესა მოციქულთა შენთა გარდამოუვლინე და განანათლენ იგინი, მას, სახიერო, ნუ მიმიღებ ჩემგან, არამედ განმიახლენ მვედრებელსა შენსა."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"ნუ განმაგდებ მე პირისა შენისაგან, და სულსა წმიდასა შენსა ნუ მიმიღებ ჩემგან."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"უფალო, რომელმან ყოვლადწმიდა სული შენი ჟამსა მესამესა მოციქულთა შენთა გარდამოუვლინე და განანათლენ იგინი, მას, სახიერო, ნუ მიმიღებ ჩემგან, არამედ განმიახლენ მვედრებელსა შენსა."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აკურთხე მაღალყოვლადუსამღვდელოესო მეუფეო წმიდა პური ესე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"და ჰყავ უკუე პური ესე პატიოსან ხორც ქრისტეს შენისა."},{"t":"rubric","text":"ჯვარს დასწერს ძღვენს."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"ამინ. აკურთხე მაღალყოვლადუსამ-ღვდელოესო მეუფეო წმიდა ბარძიმი ესე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ხოლო ბარძიმსა ამას შინა პატიოსან სისხლ ქრისტეს შენისა."},{"t":"rubric","text":"ჯვარს დასწერს ბარძიმს."},{"t":"say","role":"deacon","who":"I დიაკონ","text":"ამინ. აკურთხე მაღალყოვლადუსა-მღვდელოესო მეუფეო ორივე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"შესცვალე სულითა შენითა წმიდითა."},{"t":"rubric","text":"ჯვარს დასწერს ორივეს."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"ამინ, ამინ, ამინ, მოგვიხსენე ჩუენ მაღალყოვლადუსამღვდელოესო მეუფეო."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"დეკანოზობა თქვენი, მღვდელმონაზვნობა თქვენი, სამღვდელო დიაკვნობა თქვენი მოიხსენოს უფალმან ღმერთმან ჩუენმა სასუფეველსა თვისსა ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე ამინ."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მღვდელმთავრობა თქვენი მოიხსენოს უფალმან ღმერთმან ჩუენმა სასუფეველსა თჳსსა ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე ამინ."},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"რათა ექმნეს მიმღებეთა, განსაფრთხობელად სულისა, მისატევებელად ცოდ-ვათა, ზიარებად წმიდისა სულისა შე-ნისა, სასუფეველსა ცათასა დამკვი-დრებად, კადნიერებად წინაშე შენსა, ნუ სასჯელად, გინა დასასჯელად: მერმეცა შევწირავთ შენდა სიტყვიერსა ამას მსხვერპლსა, სარწმუნოებით შესვენებულთა-თჳს პირველთა მამათა, მამათ-მთავართა, წინასწარ-მე-ტყუელთა, მოციქულთა, ქადაგთა, მახარებელთა, მოწამეთა, აღმსარებელთა, მმარხველთა, და ყოვლისასულისა სა-რწმუნოებით აღსრულებულისა:"},{"t":"rubric","text":"I დიაკონი სასაკმევლეს მიაწვდის მეუფეს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"უმეტესად ყოვლადწმიდისა, უხრწნელისა, უფროსად კურთხეულისა, დიდებულისა დედოფლისა ჩუჱნსა ღვთისმშობელისა და მარადის ქალწულისა მარიამისა."},{"t":"say","role":"choir","who":"გუნდი","text":"ღირს-არს ჭეშმარიტად, რათა გადიდებ-დეთ, შენ ღვთისმშობელო, რომელი მარადის სანატრელ იქმენ, ყოვლად-უბიწოდ და დედად ღვთისა ჩუჱნსა. უპატიოსნესსა ქერუბიმთასა, და აღმატებით უზესთაესსა სერაბიმთასა, განუხ-რწნელად მშობელსა სიტყვისა ღვთისასა, მხოლოსა ღვთისმშობელსა გალობით ვადიდებდეთ."},{"t":"rubric","text":"I დიაკონი აკმევს საკურთხეველს."},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"წმიდისა წინასწარ-მეტყუჱლისა იოანე წინა-მორბედისა და ნათლის-მცემელისა, წმადათა დიდებულთა და ყოვლად-ქე-ბულთა მოციქულთა, და წმიდისა (სახელი) რომლისაცა ჴსენებასა აღვას-რულებთ, და ყოველთა წმიდათა შენთათა, რომელთა ვედრებითა მომხედენ ჩუჱნ, ღმერთო, და მოიჴსენენ ყოველნი დაძინებულნი სასოებითა აღდგომისა და ცხოვრებისა საუკუ-ნოჲსათა: და განუსვენე მათ, სადა იგი მიხედავს ნათელი პირისა შენისასა:"},{"t":"prayer","text":"მერმეცა გევედრებით შენ, მოიჴსენე, უფალო, ყოველი ეპისკოპოსობისა მართლმადიდებელთა, და მართლ-მკვე-თელთა სიტყვისა შენისა ჭეშმარი-ტებისასა, ყოველი მღუდელობისა, და ქრისტეს მიერ დიაკონობისა, და ყოველი სამღუდელოჲსა დასისა. მერმეცა შევსწირავთ შენდა სიტ-ყვიერსა ამას მსხვერპლსა, სოფლისა-თჳს, და წმიდისა კათოლიკე და სამოციქულოსა ეკკლესიათა-თჳს, უბრალოდ და ღირსებით მოქალაქობისა მქონებელთა-თჳს. ღვთივ დაცულისა ერისა ჩუჱნისა-თჳს და მეუფებისა მისისა-თჳს, და ყოვლისა მჴედრობათა მათთა-თჳს. მიეც მათ, უფალო, მშვიდობით მეფობაჲ, რათა ჩუჱნცა მყუდროებასა შინა მათსა დაწყნარებული და მყუდრო ცხოვრებაჲ გვაქუნდეს, ყოვლითა კეთილ მსახურებითა და პატიოსნებითა:"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"გვაკურთხენ მაღალყოვლადუსამღ-ვდელოესო მეუფეო."},{"t":"rubric","text":"ეპისკოპოსი დასახავს ჯვარს, ემთხვევა დიაკონი ხელზე და გამოდის აღსავლის კარით მაცხოვრის ხატის წინ."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"ყოველთა და ყოვლისათვის."},{"t":"say","role":"choir","who":"გუნდი","text":"ყოველთა და ყოვლისათვის."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"პირველად მოიხსენე უფალო უწმიდესი და უნეტარესი, სრულიად საქართველოს კათოლიკოს-პატრიარქი და მცხეთა-თბილისის მთავრეპისკოპოსი, ბიჭვინთისა და ცხუმ-აფხაზეთის მიტროპოლიტი დიდი მეუფე, მამაჲ ჩუჱნ ილია, რომელი მომადლე წმიდასა შენსა ეკლესიასა, მშვიდობით, ცოცხლებით, პატიოსნად, სიმრთელით, დღეგრძელობით, მართლმკვეთელობით, სიტყვისა შენისა ჭეშმარიტებისათა."},{"t":"rubric","text":"და კვალად მოიხსენე უფალო სრულიად საქარ-თველოს კათოლიკოს-პატრიარქის მოსაყდრე სენაკისა და ჩხოროწყუს მიტროპოლიტი შიო რომელი მომადლე წმიდასა შენსა ეკლესიასა, მშვიდობით, ცოცხლებით, პატიოსნად, სიმრთელით, დღეგრძელობით, მართლმკვეთელობით, სიტყვისა შენისა ჭეშმარიტებისათა."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"და კუალად მოიხსენე უფალო მაღალყოვლადუსამღვდელოესი ქუთათელ-გაე-ნათელი მიტროპოლიტი იოანე რომელი მომადლე წმიდასა შენსა ეკლესიასა, მშვიდობით, ცოც-ხლებით, პატიოსნად, სიმრთელით, დღეგრძელობით, მართლმკვეთელობით, სიტყვისა შენისა ჭეშმარიტებისათა."},{"t":"rubric","text":"I დიაკონი შედის აღსავლის კარით."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მაღალყოვლადუსამღვდელოესი ქუთა-თელ-გაენათელი მიტროპოლიტი იოანე შემწი-რველი წმიდათა ამათ ძღვენთა უფლისა და ღმრთისა ჩუჱნსადმი (გამოდის ამბიონზე)საცხოვნებელად ღვთივდაცულისა ერისა ჩუჱნსა და მეუფებისა მისისათვის, კეთილმორწმუნეთა, ნა-ყოფის შემომწირველთა და კეთილისმყოფელთა წმიდისა და ყოვლადპატიოსნისა ამის ტაძრისა, და ამას შინა მშრომელთა, მგალობელთა, აქა მდგომარეთა და ყოველთა მართლმადიდებელთა ერთათვის."},{"t":"rubric","text":"ბრუნდება საკურთხეველში და მეუფეს ემთხვევა მარჯვენაზე. დგება მისგან მარჯვნივ."},{"t":"say","role":"choir","who":"გუნდი","text":"ყოველთა და ყოვლისათვის."},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"მოიხსენე უფალო, ქალაქი რომელსა შინა ვმსახურობთ, და ყოველნი ქალა-ქნი და სოფელნი, და სარწმუნოებით მკვიდრნი მას შინა, მოიხსენე, უფალო მენავენი, მოგზაურნი, სნეულნი, მშრომელნი, ტყვეთა მხსნელნი, და ცხოვრება მათი. მოიხსენე უფალო, ნაყოფის მომრთმეველნი, და კეთილის მყოფელნი წმიდათა შენთა ეკლესიათანი, და მომხსენებელნი გლახაკთანი, და ჩუჱნ ყო-ველთა ზედა მოწყალებანი შენნი გარდამოგვივლინე."},{"t":"say","role":"priest","who":"წინამძღვარი","text":"და მომეც ჩუჱნ, უფალო ერთითა პირითა და ერთითა გულითა, დიდებად და გალობად ყოვლადპატიოსანსა და დიდად შვენიერსა სახელსა შენსა, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"და იყვნენ წყალობანი დიდისა ღმრთისა და მაცხოვრისა ჩუჱნსა იესო ქრისტესი თქვენ ყოველთა თანა."},{"t":"rubric","text":"ეპისკოპოსი გამოსახავს ორივე ხელით ჯვარს აღსავლის კარში."},{"t":"say","role":"choir","who":"გუნდი","text":"და სულისაცა შენისა თანა"},{"t":"rubric","text":"I დიაკონი აიღებს მცირე დაფარნას ფრთებს მოუკეცავს და მარჯვენა ხელით ბარძიმის თავზე სახავს ჯვარს ვიდრე არ დამთავრდება კვერექსი."},{"t":"say","role":"deacon","who":"III დიაკონი","text":"ყოველთა წმიდათა მომხსენებელთა, მერმე და მერმე მშვიდობით უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეწირულთა ამათთვის და განმწმე-დილთა პატიოსანთა ძღვენთა, უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"რათა კაცთმოყვარემან ღმერთმან ჩუჱნმან, შემწირველმან ამათმან წმიდასა და ზესთა ცათასა და საცნაურად საკურთხეველსა მისსა საყნოსელად სუნად სუნელად შეიწირნეს და ნაცვლად გარადმოგვივლინოს ჩუჱნ საღმრთო მადლი სულისა წმიდისა, ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ჴსნად ჩუჱნდა ყოვლისაგან ჭირისა, რისხვისა და იწროებისა, უფლისა მიმართ ვილოცოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"შენ შეგვედრებთ ყოველსა ცხოვრე-ბასა ჩუჱნსა და სასოებასა, მეუფეო კაცთ-მოყვარეო, და გხადით შენ, და გევედრებით, და შეგივრდებით, ღირს მყვენ ჩუჱნ მოღებად ზეცისა შენთა შესაძრწუნებელთა საიდუმლოთა, ამის სამღუდელოსა და სულიერისა ტრაპეზისათა, წმიდითა სვინდისითა, მოსატე-ვებელად ცოდვათა, შესანდობელად ბრალთა, სულისა წმიდისა ზიარებად, სასუფეველსა ცათასა დამკვიდრებად, ნუ სასჯელად, გინა დასასჯელად:"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გვაცხოვნენ, შეგჳწყალენ და დაგვიცუჱნ ჩუჱნ ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ"},{"t":"say","role":"deacon","who":"დიაკონი","text":"დღე ყოველი აღსრულებად, სიწმიდით, მშვიდობით და უცოდველად, უფლისა მიმათ ვითხოვოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვამდლენ უფალო"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ანგელოზი მშვიდობისა, სარწმუნო წინა-მძღვარი, მცველი სულთა და ხორცთა ჩუჱნთა, უფლისა მიმართ ვითხოვოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვამდლენ უფალო"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შენდობა და მოტევება ცოდვათა და უსჯულოებათა ჩუჱნთა, უფლისა მიმართ ვითხოვოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვამდლენ უფალო"},{"t":"say","role":"deacon","who":"დიაკონი","text":"კეთილნი და უმჯობესნი სულთა ჩუჱნ-თანი და მშვიდობა სოფლისა, უფლისა მიმართ ვითხოვოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვამდლენ უფალო"},{"t":"say","role":"deacon","who":"დიაკონი","text":"შემდგომნი ჟამნნი ცხოვრებისა ჩუჱნისანი მშვიდობით და სინანულით აღსრულებად, უფლისა მიმართ ვითხოვოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვამდლენ უფალო"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ქრისტიანობითნი აღსასრულნი ცხოვრე-ბისა ჩუჱნსანი, უჭირველნი, ურცხვენელნი, მშვიდობითნი და კეთილი სიტყვის-გებანი, წინაშე საშინელსა სამსჯავროსა ქრისტესსა ვითხოვოთ"},{"t":"say","role":"choir","who":"გუნდი","text":"მოგვამდლენ უფალო"},{"t":"say","role":"deacon","who":"დიაკონი","text":"ერთობასა სარწმუნოებისასა და ზიარებასა სულისა წმიდისა მთხოვნელთა, თავნი თვისნი და ურთიერთარს და ყოველი ცხოვრება ჩუჱნ, ქრისტესა ღმერთასა ჩუჱნსა შევვედროთ"},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"და ღირს მყვენ ჩუჱნ მეუფეო კადნიერებით, დაუსჯელად კადრებად და ხდად შენდა ზეცათა ღმრთისა მამისა და თქმად."},{"t":"say","role":"choir","who":"გუნდი","text":"მამაო ჩუჱნო, რომელი ხარ ცათა შინა, წმიდა იყავნ სახელი შენი, მოვედინ სუფევა შენი, იყავნ ნება შენი, ვითარცა ცათა შინა, ეგრეცა ქვეყანასა ზედა, პური ჩუჱნ არსობისა მომეც ჩუჱნ დღეს, და მომიტევენ ჩუჱნ თანანადებნი ჩუჱნნი, ვითარცა ჩუჱნ მივუტევებთ თანამდებთა მათ ჩუჱნთა და ნუ შემიყვანებ ჩუჱნ განსაცდელსა, არამედ მიხსენ ჩუჱნ ბოროტისაგან."},{"t":"say","role":"priest","who":"მღდელი","text":"რამეთუ შენი არს სუფევა, ძალი და დიდება, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ"},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობა ყოველთა"},{"t":"rubric","text":"და გადასახავს ჯვარს"},{"t":"say","role":"choir","who":"გუნდი","text":"და სულისაცა შენისა თანა"},{"t":"say","role":"deacon","who":"დიაკონი","text":"თავნი თქვენნი უფალსა მოუდრიკნეთ"},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო"},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"გმადლობ შენ, მეუფეო უხილავო, რომელმან უზომოჲთა ძალითა შენითა ყოველნი დაბადენ, და სიმრავლითა წყა-ლობისა შენისათა არა არსისაგან ყოფად მომიყვანენ ჩუჱნ ყოველნი: შენ მეუფეო, ზეცით მოიხილე მათ ზედა, რომელთა მოუდრეკიან შენდა თავნი მათნი, რამეთუ არა ჴორცთა და სის-ხლთა მოუდრიკნეს, არამედ შენ საშინელსა ღმერთსა, შენ უკუჱ, მეუფეო, ჩუჱნ ყოველთა წინა მდებარენი კეთი-ლად განაწრფელენ, თვითოეულისა საჴმარისაებრ: მენავეთა თანა მენავობად, მოგზაურთა თანა მოგზაურობად, სნეულნი განკურნენ, მკურნალო სულთა და ხორცთაო:"},{"t":"say","role":"priest","who":"მღვდელი","text":"მადლითა, და წყალობითა, და კაცთმოყვარებითა, მხოლოდ შობილისა ძისა შენისათა, რომლისა თანა კურთხეულ ხარ, თანა ყოვლად წმიდით სახიერით, და ცხოველს მყოფელით სულით შენითურთ, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"rubric","text":"ლოცვა საიდუმლოდ"},{"t":"prayer","text":"მოიჴილე, უფალო იესო ქრისტე ღმერთო ჩუჱნო წმიდით სამკვიდრებელით შენით, და საყდრით დიდებისა სუფევისა შენისათა, და მოვედ წმიდა ყოფად ჩუჱნდა, რომელი ზე მამისა თანა მჯდომარე ხარ, და აქა ჩუჱნ თანა უხილავად თანა მყოფობ: და ღირს მყვენ ჩუჱნ, მტკიცითა ჴელითა შენითა მოცემად ჩუჱნდა უხრწნელი ჴორცი შენი, და პატიოსანი სისხლი შენი, და ჩუჱნ მიერ ყოველსა ერსა შენსა."},{"t":"rubric","text":"კვერექსის ბოლოს დიაკვნები გინგილას გადაიჯვარედინებენ. ეპისკოპოსი რომ დაამთავრებს საიდუმლო ლოცვის წაკითხვას II დიაკონი დახურავს აღსავლის კარს და ჩამოაფარებს კრეტსაბმელს."},{"t":"say","role":"priest","who":"სასულიერონი ჩუმად","text":"ღმერთო გამწმიდე მე ცოდვილი, და შემიწყალე მე"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მოხედენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"წმიდაა წმიდათა."},{"t":"say","role":"choir","who":"გუნდი","text":"ერთ არს წმიდა, ერთ არს უფალი იესო ქრისტე სადიდებელად ღმრთისა, მამისა, ამინ. (დღის და წმიდის განიცადენი)"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"განსტეხე მაღალყოვლადუსამღვდელოესო მეუფეო წმიდა ტარიგი ესე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"განიტეხების და განიყოფების ტარიგი ღვთისა, განიხეტების და არა განიყოფის, მარადის იჭამების და არა დაილევის, არამედ მზიარებელთა განსწმედს."},{"t":"rubric","text":"ეპისკოპოსი დაანაწილებს ძღვენს ოთხად"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აღავსენ მაღალყოვლადუსამღვდელოესო მეუფეო წმიდა ბარძიმი."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"აღვსება სულისა წმიდისა"},{"t":"rubric","text":"ეპისკოპოსი ნაწილს იესო ჩაასვენებს წმიდა ბარძიმში."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აკურთხე მაღალყოვლადუსამღვდელოესო მეუფეო მდუღარება ესე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"კურთხეულ არს მდუღარება წმიდათა შენთა ყოვლადვე, აწ და მარადის, და უკუნითი უკუნისამდე. ამინ."},{"t":"rubric","text":"ეპისკოპოსი მდუღარებას გადასახავს ჯვარს"},{"t":"say","role":"deacon","who":"I დიაკონი","text":"მდუღარება სარწმუნოებისა აღვსება სულისა წმიდისა. ამინ."},{"t":"rubric","text":"დიაკონი ფრთხილად ჩაასხამს წმიდა ბარძიმში მდუღარებას."},{"t":"rubric","text":"ეპისკოპოსი დაანაწილებს ძღვენს მზიარებელი სასულიერო პირებისათვის. სამღვდელოება ერთმანეთს სთხოვს შენდობას."},{"t":"rubric","text":"მრწამს უფალო, და აღვიარებ რამეთუ შენ ხარ ჭეშმარიტად ქრისტე ძე ღმრთისა ცხოველისა. მოსრული სოფლად ცოდვილთა ცხოვრებად, რომელთაგან პირველი მე ვარ. კუალად მრწამს, რამეთუ ესე არს თვით უხრწნელი ჴორცი შენი, და ესე არს თჳთ პატიოსანი სისხლი შენი. შენ უკუე გევედრები, შემიწყალე მე, და შემინდევ შეცოდებანი ჩემნი, ნებსითნი, და უნებლიეთნი, სიტყვით, და საქმით, ცნობით და უმეცრებით, და ღირს-მყავ მე დაუსჯელად ზიარებად უხრწნელთა საიდუმლოთა შენთა, მოსატევებელად ცოდვათა, და ცხოვრებად საუკუნოდ, ამინ."},{"t":"rubric","text":"სერობასა საიდუმლოსა შენისასა, დღეს ძეო ღმრთისაო, ზიარებად შემიწყნარე, რათა არა მტერთა შენთა უთხრა საიდუმლო შენი. არცა ამბორს-გიყო, ვითარცა იუდა. არამედ ვითარცა ავაზაკი აღგიარებ შენ. მომიჴსენე მე უფალო, სასუფეველსა შენსა."},{"t":"rubric","text":"რათა არა სასჯელად, გინა დასასჯელად მექმნეს მე ზიარება წმიდათა შენთა საიდუმლოთა, უფალო არამედ საკურნებელად სულისა და ჴორცისა. ამინ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"პატიოსანი და ყოვლად წმიდა ჴორცი უფლისა და ღუთისა, და მაცხოვრისა ჩუჱნისა იესო ქრისტესი, მომეცემის მე მღვ-დელმთავარსა (სახელი), მოსატევებელად ცოდ-ვათა ჩემთა, და ცხოვრებად საუკუნოდ. ამინ."},{"t":"rubric","text":"ეპისკოპოსი ეზიარება წმინდა ნაწილით."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"პატიოსანსა და წმიდასა სისხლსა, უფლისა და ღუთისა და მაცხოვრისა ჩუჱნისა იესო ქრისტესსა, ვეზიარები მე მღვ-დელმთავარი (სახელი) მოსატევებელად ცოდ-ვათა ჩემთა, და ცხოვრებად საუკუნოდ. ამინ."},{"t":"rubric","text":"ეპისკოპოსი გ-გზის მოსვამს ბარძიმს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი ჩუმად","text":"წმიდაო ღმერთო, წმი-დაო ძლიერო, წმიდაო უკვდაო შეგვიწყალენ ჩუჱნ."},{"t":"say","role":"deacon","who":"დიაკვნები","text":"ამინ. ამინ. ამინ. ისპოლა ეტი დესპოტა."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ესერა შეეხო ბაგეთა ჩემთა და მომიტევებს უსჯულოებასა ჩემსა, და ცოდვასა ჩემსა განწმენდს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მღუდელნო მოვედით."},{"t":"say","role":"priest","who":"მღვდელი","text":"მომეც მე მაღალყოვლადუსამღვდელოესო მეუფეო პატიოსანი და წმიდა ჴორცი უფლისა და ღუთისა და მაცხოვრისა ჩუჱნისა იესუ ქრისტესი."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"პატიოსანი და ყოვლად წმიდა ჴორცი უფლისა და ღუთისა, და მაცხოვრისა ჩუჱ-ნისა იესო ქრისტესი, მოგეცემის შენ მღუდელსა (სახელი), მოსატევებელად ცოდვათა შენთა, და ცხოვრებად საუკუნოდ. ამინ."},{"t":"rubric","text":"მღუდელი ემთხვევა ტრაპეზს, ეპისკოპოსი ჩაუდებს ხელში ძვენს, ემთხვევა ეპისსკოპოს ხელზე და ბეჭზე, გავა ტრაპეზის ბოლო კუთხესთან და მიიღებს ნაწილს."},{"t":"say","role":"priest","who":"მღვდელი","text":"აჰა ესერა მოვალს წინაშე უკუდავისა მეუფისა."},{"t":"rubric","text":"მომეც მე მაღალყოვლადუსამღვდელოესო მეუ-ფეო პატიოსანი და წმიდა სისხლი უფლისა და ღუთისა და მაცხოვრისა ჩუჱნისა იესუ ქრისტესი."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"პატიოსანსა და წმიდასა სის-ხლსა, უფლისა და ღუთისა და მაცხოვრისა ჩუჱ-ნისა იესო ქრისტესსი მოგეცემის შენ მღვდელსა (სახელი) მოსატევებელად ცოდვათა შენთა, და ცხოვრებად საუკუნოდ. ამინ."},{"t":"rubric","text":"ეპისკოპოსი მოასმევინებს მღვდელს ბარძიმიდან გ-გზის"},{"t":"say","role":"bishop","who":"მღვდელმთავარი ჩუმად","text":"წმიდაო ღმერთო, წმი-დაო ძლიერო, წმიდაო უკვდაო შეგვიწყალენ ჩუჱნ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ესერა შეეხო ბაგეთა შენთა და მოგიტევებს უსჯულოებათა შენთა, და ცოდ-ვათა შენთა განწმენდს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"დიაკონნო მოვედით."},{"t":"say","role":"deacon","who":"დიაკონი","text":"მომეც მე მაღალყოვლადუსამღვდელო-ესო მეუფეო პატიოსანი და წმიდა ჴორცი უფლისა და ღვთისა და მაცხოვრისა ჩუჱნისა იესუ ქრისტესი."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"პატიოსანი და ყოვლად წმიდა ჴორცი უფლისა და ღუთისა, და მაცხოვრისა ჩუჱნსა იესუ ქრისტესი, მოგეცემის შენ სამ-ღუდელო დიაკონსა (სახელი), მოსატევებელად ცოდვათა შენთა, და ცხოვრებად საუკუნოდ. ამინ."},{"t":"rubric","text":"დიაკონი ემთხვევა ტრაპეზს, ეპისკოპოსი ჩაუდებს ხელში ძვენს, ემთხვევა ეპისსკოპოს ხელზე და ბეჭზე, გავა ტრაპეზის ბოლო კუთხესთან და მიიღებს ნაწილს."},{"t":"say","role":"deacon","who":"დიაკონი","text":"აჰა ესერა მოვალს წინაშე უკუდავისა მეუფისა."},{"t":"rubric","text":"მომეც მე მაღალყოვლადუსამღვდელოესო მეუ-ფეო პატიოსანი და წმიდა სისხლი უფლისა და ღუთისა და მაცხოვრისა ჩუჱნისა იესუ ქრისტესი."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"პატიოსანსა და წმიდასა სის-ხლსა, უფლისა და ღუთისა და მაცხოვრისა ჩუჱ-ნისა იესო ქრისტესსი მოგეცემის შენ სამღვდელო დიაკონსა (სახელი)მოსატევებელად ცოდვათა შენთა, და ცხოვრებად საუკუნოდ. ამინ."},{"t":"rubric","text":"ეპისკოპოსი მოასმევინებს დიაკონს ბარძიმიდან 3-გზის."},{"t":"say","role":"bishop","who":"მღვდელმთავარი ჩუმად","text":"წმიდაო ღმერთო, წმი-დაო ძლიერო, წმიდაო უკვდაო შეგვიწყალენ ჩუჱნ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"ესერა შეეხო ბაგეთა შენთა და მოგიტევებს უსჯულოებათა შენთა, და ცოდ-ვათა შენთა განწმენდს."},{"t":"rubric","text":"სასულიერო პირების ზიარების შემდეგ ეპისკოპოსი გაამზადებს ძღვენს მრევლისთვის (I დიაკონი დაეხმარება რომ პატარა დაფარნები დააფაროს ბარძიმს და ფეშხუმს, დაფას გაწმენდს ღრუბლით ფეშხუმზე, რომელზედაც ეპისკოპოსმა ძღვენი დაანაწილა). აღესრულება ხელბანა საკურთხეველში."},{"t":"rubric","text":"ლოცვა სამადლობელი."},{"t":"prayer","text":"გმადლობ შენ, მეუფეო კაცთმოყ-ვარეო, ქუჱლის-მოქმედო სულთა ჩუჱ-ნთაო, რამეთუ მოწევნულსაცა ამას დღესა ღირს მყვენ ჩუჱნ, ზეცისათა შენთა უკვდავთა საიდუმლოთა, მართლ-მკუეთელ-ჰყუჱნ გზანი ჩუჱნნი, დამამტკიცენ ჩუჱნ შიშსა შინა შენსა ყოველნივე, შეიცევ ცხოვრებაჲ ჩუჱნნი, უცთომელ ჰყუჱნ სულნი ჩუჱნნი ლოცვითა და ვედრებითა წმიდისა და დიდებულისა ღვთის-მშობელისათა, და მარადის ქალწულისა მარიამისათა, და ყოველთა წმიდათა შენთათა."},{"t":"rubric","text":"გასვლისას გაიხსნება კრეტსამბელს და აღსავლის კარს. გადის დიაკონი ბარძიმით."},{"t":"say","role":"deacon","who":"II დიაკონი","text":"შიშითა ღვთისა, სარწმუნოებით და სიყვარულით მოვედით."},{"t":"say","role":"choir","who":"გუნდი","text":"კურთხეულ არს მომავალი უფლისათა, ღმერთი უფალი და გამოგვიჩნდა ჩუჱნ."},{"t":"say","role":"deacon","who":"დიაკონი ან მღვდელი","text":"მრწამს უფალო, და აღვიარებ რამეთუ შენ ხარ ჭეშმარიტად ქრისტე ძე ღმრთისა ცხოველისა. მოსრული სოფლად ცოდვილთა ცხოვრებად, რომელთაგან პირველი მე ვარ. კუალად მრწამს, რამეთუ ესე არს თვით უხრწნელი ჴორცი შენი, და ესე არს თჳთ პატიოსანი სისხლი შენი. შენ უკუე გევედრები, შემიწყალე მე, და შემინდევ შეცოდებანი ჩემნი, ნებსითნი, და უნებლიეთნი, სიტყვით, და საქმით, ცნობით და უმეცრებით, და ღირს-მყავ მე დაუსჯელად ზიარებად უხრწნელთა საიდუმლოთა შენთა, მოსატევებელად ცოდვათა, და ცხოვრებად საუკუნოდ, ამინ."},{"t":"rubric","text":"სერობასა საიდუმლოსა შენისასა, დღეს ძეო ღმრთისაო, ზიარებად შემიწყნარე, რათა არა მტერთა შენთა უთხრა საიდუმლო შენი. არცა ამბორს-გიყო, ვითარცა იუდა. არამედ ვითარცა ავაზაკი აღგიარებ შენ. მომიჴსენე მე უფალო, სასუფეველსა შენსა."},{"t":"rubric","text":"რათა არა სასჯელად, გინა დასასჯელად მექმნეს მე ზიარება წმიდათა შენთა საიდუმლოთა, უფალო არამედ საკურნებელად სულისა და ჴორცისა. ამინ."},{"t":"rubric","text":"იწყება მრევლის ზიარება."},{"t":"say","role":"choir","who":"გუნდი","text":"ჴორცი ქრისტესი მოვიღოთ და უკუდავებისა წყაროსა გემო ვიხმიოთ."},{"t":"rubric","text":"ზიარების დასრულების შემდეგ დიაკონი მღვდელს გადასცემს ბარძიმს, მღვდელი შეაბრძანებს ბარძიმს საკურთხეველში."},{"t":"say","role":"choir","who":"გუნდი","text":"ალილუია, ალილუია, ალილუია."},{"t":"rubric","text":"თუ რამოდენიმე ბარძიმებით არის ზიარება, რომ დასრულდება აღსავლის კარით შევლენ მამები და პირდაპირ სამკვეთლოზე დაასვენებენ წმიდა ბარძიმს, ხოლო მთავარი ბარძიმი აღსავლის კარით შემოსვლის შემდეგ დაასვენებს წინამძღვარი ტრაპეზზე. მხოლოდ მთავარ ბარძიმში წინამძღვარი ფეშხუმზე არსებულ ნაწილებს ჩააბრძანებს."},{"t":"say","role":"deacon","who":"I დიაკონი","text":"აღდგომა ქრისტესი ვიხილეთ, თაყვანის-ვჰსცეთ წმიდასა ამას უფა-ლსა დიდებისასა იესუს, მხოლოსა ღმე-რთსა ჩუჱნსა, და ესრეთ ჴმა ვჰყოთ: ჯუარსა შენსა თაყვანის-ვჰსცემთ ქრისტე მეუფეო, და წმიდასა აღდ-გომასა შენსა უგალობთ და ვადიდებთ, რამეთუ შენ ხარ ღმერთი ჩუჱნი და ჩუჱნ შენსა გარეშე სხვა ღმერთი არა ვიცით; მოვედით ყოველნი მორწმუნენი, თაყვანის-ვჰსცეთ ქრის-ტეს ღმრთისა ჩუჱნისა აღდგომასა, რა-მეთუ აჰა ესერა მოიწია ჯუარისა მიერ და აღდგომისა სიხარული ყოვ-ლისა სოფლისა. მარადის ვაკურთ-ხევდეთ ქრისტესა და უგალობდეთ აღდგომასა მისსა, რამეთუ ჯუარცმა თავს-იდუა ჩუჱნ-თჳს და სიკუდილითა სიკუდილი განაქარვა."},{"t":"prayer","text":"განათლდი, განათლდი, ახალო იერუსალიმ, დღეს დიდება უფლისა შენ ზედა გამობრწყინდა, განსცხრებოდე და იხარებდ სიონ, და აწ შენცა იშუ-ებდი, ღმრთის-მშობელო, აღდგომასა ძისა შენისასა"},{"t":"prayer","text":"ჵ პასექო, დიდო და სამღუდელოო, ქრისტე: ჵ სიბრძნეო და სიტყვაო და ძალო, მომეც ჩუჱნ უსრულესი მოღება მადლთა შენთა დაუღამებელსა მას დღესა სუფევისა შენისასა"},{"t":"prayer","text":"მიუტევენ უფალო ცოდვანი, აქა მოჴსენიებულთანი პატიოსნითა სისხ-ლითა შენითა, მეოხებითა წმიდათა შენ-თათა."},{"t":"rubric","text":"სტიქაროსნები აანთებენ დიკირ-ტრიკირს და გავლიან ამბიონზე. როდესაც ბარძიმშია უკვე ნაწილები და ფეშხუმზე დევს დაფარნა კოვზი ლახვარი ვარსკვლავი, ეპისკოპოსს I დიაკონი მიაწვდის მიტრას."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"აცხოვნე უფალო ერი შენი და აკურთხე სამკვიდრებელი შენი."},{"t":"rubric","text":"ეპისკოპოსი გადის ამბიონზე და გადასახავს დიკირ-ტრიკირით ჯვარს. III დიაკონი აიღებს კურთხევას კვერექსისათვის, ხოლო I დიაკონი მეუფეს მიაწვდის სასაკმევლეს, უკმევს ბარძიმ-ფეშხუმს, სასაკმევლესა და ფეშხუმს ორივეს მიაწვდის I დიაკონს, რომელიც აღსავლის კარისა და ტრაპეზს შუა გაივლის, დაასვენებს ფეშხუმს სამკვეთლოზე და უკმევს მისკენ მომავალ ბარძიმს."},{"t":"say","role":"bishop","who":"მღვდელმთავარი (ჩუმად)","text":"ამაღლდი ცათა შინა, ღმერთო, და ყოველსა ქუჱყანასა ზედა არს დიდება შენი."},{"t":"say","role":"choir","who":"გუნდი","text":"ნათელი ჭეშამარიტი ვიხილეთ, ზეცათა სული მოვიღეთ, ვპოვეთ სარწმუნოებაი ჭეშმარიტი და განუყოფელსა სამებასა თაყვანისვცემთ, რათა გვაცხოვნეს ჩუჱნ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი (ჩუმად)","text":"კურთხეულ არს ღმერთი ჩუჱნი."},{"t":"say","role":"priest","who":"მღვდელი","text":"ყოვლადვე აწდა და მარადის და უკუნითი უკუნისამდე."},{"t":"rubric","text":"ბარძიმს მიაწვდის წინამძღვარს რომელიც გადააბრძანებს მას სამკვეთლოზე. I დიაკონი მიაწოდებს საცეცხლურს წინამძღვარს, რომელიც 3-გზის უკმევს ძღვენს."},{"t":"say","role":"choir","who":"გუნდი","text":"აღავსე პირი ჩემი ქებითა შენითა უფალო, რათა ვუგალობდე დიდებასა შენსა, რამეთუ ღირს მყვენ ჩუჱნ ზიარებად წმიდათა სენთა საღმრთოთა, უკვდავთა და ცხოველსმყო-ფელთა საიდუმლოთა, დაგვმარხენ ჩუჱნ სიწ-მიდეთა შინა შენთა, ყოველსა დღესა გვასწავენ სიმართლენი შენნი: ალილუია, ალილუია, ალი-ლუია."},{"t":"rubric","text":"III დიაკონი გადის კვერქსზე."},{"t":"say","role":"deacon","who":"დიაკონი","text":"აღემართენით, მიმღებელნი საღმრთოთა, წმიდათა, უხრწნელთა, უკვდავთა ზეცისა ცხო-ველთა, საშინელთა ქრისტეს საიდუმლოთა, ღირ-სებით ვმადლობდეთ უფალსა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"შეგვეწიენ, გავცხოვნენ, შეგჳწყალენ და დაგვიცუჱნ ჩუჱნ, ღმერთო შენითა მადლითა."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"say","role":"deacon","who":"დიაკონი","text":"დღე ყოველი აღსრულებად, სიწმიდით, მშვიდობით და უცოდველად მთხოვნელთა, თავნი თჳსნი და ურთიერთარს და ყოველი ცხოვრება ჩუჱნი ქრისტესა ღმერთსა ჩუჱნსა შევვედროთ."},{"t":"say","role":"choir","who":"გუნდი","text":"შენ უფალო."},{"t":"rubric","text":"ოდიკის დაკეცვის შემდეგ II დიაკონი სახარებას მიაწოდებს ეპისკოპოსს, რომელიც ჯვარს გამოსახავს სახარებით ოდიკზე."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"რამეთუ შენ ხარ განმწმენ-დელი ჩუჱნ და შენდა დიდებასა აღვავლენთ, მამისა და ძისა და წმიდისა სულისა, აწ და მარადის და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მშვიდობით წარვიდეთ."},{"t":"say","role":"choir","who":"გუნდი","text":"სახელითა უფლისათა."},{"t":"say","role":"deacon","who":"დიაკონი","text":"უფლისა მიმართ ვილოცოთ."},{"t":"say","role":"choir","who":"გუნდი","text":"უფალო შეგჳწყალენ."},{"t":"rubric","text":"მღვდელი გამოდის აღსავლის კარიდან და დგება ამბიონის წინ."},{"t":"rubric","text":"ლოცვა ამბიონისა"},{"t":"prayer","text":"რომელი აკურთხევ მაკურთხეველთა შენთა უფალო, და წმიდა ჰყოფ შენდა მომართ მსასოებელთა შენთა, აცხოვნე ერი შენი, და აკურთხე სამკვიდრებელი შენი, სავსება ეკლესიისა შენისა დაიცევ, წმიდა ჰყვენ მოყვარენი სახ-ლისა შენისა მშვენიერებისანი, შენ იგინი ნაცვლად ადიდენ საღმრთოჲთა ძალითა შენითა, ნუ დამაგდებ ჩუჱნ მოსავთა შენთა, მშვიდობა სოფელსა მოანიჭე, ეკლესიათა შენთა, მღუდელთა, ღვთივდაცულსა ერსა ჩუჱნსა და მეუ-ფებასა მისსა, მხედართა და ყოველსა ერსა შენსა, რამეთუ ყოველი მოცემა კეთილი და ყოველი ნიჭი სრული, ზეგარდამო არს შთამომავალი შენ მიერ, მამისაგან ნათლისა, და შენდა დიდებასა და მადლობასა და თაყვანის-ცე-მასა აღვავლენთ მამისა, და ძისა, და წმიდისა სულისა, აწ და მარადის, და უკუნითი უკუნისამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. იყავნ სახელი უფლისა კურთხეულ ამიერითგან და უკუნისამდე გ-გზის."},{"t":"say","role":"choir","who":"მედავითნე","text":"დიდება მამასა და ძესა და წმიდასა სულსა აწ და მარადის და უკუნითი უკუნისამდე, ამინ."},{"t":"rubric","text":"(ფსალმუნი ლგ) ვაკურთხო უფალი ყოველსა ჟამსა...(ბოლომდე)"},{"t":"rubric","text":"დიაკვნები ტრაპეზისგან მარჯვნივ იმუხლებიან მარჯვენა მუხლზე, ეპისკოპოსი უკითხავს ლოცვას."},{"t":"rubric","text":"ლოცვა მარადის სიწმინდეთა მოკაზმისა."},{"t":"prayer","text":"აღვსება შჯულისა და წინას-წარ-მეტყველთა შენ ხარ ქრისტე ღმერთო ჩუჱნო, რომელმან აღავსენ ყოველნი მამობრივი განგებულება, აღავსე სი-ხარულითა და მხიარულებითა გულნი ჩუჱნნი, ყოვლადვე აწ და მარადის და უკუნითი უკუნისამდე. ამინ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"კურთხევა უფლისა თქვენზე-და მისითა მადლითა და კაცთმოყვარებითა, ყოვლადვე, აწ და მარადის და უკუნითი უკუნი-სამდე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"დიდება შენდა ქრისტე ღმერთო ჩუჱნო სასოებაო ჩუჱნო დიდება შენდა."},{"t":"say","role":"choir","who":"გუნდი","text":"დიდება მამასა და ძესა და წმიდასა სულსა აწ და მარადის და უკუნითი უკუნისამდე, ამინ. უფალო შეგჳწყალენ (გ-გზის). სახელითა უფლისათა მაღალყოვლადუსამღვდელოესო მეუფეო გვაკურთხენ."},{"t":"say","role":"bishop","who":"მღვდელმთავარი","text":"მკვდრეთით აღდგომილმან, ქრისტემან ჭეშამარიტმან ღმერთმან ჩუჱნმან, მეოხებითა ყოვლადუხრწნელისა დედისა თვისისათა და მარადის ქალწულისა მარიამისა, წმიდათა დიდებულთა და ყოვლადქებულთა მოციქულთა, თავთა მოციქულთა პეტრესი და პავლესითა, და ანდრია პირველწოდებულისა და სვიმონ კანანელისა, წმიდათა შორის მამისა ჩუჱნსა იოანე ოქროპირისა, კონსტანინეპოლელ მთავარეპისკოპოსისა, წმიდათა და მართალთა მშობელთა ღუთისათა იოაკიმ და ანასითა და წმიდისა (ვისი სახელობისაც არის ტაძარი) და (სახელი ვისი ხსენებაც არის), რომლისაცა ხსენებასა აღვას-რულებთ ჩუჱნ დღეს და ყოველთა წმიდათათა, შეგვიწყალნეს და გვაცხოვნეს ჩუჱნ, ვითარცა სახიერ არს და კაცთმოყვარე."},{"t":"say","role":"choir","who":"გუნდი","text":"ამინ. უფალო შეგჳწყალენ გ-გზის."},{"t":"rubric","text":"ეპისკოპოსი მრავალჟამიერის, ქადაგებისა და ჯვარზე მთხვევის შემდეგ შევა საკურთხეველში, განიმოსება."},{"t":"rubric","text":"მღვდელმთავარი გამოდის ამბიონზე გამოსახავს სამივე მხარეს ჯვარს."},{"t":"say","role":"choir","who":"გუნდი","text":"ისპოლა ეტი დესპოტა. მრავალჟამიერ."},{"t":"rubric","text":"აკურთხებს ხალხს, ემთხვევა შუა ხატს, მივა სტოაში წინასწარ გამზადებულ არწივზე, გამოსახავს ჯვარს პირით აღმოსავლეთით (საკურთხევლისაკენ)"},{"t":"say","role":"choir","who":"მგალობლები","text":"ისპოლა ეტი დესპოტა."},{"t":"rubric","text":"დაიხურება აღსავლის კარი და კრეტსაბმელი."}],"toc":[{"text":"დასაწყისი","i":0},{"text":"ანტიფონები","i":118},{"text":"მცირე შესვლა","i":160},{"text":"სამწმიდაო","i":171},{"text":"სამოციქულო","i":213},{"text":"სახარება","i":223},{"text":"ქერუბიკონი","i":330},{"text":"დიდი შესვლა","i":339},{"text":"მრწამსი","i":426},{"text":"ევქარისტიული კანონი","i":454},{"text":"მამაო ჩუენო","i":549},{"text":"მრევლის ზიარება","i":619},{"text":"დასასრული","i":668}]}];
